function parseAnswerSourcesJsonIfValid(source: string, label: string) {
  if (!source.trim() || !hasValidAnswerSourcesJsonOrEmpty(source, label)) {
    return undefined
  }

  return parseAnswerSourcesJson(source, label)
}

function formatSupportsMixedDecisionTopicAndRemainingAnswerInference(
  format: GoalSourceResponseFormat,
) {
  return format === 'auto' || ANSWER_SOURCE_ONLY_FORMATS.has(format);
}

function listMixedDecisionTopicAndRemainingAnswerIssues(
  format: GoalSourceResponseFormat,
  answerSources: GoalAnswerSourceInput[] | undefined,
  inferDecisionTopics: boolean,
  inferRemainingAnswers: boolean,
) {
  if (!inferDecisionTopics || !inferRemainingAnswers) {
    return [];
  }

  const issues: string[] = [];
  if (!formatSupportsMixedDecisionTopicAndRemainingAnswerInference(format)) {
    issues.push(
      'Infer decision topics plus infer remaining planner answers can only run through pending_answer_sources or matching_answer_sources.',
    );
  }

  if (!answerSources || answerSources.length === 0) {
    issues.push(
      'Infer decision topics plus infer remaining planner answers needs structured answer sources with explicit routing metadata.',
    );
    return issues;
  }

  const invalidRouting = answerSources.some((answerSource) => {
    const route = answerSource.route;
    const decisionKey = answerSource.decisionKey?.trim();
    const answerKey = answerSource.answerKey?.trim();

    if (decisionKey && answerKey) {
      return true;
    }
    if (route === 'decision' && answerKey) {
      return true;
    }
    if (route === 'planning' && decisionKey) {
      return true;
    }
    return !route && !decisionKey && !answerKey;
  });

  if (invalidRouting) {
    issues.push(
      'Each remaining answer source must carry non-conflicting explicit routing via route, decisionKey, or answerKey before infer decision topics can be combined with infer remaining planner answers.',
    );
  }

  return issues;
}

function formatWillUseAnswerSourceOnlyInterpretation(
  format: GoalSourceResponseFormat,
  sourceResponse: string | undefined,
  answerSources?: GoalAnswerSourceInput[],
) {
  if (!answerSources || answerSources.length === 0) {
    return false;
  }

  if (formatUsesAnswerSourceOnlyInterpretation(format)) {
    return true;
  }

  return format === 'auto' && !sourceResponse;
}

function hasExactlyOneVisibleRemainingAnswerSourceMatchHint(matchHints?: string[]) {
  const uniqueHints = new Set(
    (matchHints ?? [])
      .map((matchHint) => matchHint.trim().toLowerCase())
      .filter((matchHint) => matchHint.length > 0),
  );
  return uniqueHints.size === 1;
}

function hasStableRemainingAnswerSourceKeyAuthority(answerSourceKey?: string) {
  const trimmed = answerSourceKey?.trim();
  if (!trimmed) {
    return false;
  }

  const stripped = trimmed.replace(/(?:[_-]+(?:answer|source))$/i, '').trim();
  return stripped.length > 0 && stripped !== trimmed;
}

function hasVisibleRemainingAnswerSourceSummaryAuthority(entry: GoalAnswerSourceInput) {
  return Boolean(
    entry.summary?.trim() ||
      entry.prompt?.trim() ||
      entry.decisionKey?.trim() ||
      entry.summaryKey?.trim() ||
      hasExactlyOneVisibleRemainingAnswerSourceMatchHint(entry.matchHints) ||
      hasStableRemainingAnswerSourceKeyAuthority(entry.answerSourceKey),
  );
}

function listRemainingAnswerSourceSummaryAuthorityIssues(
  label: string,
  entries: GoalAnswerSourceInput[],
) {
  const issues: string[] = [];

  entries.forEach((entry, index) => {
    if (hasVisibleRemainingAnswerSourceSummaryAuthority(entry)) {
      return;
    }

    const entryLabel =
      entries.length === 1 ? label : `${label} entry ${index + 1}`;
    issues.push(
      `${entryLabel} needs visible summary authority via summary, prompt, decisionKey, summaryKey, exactly one match hint, or stable answerSourceKey.`,
    );
  });

  return issues;
}

function resolveMixedRemainingAnswerSourceRoute(entry: GoalAnswerSourceInput) {
  const route = entry.route?.trim();
  const decisionKey = entry.decisionKey?.trim();
  const answerKey = entry.answerKey?.trim();

  if (route === 'decision' && !answerKey) {
    return 'decision' as const;
  }
  if (route === 'planning' && !decisionKey) {
    return 'planning' as const;
  }
  if (decisionKey && !answerKey) {
    return 'decision' as const;
  }
  if (answerKey && !decisionKey) {
    return 'planning' as const;
  }

  return undefined;
}

function listPlanningRemainingAnswerSourceAuthorityIssues({
  format,
  sourceResponse,
  answerSources,
  inferRemainingAnswers,
  explicitPlanningAnswerCount,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  answerSources?: GoalAnswerSourceInput[];
  inferRemainingAnswers: boolean;
  explicitPlanningAnswerCount: number;
}) {
  if (
    !inferRemainingAnswers ||
    explicitPlanningAnswerCount > 0 ||
    !formatWillUseAnswerSourceOnlyInterpretation(
      format,
      normalizeOptionalString(sourceResponse),
      answerSources,
    )
  ) {
    return [] as string[];
  }

  return listRemainingAnswerSourceSummaryAuthorityIssues(
    'Remaining planner answer source',
    answerSources ?? [],
  );
}

function listDecisionTopicRemainingAnswerSourceAuthorityIssues({
  format,
  sourceResponse,
  answerSources,
  inferDecisionTopics,
  inferOpenDecisions,
  inferRemainingAnswers,
  explicitDecisionAnswerCount,
  explicitPlanningAnswerCount,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  answerSources?: GoalAnswerSourceInput[];
  inferDecisionTopics: boolean;
  inferOpenDecisions: boolean;
  inferRemainingAnswers: boolean;
  explicitDecisionAnswerCount: number;
  explicitPlanningAnswerCount?: number;
}) {
  if (
    !inferDecisionTopics ||
    inferOpenDecisions ||
    explicitDecisionAnswerCount > 0 ||
    !formatWillUseAnswerSourceOnlyInterpretation(
      format,
      normalizeOptionalString(sourceResponse),
      answerSources,
    )
  ) {
    return [] as string[];
  }

  if (!inferRemainingAnswers) {
    return listRemainingAnswerSourceSummaryAuthorityIssues(
      'Remaining decision-topic answer source',
      answerSources ?? [],
    );
  }

  if ((explicitPlanningAnswerCount ?? 0) > 0) {
    return [];
  }

  if (
    listMixedDecisionTopicAndRemainingAnswerIssues(
      format,
      answerSources,
      inferDecisionTopics,
      inferRemainingAnswers,
    ).length > 0
  ) {
    return [];
  }

  const decisionEntries: GoalAnswerSourceInput[] = [];
  const planningEntries: GoalAnswerSourceInput[] = [];

  for (const answerSource of answerSources ?? []) {
    const route = resolveMixedRemainingAnswerSourceRoute(answerSource);
    if (route === 'decision') {
      decisionEntries.push(answerSource);
    } else if (route === 'planning') {
      planningEntries.push(answerSource);
    }
  }

  return [
    ...listRemainingAnswerSourceSummaryAuthorityIssues(
      'Remaining decision-topic answer source',
      decisionEntries,
    ),
    ...listRemainingAnswerSourceSummaryAuthorityIssues(
      'Remaining follow-through planner answer source',
      planningEntries,
    ),
  ];
}

function resolveRemainingDecisionAnswerSourceDescriptorKey(
  entry: GoalAnswerSourceInput,
) {
  const decisionKey = entry.decisionKey?.trim();
  if (decisionKey) {
    return `decisionKey:${decisionKey}`;
  }

  const summaryKey = entry.summaryKey?.trim();
  if (summaryKey) {
    return `summaryKey:${summaryKey}`;
  }

  const answerSourceKey = entry.answerSourceKey.trim();
  return `answerSourceKey:${answerSourceKey}`;
}

function resolveRemainingPlanningAnswerSourceDescriptorKey(
  entry: GoalAnswerSourceInput,
) {
  const answerKey = entry.answerKey?.trim();
  if (answerKey) {
    return `answerKey:${answerKey}`;
  }

  const summaryKey = entry.summaryKey?.trim();
  if (summaryKey) {
    return `summaryKey:${summaryKey}`;
  }

  const answerSourceKey = entry.answerSourceKey.trim();
  return `answerSourceKey:${answerSourceKey}`;
}

function listNonContiguousRemainingAnswerSourceRepeatIssues(
  label: string,
  entries: GoalAnswerSourceInput[],
  resolveDescriptorKey: (entry: GoalAnswerSourceInput) => string,
) {
  const issues: string[] = [];
  const seenDescriptorKeys = new Set<string>();
  let currentDescriptorKey: string | undefined;

  for (const entry of entries) {
    const descriptorKey = resolveDescriptorKey(entry);

    if (descriptorKey === currentDescriptorKey) {
      continue;
    }

    if (seenDescriptorKeys.has(descriptorKey)) {
      const descriptorLabel = formatRemainingAnswerSourceDescriptorLabel(
        descriptorKey,
      );
      issues.push(
        `Non-contiguous remaining answer sources repeated ${descriptorLabel} for ${label}.`,
      );
      continue;
    }

    seenDescriptorKeys.add(descriptorKey);
    currentDescriptorKey = descriptorKey;
  }

  return issues;
}

function formatRemainingAnswerSourceDescriptorLabel(descriptorKey: string) {
  const separatorIndex = descriptorKey.indexOf(':');
  if (separatorIndex === -1) {
    return `"${descriptorKey}"`;
  }

  const descriptorKind = descriptorKey.slice(0, separatorIndex);
  const descriptorValue = descriptorKey.slice(separatorIndex + 1);
  if (!descriptorKind || !descriptorValue) {
    return `"${descriptorKey}"`;
  }

  return `${descriptorKind} "${descriptorValue}"`;
}

function normalizeRemainingAnswerSourceLabel(value: string) {
  return value
    .trim()
    .toLowerCase()
    .replace(/[\s_-]+/g, ' ');
}

function mergeRemainingAnswerSourceMetadataValue(
  currentValue: string | undefined,
  nextValue: string | undefined,
  fieldLabel: string,
  label: string,
  areEqual: (left: string, right: string) => boolean = (left, right) =>
    left === right,
) {
  const current = currentValue?.trim() || undefined;
  const next = nextValue?.trim() || undefined;
  if (!current) {
    return next;
  }
  if (!next) {
    return current;
  }
  if (!areEqual(current, next)) {
    throw new Error(`Conflicting ${fieldLabel} values in answerSources for ${label}.`);
  }
  return current;
}

function validateMergedRemainingAnswerSourceEntries(
  entries: GoalAnswerSourceInput[],
  label: string,
) {
  const [firstEntry, ...restEntries] = entries;
  if (!firstEntry) {
    return;
  }

  let mergedEntry = {
    sourceGroupKey: firstEntry.sourceGroupKey?.trim() || undefined,
    route: firstEntry.route?.trim() || undefined,
    decisionKey: firstEntry.decisionKey?.trim() || undefined,
    answerKey: firstEntry.answerKey?.trim() || undefined,
    summaryKey: firstEntry.summaryKey?.trim() || undefined,
    summary: firstEntry.summary?.trim() || undefined,
    prompt: firstEntry.prompt?.trim() || undefined,
  };

  for (const entry of restEntries) {
    mergedEntry = {
      sourceGroupKey: mergeRemainingAnswerSourceMetadataValue(
        mergedEntry.sourceGroupKey,
        entry.sourceGroupKey,
        'sourceGroupKey',
        label,
      ),
      route: mergeRemainingAnswerSourceMetadataValue(
        mergedEntry.route,
        entry.route,
        'route',
        label,
      ),
      decisionKey: mergeRemainingAnswerSourceMetadataValue(
        mergedEntry.decisionKey,
        entry.decisionKey,
        'decisionKey',
        label,
      ),
      answerKey: mergeRemainingAnswerSourceMetadataValue(
        mergedEntry.answerKey,
        entry.answerKey,
        'answerKey',
        label,
      ),
      summaryKey: mergeRemainingAnswerSourceMetadataValue(
        mergedEntry.summaryKey,
        entry.summaryKey,
        'summaryKey',
        label,
      ),
      summary: mergeRemainingAnswerSourceMetadataValue(
        mergedEntry.summary,
        entry.summary,
        'summary',
        label,
        (left, right) =>
          normalizeRemainingAnswerSourceLabel(left) ===
          normalizeRemainingAnswerSourceLabel(right),
      ),
      prompt: mergeRemainingAnswerSourceMetadataValue(
        mergedEntry.prompt,
        entry.prompt,
        'prompt',
        label,
      ),
    };
  }
}

function listRemainingAnswerSourceMergeConflictIssues(
  label: string,
  entries: GoalAnswerSourceInput[],
  groupKeyResolver: (entry: GoalAnswerSourceInput) => string,
) {
  const issues: string[] = [];
  let currentGroupKey: string | undefined;
  let currentGroupEntries: GoalAnswerSourceInput[] = [];

  const flushCurrentGroup = () => {
    if (currentGroupEntries.length <= 1) {
      currentGroupEntries = [];
      return;
    }

    try {
      validateMergedRemainingAnswerSourceEntries(currentGroupEntries, label);
    } catch (error) {
      issues.push(error instanceof Error ? error.message : String(error));
    }
    currentGroupEntries = [];
  };

  for (const entry of entries) {
    const groupKey = groupKeyResolver(entry);
    if (groupKey !== currentGroupKey) {
      flushCurrentGroup();
      currentGroupKey = groupKey;
    }
    currentGroupEntries.push(entry);
  }

  flushCurrentGroup();
  return issues;
}

function listPlanningRemainingAnswerSourceContiguityIssues({
  format,
  sourceResponse,
  answerSources,
  inferRemainingAnswers,
  explicitPlanningAnswerCount,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  answerSources?: GoalAnswerSourceInput[];
  inferRemainingAnswers: boolean;
  explicitPlanningAnswerCount: number;
}) {
  if (
    !inferRemainingAnswers ||
    explicitPlanningAnswerCount > 0 ||
    !formatWillUseAnswerSourceOnlyInterpretation(
      format,
      normalizeOptionalString(sourceResponse),
      answerSources,
    )
  ) {
    return [] as string[];
  }

  return listNonContiguousRemainingAnswerSourceRepeatIssues(
    'inferRemainingAnswers',
    answerSources ?? [],
    resolveRemainingPlanningAnswerSourceDescriptorKey,
  );
}

function listPlanningRemainingAnswerSourceMergeConflictIssues({
  format,
  sourceResponse,
  answerSources,
  inferRemainingAnswers,
  explicitPlanningAnswerCount,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  answerSources?: GoalAnswerSourceInput[];
  inferRemainingAnswers: boolean;
  explicitPlanningAnswerCount: number;
}) {
  if (
    !inferRemainingAnswers ||
    explicitPlanningAnswerCount > 0 ||
    !formatWillUseAnswerSourceOnlyInterpretation(
      format,
      normalizeOptionalString(sourceResponse),
      answerSources,
    )
  ) {
    return [] as string[];
  }

  return listRemainingAnswerSourceMergeConflictIssues(
    'followThrough.inferRemainingAnswers',
    answerSources ?? [],
    resolveRemainingPlanningAnswerSourceDescriptorKey,
  );
}

function listDecisionTopicRemainingAnswerSourceContiguityIssues({
  format,
  sourceResponse,
  answerSources,
  inferDecisionTopics,
  inferOpenDecisions,
  inferRemainingAnswers,
  explicitDecisionAnswerCount,
  explicitPlanningAnswerCount,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  answerSources?: GoalAnswerSourceInput[];
  inferDecisionTopics: boolean;
  inferOpenDecisions: boolean;
  inferRemainingAnswers: boolean;
  explicitDecisionAnswerCount: number;
  explicitPlanningAnswerCount?: number;
}) {
  if (
    !inferDecisionTopics ||
    inferOpenDecisions ||
    explicitDecisionAnswerCount > 0 ||
    !formatWillUseAnswerSourceOnlyInterpretation(
      format,
      normalizeOptionalString(sourceResponse),
      answerSources,
    )
  ) {
    return [] as string[];
  }

  if (!inferRemainingAnswers) {
    return listNonContiguousRemainingAnswerSourceRepeatIssues(
      'inferDecisionTopics',
      answerSources ?? [],
      resolveRemainingDecisionAnswerSourceDescriptorKey,
    );
  }

  if ((explicitPlanningAnswerCount ?? 0) > 0) {
    return [];
  }

  if (
    listMixedDecisionTopicAndRemainingAnswerIssues(
      format,
      answerSources,
      inferDecisionTopics,
      inferRemainingAnswers,
    ).length > 0
  ) {
    return [];
  }

  const issues: string[] = [];
  const seenDescriptorKeys = new Set<string>();
  let currentDescriptorKey: string | undefined;
  let currentRoute: 'decision' | 'planning' | undefined;

  for (const entry of answerSources ?? []) {
    const route = resolveMixedRemainingAnswerSourceRoute(entry);
    if (!route) {
      continue;
    }

    const descriptorKey =
      route === 'decision'
        ? resolveRemainingDecisionAnswerSourceDescriptorKey(entry)
        : resolveRemainingPlanningAnswerSourceDescriptorKey(entry);

    if (descriptorKey === currentDescriptorKey && route === currentRoute) {
      continue;
    }

    if (seenDescriptorKeys.has(descriptorKey)) {
      const descriptorLabel = formatRemainingAnswerSourceDescriptorLabel(
        descriptorKey,
      );
      issues.push(
        `Non-contiguous remaining answer sources repeated ${descriptorLabel} for mixed remaining answer inference.`,
      );
      continue;
    }

    seenDescriptorKeys.add(descriptorKey);
    currentDescriptorKey = descriptorKey;
    currentRoute = route;
  }

  return issues;
}

function listDecisionTopicRemainingAnswerSourceMergeConflictIssues({
  format,
  sourceResponse,
  answerSources,
  inferDecisionTopics,
  inferOpenDecisions,
  inferRemainingAnswers,
  explicitDecisionAnswerCount,
  explicitPlanningAnswerCount,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  answerSources?: GoalAnswerSourceInput[];
  inferDecisionTopics: boolean;
  inferOpenDecisions: boolean;
  inferRemainingAnswers: boolean;
  explicitDecisionAnswerCount: number;
  explicitPlanningAnswerCount?: number;
}) {
  if (
    !inferDecisionTopics ||
    inferOpenDecisions ||
    explicitDecisionAnswerCount > 0 ||
    !formatWillUseAnswerSourceOnlyInterpretation(
      format,
      normalizeOptionalString(sourceResponse),
      answerSources,
    )
  ) {
    return [] as string[];
  }

  if (!inferRemainingAnswers) {
    return listRemainingAnswerSourceMergeConflictIssues(
      'inferDecisionTopics',
      answerSources ?? [],
      resolveRemainingDecisionAnswerSourceDescriptorKey,
    );
  }

  if ((explicitPlanningAnswerCount ?? 0) > 0) {
    return [];
  }

  if (
    listMixedDecisionTopicAndRemainingAnswerIssues(
      format,
      answerSources,
      inferDecisionTopics,
      inferRemainingAnswers,
    ).length > 0
  ) {
    return [];
  }

  return listRemainingAnswerSourceMergeConflictIssues(
    'inferDecisionTopics + followThrough.inferRemainingAnswers',
    answerSources ?? [],
    (entry) => {
      const route = resolveMixedRemainingAnswerSourceRoute(entry) ?? 'planning';
      const descriptorKey =
        route === 'decision'
          ? resolveRemainingDecisionAnswerSourceDescriptorKey(entry)
          : resolveRemainingPlanningAnswerSourceDescriptorKey(entry);
      return `${route}:${descriptorKey}`;
    },
  );
}

function humanizeRemainingAnswerSourceKey(value: string | undefined) {
  const trimmed = value?.trim();
  if (!trimmed) {
    return undefined;
  }

  const humanized = trimmed.replace(/[_-]+/g, ' ');
  const stripped = humanized.replace(/\s+(?:answer|source)$/i, '').trim();
  if (!stripped || stripped === humanized.trim()) {
    return undefined;
  }

  return stripped;
}

function humanizeRemainingDecisionDescriptorKey(value: string | undefined) {
  const trimmed = value?.trim();
  return trimmed ? trimmed.replace(/[_-]+/g, ' ') : undefined;
}

function parseFrontendOrderedSourceResponseItems(sourceResponse: string) {
  const items: string[] = [];
  for (const line of sourceResponse.split(/\r?\n/)) {
    const trimmed = line.trim();
    if (!trimmed) {
      continue;
    }
    const value = stripFrontendPresentationListMarkers(trimmed);
    if (!value) {
      continue;
    }
    items.push(value);
  }
  return items;
}

function normalizeFrontendOrderedSourceResponseBlock(block: string) {
  const trimmed = block.trim();
  if (!trimmed) {
    return trimmed;
  }

  const paragraphs = trimmed
    .split(/\r?\n\s*\r?\n+/)
    .map((paragraph) => stripFrontendPresentationListMarkers(paragraph.trim()))
    .filter(Boolean);
  if (paragraphs.length === 0) {
    return trimmed;
  }

  return paragraphs.join('\n\n');
}

function parseFrontendOrderedSourceResponseBlocks(sourceResponse: string) {
  return sourceResponse
    .split(/\r?\n\s*\r?\n\s*\r?\n+/)
    .map((block) => normalizeFrontendOrderedSourceResponseBlock(block))
    .filter(Boolean);
}

function frontendSourceResponseHasMultipleMarkedOrderedLines(
  sourceResponse: string | undefined,
) {
  const shared = sourceResponse?.trim();
  if (!shared) {
    return false;
  }

  let markedLineCount = 0;
  for (const line of shared.split(/\r?\n/)) {
    const trimmed = line.trim();
    if (!trimmed) {
      continue;
    }
    if (stripFrontendPresentationListMarkers(trimmed) !== trimmed) {
      markedLineCount += 1;
      if (markedLineCount > 1) {
        return true;
      }
    }
  }

  return false;
}

function listOrderedSourceResponseStructureIssues({
  format,
  sourceResponse,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
}) {
  if (format !== 'ordered_blocks') {
    return [] as string[];
  }

  const normalizedSourceResponse = normalizeOptionalString(sourceResponse) ?? '';
  if (!normalizedSourceResponse) {
    return [] as string[];
  }

  const blocks = parseFrontendOrderedSourceResponseBlocks(normalizedSourceResponse);
  if (
    blocks.length === 1 &&
    frontendSourceResponseHasMultipleMarkedOrderedLines(normalizedSourceResponse)
  ) {
    return [
      'sourceResponseFormat ordered_blocks rejected sourceResponse because it collapsed multiple ordered item lines into one ordered block.',
    ];
  }

  return [] as string[];
}

function listOrderedSourceResponseUnconsumedIssues({
  format,
  sourceResponse,
  explicitDecisionAnswerCount = 0,
  explicitPlanningAnswerCount = 0,
  explicitDecisionKeys = [],
  inferOpenDecisions = false,
  openDecisionKeys = [],
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  explicitDecisionAnswerCount?: number;
  explicitPlanningAnswerCount?: number;
  explicitDecisionKeys?: string[];
  inferOpenDecisions?: boolean;
  openDecisionKeys?: string[];
}) {
  if (format !== 'ordered_items' && format !== 'ordered_blocks') {
    return [] as string[];
  }

  const normalizedSourceResponse = normalizeOptionalString(sourceResponse) ?? '';
  if (!normalizedSourceResponse) {
    return [] as string[];
  }

  if (
    format === 'ordered_blocks' &&
    listOrderedSourceResponseStructureIssues({
      format,
      sourceResponse: normalizedSourceResponse,
    }).length > 0
  ) {
    return [] as string[];
  }

  const unitCount =
    format === 'ordered_items'
      ? parseFrontendOrderedSourceResponseItems(normalizedSourceResponse).length
      : parseFrontendOrderedSourceResponseBlocks(normalizedSourceResponse).length;
  if (unitCount === 0) {
    return [] as string[];
  }

  const normalizedOpenDecisionKeys = new Set(
    openDecisionKeys
      .map((value) => value.trim())
      .filter((value) => value.length > 0),
  );
  const matchedOpenDecisionKeys = new Set(
    explicitDecisionKeys
      .map((value) => value.trim())
      .filter((value) => normalizedOpenDecisionKeys.has(value)),
  );
  const inferredOpenDecisionCount = inferOpenDecisions
    ? Math.max(
        0,
        normalizedOpenDecisionKeys.size - matchedOpenDecisionKeys.size,
      )
    : 0;
  const expectedConsumerCount =
    explicitDecisionAnswerCount +
    explicitPlanningAnswerCount +
    inferredOpenDecisionCount;

  if (expectedConsumerCount <= 0 || unitCount <= expectedConsumerCount) {
    return [] as string[];
  }

  const remainingCount = unitCount - expectedConsumerCount;
  const unitLabel = format === 'ordered_items' ? 'ordered items' : 'ordered blocks';
  return [
    `sourceResponseFormat ${format} rejected sourceResponse because it left ${remainingCount} unconsumed ${unitLabel}.`,
  ];
}

type FrontendQuestionSourceResponseBlock = {
  question: string;
  answer: string;
};

function stripLeadingFrontendQuestionPromptConjunction(question: string) {
  return stripFrontendPresentationListMarkers(
    question.trim().replace(/^(?:and|but)\s+/i, ''),
  );
}

function normalizeFrontendExplicitQuestionSurfaceText(question: string) {
  if (!question) {
    return question;
  }

  return `${question.slice(0, 1).toUpperCase()}${question.slice(1)}`;
}

function inferFrontendCanonicalQuestionPrompt(question: string) {
  const trimmed = stripLeadingFrontendQuestionPromptConjunction(question)
    .replace(/[?？.!。！]+$/u, '')
    .trim();
  const subject = /^what should\s+(?<subject>.+?)\s+be$/i.exec(trimmed)?.groups?.subject;
  if (!subject) {
    return undefined;
  }

  return normalizeFrontendExplicitQuestionSurfaceText(
    `What should ${subject.trim()} be?`,
  );
}

function isFrontendQuestionSourceResponseParagraph(paragraph: string) {
  const trimmed = stripLeadingFrontendQuestionPromptConjunction(paragraph);
  return /[?？]\s*$/u.test(trimmed) || Boolean(inferFrontendCanonicalQuestionPrompt(trimmed));
}

function normalizeFrontendQuestionSourceResponsePrompt(question: string) {
  const trimmed = stripLeadingFrontendQuestionPromptConjunction(question);
  if (!trimmed) {
    return trimmed;
  }
  if (/[?？]\s*$/u.test(trimmed)) {
    return normalizeFrontendExplicitQuestionSurfaceText(trimmed);
  }

  return (
    inferFrontendCanonicalQuestionPrompt(trimmed) ??
    normalizeFrontendExplicitQuestionSurfaceText(trimmed)
  );
}

function parseFrontendQuestionSourceResponseBlocks(sourceResponse: string) {
  const paragraphs = sourceResponse
    .split(/\r?\n\s*\r?\n+/)
    .map((paragraph) => stripFrontendPresentationListMarkers(paragraph.trim()))
    .filter(Boolean);
  const blocks: FrontendQuestionSourceResponseBlock[] = [];
  let currentQuestion: string | undefined;
  let answerParagraphs: string[] = [];

  for (const paragraph of paragraphs) {
    if (isFrontendQuestionSourceResponseParagraph(paragraph)) {
      const questionParagraph =
        normalizeFrontendQuestionSourceResponsePrompt(paragraph);
      if (currentQuestion) {
        if (answerParagraphs.length === 0) {
          throw new Error(
            `Question block "${currentQuestion}" in sourceResponse did not include an answer block.`,
          );
        }
        blocks.push({
          question: currentQuestion,
          answer: answerParagraphs.join('\n\n'),
        });
      } else if (answerParagraphs.length > 0) {
        throw new Error(
          'sourceResponseFormat question_blocks requires sourceResponse to start with a question block.',
        );
      }
      currentQuestion = questionParagraph;
      answerParagraphs = [];
      continue;
    }

    if (!currentQuestion) {
      throw new Error(
        'sourceResponseFormat question_blocks requires sourceResponse to start with a question block.',
      );
    }
    answerParagraphs.push(paragraph);
  }

  if (!currentQuestion) {
    return blocks;
  }
  if (answerParagraphs.length === 0) {
    throw new Error(
      `Question block "${currentQuestion}" in sourceResponse did not include an answer block.`,
    );
  }

  blocks.push({
    question: currentQuestion,
    answer: answerParagraphs.join('\n\n'),
  });
  return blocks;
}

function listQuestionBlockStructureIssues({
  format,
  sourceResponse,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
}) {
  if (format !== 'question_blocks') {
    return [] as string[];
  }

  const normalizedSourceResponse = normalizeOptionalString(sourceResponse) ?? '';
  if (!normalizedSourceResponse) {
    return [] as string[];
  }

  try {
    parseFrontendQuestionSourceResponseBlocks(normalizedSourceResponse);
    return [] as string[];
  } catch (error) {
    return [error instanceof Error ? error.message : String(error)];
  }
}

function listQuestionBlockUnconsumedIssues({
  format,
  sourceResponse,
  explicitDecisionAnswerCount = 0,
  explicitPlanningAnswerCount = 0,
  explicitDecisionKeys = [],
  inferOpenDecisions = false,
  inferDecisionTopics = false,
  inferRemainingAnswers = false,
  openDecisionKeys = [],
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  explicitDecisionAnswerCount?: number;
  explicitPlanningAnswerCount?: number;
  explicitDecisionKeys?: string[];
  inferOpenDecisions?: boolean;
  inferDecisionTopics?: boolean;
  inferRemainingAnswers?: boolean;
  openDecisionKeys?: string[];
}) {
  if (format !== 'question_blocks') {
    return [] as string[];
  }

  if (inferDecisionTopics || inferRemainingAnswers) {
    return [] as string[];
  }

  const normalizedSourceResponse = normalizeOptionalString(sourceResponse) ?? '';
  if (!normalizedSourceResponse) {
    return [] as string[];
  }

  if (
    listQuestionBlockStructureIssues({
      format,
      sourceResponse: normalizedSourceResponse,
    }).length > 0
  ) {
    return [] as string[];
  }

  const blockCount =
    parseFrontendQuestionSourceResponseBlocks(normalizedSourceResponse).length;
  if (blockCount === 0) {
    return [] as string[];
  }

  const normalizedOpenDecisionKeys = new Set(
    openDecisionKeys
      .map((value) => value.trim())
      .filter((value) => value.length > 0),
  );
  const matchedOpenDecisionKeys = new Set(
    explicitDecisionKeys
      .map((value) => value.trim())
      .filter((value) => normalizedOpenDecisionKeys.has(value)),
  );
  const inferredOpenDecisionCount = inferOpenDecisions
    ? Math.max(0, normalizedOpenDecisionKeys.size - matchedOpenDecisionKeys.size)
    : 0;
  const expectedConsumerCount =
    explicitDecisionAnswerCount +
    explicitPlanningAnswerCount +
    inferredOpenDecisionCount;

  if (expectedConsumerCount <= 0 || blockCount <= expectedConsumerCount) {
    return [] as string[];
  }

  return [
    `sourceResponseFormat question_blocks rejected sourceResponse because it left ${blockCount - expectedConsumerCount} unconsumed question blocks.`,
  ];
}

type FrontendLabeledSection = {
  label: string;
  value: string;
};

type FrontendDecisionLabeledSectionConsumer = {
  decisionKey?: string;
  summaryKey?: string;
  summary: string;
  prompt?: string;
  matchHints?: string | string[];
};

type FrontendPlanningLabeledSectionConsumer = {
  answerKey?: string;
  summaryKey?: string;
  summary: string;
  prompt?: string;
  matchHints?: string | string[];
};

function findNestedFrontendLabeledSectionInValue(value: string) {
  const sentences = value
    .split(/(?<=[.?!。？！])\s+/u)
    .map((sentence) => sentence.trim())
    .filter((sentence) => sentence.length > 0);

  const nestedAtStart = /^(?:[-*•]\s*)?([^:：]+?)\s*[:：]\s*(.+)$/u.exec(sentences[0] ?? '');
  if (nestedAtStart?.[1]?.trim() && nestedAtStart?.[2]?.trim()) {
    return nestedAtStart[1].trim();
  }

  for (const sentence of sentences.slice(1)) {
    const nestedSentence = /^(?:[-*•]\s*)?([^:：]+?)\s*[:：]\s*(.+)$/u.exec(sentence);
    if (nestedSentence?.[1]?.trim() && nestedSentence?.[2]?.trim()) {
      return nestedSentence[1].trim();
    }
  }

  return null;
}

function parseFrontendLabeledSectionLine(line: string) {
  const trimmed = line.trim().replace(/^(?:[-*•]\s*)+/u, '');
  if (!trimmed) {
    return undefined;
  }

  const match = /^(?:[-*•]\s*)?([^:：]+?)\s*[:：]\s*(.+)$/u.exec(trimmed);
  const label = match?.[1]?.trim();
  const value = match?.[2]?.trim();
  if (!label || !value) {
    return undefined;
  }

  return { label, value } satisfies FrontendLabeledSection;
}

function analyzeFrontendLabeledSections(sourceResponse: string) {
  const sections: FrontendLabeledSection[] = [];
  const seenLabels = new Set<string>();
  const issues: string[] = [];

  for (const line of sourceResponse.split(/\r?\n/)) {
    const parsed = parseFrontendLabeledSectionLine(line);
    if (!parsed) {
      continue;
    }
    const { label, value } = parsed;

    if (findNestedFrontendLabeledSectionInValue(value)) {
      issues.push(
        `Labeled section "${label}" in sourceResponse included another labeled section inside its value.`,
      );
      continue;
    }

    const normalizedLabel = normalizeRemainingAnswerSourceLabel(label);
    if (!normalizedLabel) {
      continue;
    }
    if (seenLabels.has(normalizedLabel)) {
      issues.push(`Duplicate labeled section "${label}" in sourceResponse.`);
      continue;
    }

    seenLabels.add(normalizedLabel);
    sections.push({ label, value });
  }

  return { sections, issues };
}

function parseFrontendLabeledSections(sourceResponse: string) {
  return analyzeFrontendLabeledSections(sourceResponse).sections;
}

function listLabeledSectionStructureIssues({
  format,
  sourceResponse,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
}) {
  if (format !== 'labeled_sections') {
    return [] as string[];
  }

  return analyzeFrontendLabeledSections(normalizeOptionalString(sourceResponse) ?? '').issues;
}

function listLabeledSectionUnconsumedIssues({
  format,
  sourceResponse,
  explicitConsumerCount,
  inferOpenDecisions = false,
  inferDecisionTopics = false,
  inferRemainingAnswers = false,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  explicitConsumerCount: number;
  inferOpenDecisions?: boolean;
  inferDecisionTopics?: boolean;
  inferRemainingAnswers?: boolean;
}) {
  if (
    format !== 'labeled_sections' ||
    inferOpenDecisions ||
    inferDecisionTopics ||
    inferRemainingAnswers
  ) {
    return [] as string[];
  }

  const { sections, issues } = analyzeFrontendLabeledSections(
    normalizeOptionalString(sourceResponse) ?? '',
  );
  if (issues.length > 0 || sections.length === 0) {
    return [];
  }

  const unconsumedSectionCount = sections.length - explicitConsumerCount;
  if (unconsumedSectionCount <= 0) {
    return [];
  }

  return [
    `sourceResponseFormat labeled_sections rejected sourceResponse because it left ${unconsumedSectionCount} unconsumed labeled sections.`,
  ];
}

function normalizeFrontendLabeledSectionMatchHints(
  value: string | string[] | undefined,
) {
  if (Array.isArray(value)) {
    return value.map((entry) => entry.trim()).filter((entry) => entry.length > 0);
  }

  if (typeof value === 'string') {
    return parseListInput(value);
  }

  return [] as string[];
}

function dedupeFrontendLabeledSectionCandidates(
  candidates: Array<string | undefined>,
) {
  const seen = new Set<string>();
  const result: string[] = [];

  for (const candidate of candidates) {
    const trimmed = candidate?.trim();
    if (!trimmed) {
      continue;
    }
    const identity = normalizeRemainingAnswerSourceLabel(trimmed);
    if (!identity || seen.has(identity)) {
      continue;
    }
    seen.add(identity);
    result.push(trimmed);
  }

  return result;
}

function buildFrontendDecisionLabeledSectionCandidates(
  answer: FrontendDecisionLabeledSectionConsumer,
) {
  return dedupeFrontendLabeledSectionCandidates([
    humanizeRemainingDecisionDescriptorKey(answer.summaryKey),
    humanizeRemainingDecisionDescriptorKey(answer.decisionKey),
    answer.summary,
    answer.prompt,
    ...normalizeFrontendLabeledSectionMatchHints(answer.matchHints),
  ]);
}

function buildFrontendPlanningLabeledSectionCandidates(
  answer: FrontendPlanningLabeledSectionConsumer,
) {
  return dedupeFrontendLabeledSectionCandidates([
    humanizeRemainingDecisionDescriptorKey(answer.answerKey),
    humanizeRemainingDecisionDescriptorKey(answer.summaryKey),
    answer.summary,
    answer.prompt,
    ...normalizeFrontendLabeledSectionMatchHints(answer.matchHints),
  ]);
}

function findFrontendLabeledSectionMatch(
  sections: FrontendLabeledSection[],
  candidates: string[],
  consumedLabels: Set<string>,
) {
  for (const candidate of candidates) {
    const normalizedCandidate = normalizeRemainingAnswerSourceLabel(candidate);
    if (!normalizedCandidate || consumedLabels.has(normalizedCandidate)) {
      continue;
    }

    const match = sections.find(
      (section) =>
        normalizeRemainingAnswerSourceLabel(section.label) === normalizedCandidate,
    );
    if (match) {
      consumedLabels.add(normalizedCandidate);
      return match;
    }
  }

  return null;
}

function listLabeledSectionExplicitConsumerMatchIssues({
  format,
  sourceResponse,
  decisionAnswers = [],
  planningAnswers = [],
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  decisionAnswers?: FrontendDecisionLabeledSectionConsumer[];
  planningAnswers?: FrontendPlanningLabeledSectionConsumer[];
}) {
  if (format !== 'labeled_sections') {
    return [] as string[];
  }

  const { sections, issues } = analyzeFrontendLabeledSections(
    normalizeOptionalString(sourceResponse) ?? '',
  );
  if (issues.length > 0) {
    return [];
  }

  const consumedLabels = new Set<string>();

  for (const answer of decisionAnswers) {
    const candidates = buildFrontendDecisionLabeledSectionCandidates(answer);
    if (candidates.length === 0) {
      continue;
    }

    const match = findFrontendLabeledSectionMatch(sections, candidates, consumedLabels);
    if (!match) {
      return [
        `No labeled section matched decision answer ${
          answer.decisionKey?.trim() || answer.summary.trim()
        } in sourceResponse.`,
      ];
    }
  }

  for (const answer of planningAnswers) {
    const candidates = buildFrontendPlanningLabeledSectionCandidates(answer);
    if (candidates.length === 0) {
      continue;
    }

    const match = findFrontendLabeledSectionMatch(sections, candidates, consumedLabels);
    if (!match) {
      return [
        `No labeled section matched planner answer ${answer.summary.trim()} in sourceResponse.`,
      ];
    }
  }

  return [] as string[];
}

const FRONTEND_INLINE_TOPIC_SUMMARY_VERB_PATTERN =
  '(?:should|will|must|can|could|would|is|are|was|were|uses|use|means|requires|starts)';

const FRONTEND_LEADING_IDEOGRAPHIC_COMMA_NUMBER_MARKER_PATTERN =
  /^(?:(?:\d+|[０-９]+|[一二三四五六七八九十百千]+)、\s*)+/u;
const FRONTEND_LEADING_CJK_NUMBER_PAREN_MARKER_PATTERN =
  /^(?:(?:\([一二三四五六七八九十百千]+\)|（[一二三四五六七八九十百千]+）)\s*)+/u;
const FRONTEND_LEADING_FULLWIDTH_NUMBER_PAREN_MARKER_PATTERN =
  /^(?:(?:\([０-９]+\)|（[０-９]+）)\s*)+/u;
const FRONTEND_LEADING_FULLWIDTH_NUMBER_MARKER_PATTERN =
  /^(?:(?:[０-９]+[．.)）])\s*)+/u;
const FRONTEND_LEADING_CIRCLED_NUMBER_MARKER_PATTERN = /^(?:[①-⑳]\s*)+/u;
const FRONTEND_LEADING_COMMON_ROMAN_OUTLINE_PAREN_MARKER_PATTERN =
  /^(?:(?:\([IVXivx]{2,8}\)|（[IVXivx]{2,8}）)\s*)+/u;
const FRONTEND_LEADING_COMMON_ROMAN_OUTLINE_MARKER_PATTERN =
  /^(?:(?:[IVX]{2,8}[.)])\s*)+/u;

function stripFrontendPresentationListMarkers(text: string) {
  let stripped = text.trim();

  while (stripped) {
    const next = stripped
      .replace(/^(?:#{1,6}\s+)+/u, '')
      .replace(/^(?:>\s*)+/u, '')
      .replace(/^(?:[-*]\s*\[(?: |x|X)\]\s*)+/u, '')
      .replace(/^(?:\[(?: |x|X)\]\s*)+/u, '')
      .replace(FRONTEND_LEADING_IDEOGRAPHIC_COMMA_NUMBER_MARKER_PATTERN, '')
      .replace(FRONTEND_LEADING_CJK_NUMBER_PAREN_MARKER_PATTERN, '')
      .replace(FRONTEND_LEADING_FULLWIDTH_NUMBER_PAREN_MARKER_PATTERN, '')
      .replace(FRONTEND_LEADING_FULLWIDTH_NUMBER_MARKER_PATTERN, '')
      .replace(FRONTEND_LEADING_CIRCLED_NUMBER_MARKER_PATTERN, '')
      .replace(/^(?:(?:\(\d+\)|（\d+）|\([A-Za-z]\)|（[A-Za-z]）)\s*)+/u, '')
      .replace(FRONTEND_LEADING_COMMON_ROMAN_OUTLINE_PAREN_MARKER_PATTERN, '')
      .replace(FRONTEND_LEADING_COMMON_ROMAN_OUTLINE_MARKER_PATTERN, '')
      .replace(/^(?:(?:\d+[.)]|[A-Za-z][.)])\s*)+/u, '')
      .replace(/^(?:[-+*•・●→○◦▪◆■□▸▹►▻▶▷⁃‣–—―]\s*)+/u, '')
      .trim();
    if (next === stripped) {
      return stripped;
    }
    stripped = next;
  }

  return stripped;
}

function frontendInlineTopicPredicateIncludesSubstantiveAnswerContent(answer: string) {
  const stripped = answer
    .trim()
    .replace(
      new RegExp(`^(?:${FRONTEND_INLINE_TOPIC_SUMMARY_VERB_PATTERN})\\b\\s*`, 'i'),
      '',
    )
    .replace(
      /^(?:(?:be|been|being|use|uses|means|requires|starts|with|as|the|a|an|our|your|their)\b\s*)+/i,
      '',
    )
    .replace(/^[\p{P}\p{S}\s]+/gu, '')
    .trim();

  return /[\p{L}\p{N}]/u.test(stripped);
}

function normalizeFrontendInlineTopicAnswer(value: string) {
  const stripped = value
    .trim()
    .replace(
      new RegExp(`^(?:${FRONTEND_INLINE_TOPIC_SUMMARY_VERB_PATTERN})\\b\\s*`, 'i'),
      '',
    )
    .trim();

  if (stripped.length === 0) {
    return stripped;
  }

  return `${stripped.slice(0, 1).toUpperCase()}${stripped.slice(1)}`;
}

function isFrontendQuestionLikeInlineTopicClause(text: string) {
  const trimmed = text.trim();
  return (
    /[?？]$/u.test(trimmed) ||
    /^(?:what|which|who|when|where|why|how)\b/i.test(trimmed)
  );
}

function shouldMergeWithFollowingFrontendInlineTopicClause(clause: string) {
  const trimmed = stripFrontendPresentationListMarkers(
    clause.trim().replace(/^(?:and|but)\s+/i, ''),
  );
  if (!trimmed || /[.?!。？！]$/u.test(trimmed)) {
    return false;
  }

  if (/^(?<label>.+?)\s*(?::|：|=|＝|->|－>|→)\s*$/u.test(trimmed)) {
    return true;
  }

  if (/^(?<label>.+?)\s+(?:-|－|–|—)\s*$/u.test(trimmed)) {
    return true;
  }

  const verbal = new RegExp(
    `^(?<label>.+?)\\s+(?<answer>${FRONTEND_INLINE_TOPIC_SUMMARY_VERB_PATTERN}\\b.*)$`,
    'i',
  ).exec(trimmed)?.groups;

  return Boolean(
    verbal?.answer &&
      !frontendInlineTopicPredicateIncludesSubstantiveAnswerContent(verbal.answer),
  );
}

function splitFrontendInlineTopicClauses(sourceResponse: string) {
  const rawClauses = sourceResponse
    .split(/(?:\r?\n+|;+\s*|；+\s*|(?<=[.?!。？！])\s+)/)
    .map((clause) => clause.trim())
    .filter((clause) => clause.length > 0);

  const clauses: string[] = [];
  for (const clause of rawClauses) {
    const previousClause = clauses.at(-1);
    if (
      previousClause &&
      shouldMergeWithFollowingFrontendInlineTopicClause(previousClause)
    ) {
      clauses[clauses.length - 1] = `${previousClause} ${clause}`.trim();
      continue;
    }
    clauses.push(clause);
  }

  return clauses;
}

function parseFrontendInlineTopicClause(clause: string) {
  const trimmed = stripFrontendPresentationListMarkers(
    clause.trim().replace(/^(?:and|but)\s+/i, ''),
  );
  if (!trimmed) {
    return undefined;
  }

  const punctuated = /^(?<label>.+?)\s*(?::|：|=|＝|->|－>|→)\s*(?<answer>.+)$/u.exec(
    trimmed,
  )?.groups;
  if (punctuated?.label && punctuated.answer) {
    return {
      label: punctuated.label.trim(),
      value: normalizeFrontendInlineTopicAnswer(punctuated.answer),
    } satisfies FrontendLabeledSection;
  }

  const dashed = /^(?<label>.+?)\s+(?:-|－|–|—)\s+(?<answer>.+)$/u.exec(
    trimmed,
  )?.groups;
  if (dashed?.label && dashed.answer) {
    return {
      label: dashed.label.trim(),
      value: normalizeFrontendInlineTopicAnswer(dashed.answer),
    } satisfies FrontendLabeledSection;
  }

  if (isFrontendQuestionLikeInlineTopicClause(trimmed)) {
    return undefined;
  }

  const verbal = new RegExp(
    `^(?<label>.+?)\\s+(?<answer>${FRONTEND_INLINE_TOPIC_SUMMARY_VERB_PATTERN}\\b.+)$`,
    'i',
  ).exec(trimmed)?.groups;
  if (
    verbal?.label &&
    verbal.answer &&
    frontendInlineTopicPredicateIncludesSubstantiveAnswerContent(verbal.answer)
  ) {
    return {
      label: verbal.label.trim(),
      value: normalizeFrontendInlineTopicAnswer(verbal.answer),
    } satisfies FrontendLabeledSection;
  }

  return undefined;
}

function frontendInlineTopicClauseUsesExplicitLabelValueSeparator(trimmedClause: string) {
  return (
    /^(?<label>.+?)\s*(?::|：|=|＝|->|－>|→)\s*(?<answer>.+)$/u.test(trimmedClause) ||
    /^(?<label>.+?)\s+(?:-|－|–|—)\s+(?<answer>.+)$/u.test(trimmedClause)
  );
}

function analyzeFrontendInlineTopicClauses(sourceResponse: string) {
  const sections: FrontendLabeledSection[] = [];
  const seenLabels = new Set<string>();
  const issues: string[] = [];

  for (const clause of splitFrontendInlineTopicClauses(sourceResponse)) {
    const parsed = parseFrontendInlineTopicClause(clause);
    if (!parsed) {
      continue;
    }

    const normalizedLabel = normalizeRemainingAnswerSourceLabel(parsed.label);
    if (!normalizedLabel) {
      continue;
    }
    if (seenLabels.has(normalizedLabel)) {
      issues.push(`Duplicate inline topic clause "${parsed.label}" in sourceResponse.`);
      continue;
    }

    seenLabels.add(normalizedLabel);
    sections.push(parsed);
  }

  return { sections, issues };
}

function parseFrontendInlineTopicClauses(sourceResponse: string) {
  return analyzeFrontendInlineTopicClauses(sourceResponse).sections;
}

function listInlineTopicStructureIssues({
  format,
  sourceResponse,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
}) {
  if (format !== 'inline_topics') {
    return [] as string[];
  }

  return analyzeFrontendInlineTopicClauses(normalizeOptionalString(sourceResponse) ?? '').issues;
}

function listInlineTopicUnconsumedIssues({
  format,
  sourceResponse,
  explicitConsumerCount,
  inferOpenDecisions = false,
  inferDecisionTopics = false,
  inferRemainingAnswers = false,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  explicitConsumerCount: number;
  inferOpenDecisions?: boolean;
  inferDecisionTopics?: boolean;
  inferRemainingAnswers?: boolean;
}) {
  if (
    format !== 'inline_topics' ||
    inferOpenDecisions ||
    inferDecisionTopics ||
    inferRemainingAnswers
  ) {
    return [] as string[];
  }

  const { sections, issues } = analyzeFrontendInlineTopicClauses(
    normalizeOptionalString(sourceResponse) ?? '',
  );
  if (issues.length > 0 || sections.length === 0) {
    return [];
  }

  const unconsumedSectionCount = sections.length - explicitConsumerCount;
  if (unconsumedSectionCount <= 0) {
    return [];
  }

  return [
    `sourceResponseFormat inline_topics rejected sourceResponse because it left ${unconsumedSectionCount} unconsumed inline topic clauses.`,
  ];
}

function findFrontendInlineTopicMatch(
  sections: FrontendLabeledSection[],
  candidates: string[],
  consumedLabels: Set<string>,
) {
  for (const candidate of candidates) {
    const normalizedCandidate = normalizeRemainingAnswerSourceLabel(candidate);
    if (!normalizedCandidate || consumedLabels.has(normalizedCandidate)) {
      continue;
    }

    const match = sections.find(
      (section) =>
        normalizeRemainingAnswerSourceLabel(section.label) === normalizedCandidate,
    );
    if (match) {
      consumedLabels.add(normalizedCandidate);
      return match;
    }
  }

  return null;
}

function listInlineTopicExplicitConsumerMatchIssues({
  format,
  sourceResponse,
  decisionAnswers = [],
  planningAnswers = [],
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  decisionAnswers?: FrontendDecisionLabeledSectionConsumer[];
  planningAnswers?: FrontendPlanningLabeledSectionConsumer[];
}) {
  if (format !== 'inline_topics') {
    return [] as string[];
  }

  const { sections, issues } = analyzeFrontendInlineTopicClauses(
    normalizeOptionalString(sourceResponse) ?? '',
  );
  if (issues.length > 0) {
    return [];
  }

  const consumedLabels = new Set<string>();

  for (const answer of decisionAnswers) {
    const candidates = buildFrontendDecisionLabeledSectionCandidates(answer);
    if (candidates.length === 0) {
      continue;
    }

    const match = findFrontendInlineTopicMatch(sections, candidates, consumedLabels);
    if (!match) {
      return [
        `No inline topic clause matched decision answer ${
          answer.decisionKey?.trim() || answer.summary.trim()
        } in sourceResponse.`,
      ];
    }
  }

  for (const answer of planningAnswers) {
    const candidates = buildFrontendPlanningLabeledSectionCandidates(answer);
    if (candidates.length === 0) {
      continue;
    }

    const match = findFrontendInlineTopicMatch(sections, candidates, consumedLabels);
    if (!match) {
      return [
        `No inline topic clause matched planner answer ${answer.summary.trim()} in sourceResponse.`,
      ];
    }
  }

  return [] as string[];
}

function listInlineTopicDecisionTopicIssues({
  format,
  sourceResponse,
  decisions,
  inferDecisionTopics,
  inferOpenDecisions,
  inferRemainingAnswers,
  explicitDecisionAnswerCount,
  explicitPlanningAnswerCount,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  decisions: GoalDecision[];
  inferDecisionTopics: boolean;
  inferOpenDecisions: boolean;
  inferRemainingAnswers: boolean;
  explicitDecisionAnswerCount: number;
  explicitPlanningAnswerCount?: number;
}) {
  if (!inferDecisionTopics || format !== 'inline_topics') {
    return [] as string[];
  }

  const sections = parseFrontendInlineTopicClauses(
    normalizeOptionalString(sourceResponse) ?? '',
  );
  if (sections.length === 0) {
    return [
      'sourceResponseFormat inline_topics requires at least one inline topic clause when inferDecisionTopics is enabled.',
    ];
  }

  if (
    inferOpenDecisions ||
    inferRemainingAnswers ||
    explicitDecisionAnswerCount > 0 ||
    (explicitPlanningAnswerCount ?? 0) > 0
  ) {
    return [];
  }

  const summaryCounts = buildKnownDecisionSummaryCountMap(decisions);
  const issues: string[] = [];
  const seenSummaries = new Set<string>();

  for (const section of sections) {
    const normalizedSummary = normalizeRemainingAnswerSourceLabel(section.label);
    if (!normalizedSummary || seenSummaries.has(normalizedSummary)) {
      continue;
    }

    if ((summaryCounts.get(normalizedSummary) ?? 0) > 1) {
      issues.push(`Multiple existing decisions match inferred label "${section.label}".`);
      seenSummaries.add(normalizedSummary);
    }
  }

  return issues;
}

function listInlineTopicOpenDecisionIssues({
  format,
  sourceResponse,
  decisions,
  inferOpenDecisions,
  explicitDecisionAnswerCount,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  decisions: GoalDecision[];
  inferOpenDecisions: boolean;
  explicitDecisionAnswerCount: number;
}) {
  if (!inferOpenDecisions || format !== 'inline_topics' || explicitDecisionAnswerCount > 0) {
    return [] as string[];
  }

  const sections = parseFrontendInlineTopicClauses(
    normalizeOptionalString(sourceResponse) ?? '',
  );
  if (sections.length === 0) {
    return [
      'sourceResponseFormat inline_topics requires at least one inline topic clause when inferOpenDecisions is enabled.',
    ];
  }

  const openDecisionSummaries = buildKnownDecisionSummaryLookup(decisions);
  if (openDecisionSummaries.size === 0) {
    return [];
  }

  const hasMatchingOpenDecision = sections.some((section) =>
    openDecisionSummaries.has(normalizeRemainingAnswerSourceLabel(section.label)),
  );
  if (hasMatchingOpenDecision) {
    return [];
  }

  return [
    'sourceResponseFormat inline_topics requires at least one inline topic clause to match an open decision when inferOpenDecisions is enabled.',
  ];
}

function formatFrontendQuotedValueList(values: string[]) {
  return values.map((value) => `"${value}"`).join(', ');
}

function dedupeNonEmptyFrontendStrings(values: Array<string | undefined>) {
  const seen = new Set<string>();
  const result: string[] = [];

  for (const value of values) {
    const trimmed = value?.trim();
    if (!trimmed || seen.has(trimmed)) {
      continue;
    }
    seen.add(trimmed);
    result.push(trimmed);
  }

  return result;
}

function splitFrontendStandaloneAuthoritySentences(text: string) {
  return text
    .split(/(?:\r?\n+|(?<=[.?!。？！])\s+)/u)
    .map((sentence) => sentence.trim())
    .filter((sentence) => sentence.length > 0);
}

function humanizeFrontendStandaloneTopicSummary(value: string | undefined) {
  const normalized = value
    ?.trim()
    .replace(/[_-]+/g, ' ')
    .replace(/\s+/g, ' ');
  if (!normalized) {
    return undefined;
  }

  return `${normalized.slice(0, 1).toUpperCase()}${normalized.slice(1)}`;
}

function normalizeFrontendQuestionAuthorityPrompt(text: string) {
  const trimmed = stripFrontendPresentationListMarkers(
    text.trim().replace(/^(?:and|but)\s+/i, ''),
  )
    .replace(/[?？]+$/u, '')
    .trim();
  if (!trimmed) {
    return undefined;
  }

  const canonicalSummary = /^(?:what)\s+should\s+(?:the\s+)?(.+?)\s+be$/i.exec(trimmed)?.[1];
  const normalizedSummary = normalizeRemainingAnswerSourceLabel(
    canonicalSummary ?? '',
  );
  if (normalizedSummary) {
    return `What should the ${normalizedSummary} be?`;
  }

  const collapsed = trimmed.replace(/\s+/g, ' ');
  return `${collapsed.slice(0, 1).toUpperCase()}${collapsed.slice(1)}?`;
}

function extractFrontendStandaloneQuestionAuthoritiesFromText(text: string) {
  return dedupeNonEmptyFrontendStrings(
    splitFrontendStandaloneAuthoritySentences(text).flatMap((sentence) => {
      if (!isFrontendQuestionLikeInlineTopicClause(sentence)) {
        return [];
      }

      const normalized = normalizeFrontendQuestionAuthorityPrompt(sentence);
      return normalized ? [normalized] : [];
    }),
  );
}

function extractFrontendStandaloneTopicAuthoritiesFromText(
  text: string,
  { includeInlineTopicLabels = false }: { includeInlineTopicLabels?: boolean } = {},
) {
  return dedupeNonEmptyFrontendStrings(
    splitFrontendStandaloneAuthoritySentences(text).flatMap((sentence) => {
      const trimmed = stripFrontendPresentationListMarkers(
        sentence.trim().replace(/^(?:and|but)\s+/i, ''),
      );
      if (!trimmed) {
        return [];
      }

      const inlineTopicClause = parseFrontendInlineTopicClause(trimmed);
      if (inlineTopicClause) {
        return includeInlineTopicLabels ? [inlineTopicClause.label] : [];
      }

      const prefixedSummary =
        /^(?:for|about|regarding)\s+(.+?)(?:\s*[:,]|,\s*|\s+(?:use|be|is|are|should|can|will|needs|need|requires|means|starts|start|works|work)\b)/i.exec(
          trimmed,
        )?.[1] ??
        undefined;
      const trailingSummary =
        /\bfor\s+(.+?)(?:[.?!。？！]|$)/i.exec(trimmed)?.[1] ?? undefined;

      return dedupeNonEmptyFrontendStrings([
        humanizeFrontendStandaloneTopicSummary(prefixedSummary),
        humanizeFrontendStandaloneTopicSummary(trailingSummary),
      ]);
    }),
  );
}

function collectSemanticallyValidFrontendInlineTopicClauseIndexes(sourceResponse: string) {
  const indexes = new Set<number>();

  for (const [clauseIndex, clause] of splitFrontendInlineTopicClauses(
    sourceResponse,
  ).entries()) {
    if (parseFrontendInlineTopicClause(clause)) {
      indexes.add(clauseIndex);
    }
  }

  return indexes;
}

function groupRemainingNonFrontendInlineTopicClauseChunks(
  sourceResponse: string,
  inlineClauseIndexes: Set<number>,
) {
  const chunks: string[] = [];
  let currentChunkClauses: string[] = [];

  for (const [clauseIndex, clause] of splitFrontendInlineTopicClauses(
    sourceResponse,
  ).entries()) {
    if (inlineClauseIndexes.has(clauseIndex)) {
      if (currentChunkClauses.length > 0) {
        chunks.push(currentChunkClauses.join(' '));
        currentChunkClauses = [];
      }
      continue;
    }

    currentChunkClauses.push(clause);
  }

  if (currentChunkClauses.length > 0) {
    chunks.push(currentChunkClauses.join(' '));
  }

  return chunks;
}

function hasFrontendInlineTopicExplicitConsumerCoverage(
  sections: FrontendLabeledSection[],
  decisionAnswers: FrontendDecisionLabeledSectionConsumer[],
  planningAnswers: FrontendPlanningLabeledSectionConsumer[],
) {
  const consumedLabels = new Set<string>();
  let matchedConsumerCount = 0;

  for (const answer of decisionAnswers) {
    const candidates = buildFrontendDecisionLabeledSectionCandidates(answer);
    if (candidates.length === 0) {
      continue;
    }

    matchedConsumerCount += 1;
    if (!findFrontendInlineTopicMatch(sections, candidates, consumedLabels)) {
      return false;
    }
  }

  for (const answer of planningAnswers) {
    const candidates = buildFrontendPlanningLabeledSectionCandidates(answer);
    if (candidates.length === 0) {
      continue;
    }

    matchedConsumerCount += 1;
    if (!findFrontendInlineTopicMatch(sections, candidates, consumedLabels)) {
      return false;
    }
  }

  return matchedConsumerCount > 0;
}

function listInlineTopicStandaloneAuthorityIssues({
  format,
  sourceResponse,
  decisionAnswers = [],
  planningAnswers = [],
  decisions = [],
  inferDecisionTopics = false,
  inferOpenDecisions = false,
  inferRemainingAnswers = false,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  decisionAnswers?: FrontendDecisionLabeledSectionConsumer[];
  planningAnswers?: FrontendPlanningLabeledSectionConsumer[];
  decisions?: GoalDecision[];
  inferDecisionTopics?: boolean;
  inferOpenDecisions?: boolean;
  inferRemainingAnswers?: boolean;
}) {
  if (format !== 'inline_topics') {
    return [] as string[];
  }

  const normalizedSourceResponse = normalizeOptionalString(sourceResponse) ?? '';
  if (!normalizedSourceResponse) {
    return [] as string[];
  }

  const { sections, issues } = analyzeFrontendInlineTopicClauses(
    normalizedSourceResponse,
  );
  if (issues.length > 0 || sections.length === 0) {
    return [] as string[];
  }

  const hasExplicitCoverage = hasFrontendInlineTopicExplicitConsumerCoverage(
    sections,
    decisionAnswers,
    planningAnswers,
  );
  const openDecisionSummaries = buildKnownDecisionSummaryLookup(decisions);
  const hasOpenDecisionCoverage =
    inferOpenDecisions &&
    sections.some((section) =>
      openDecisionSummaries.has(
        normalizeRemainingAnswerSourceLabel(section.label),
      ),
    );
  const hasDecisionTopicInferenceCoverage =
    inferDecisionTopics &&
    !inferOpenDecisions &&
    !inferRemainingAnswers &&
    decisionAnswers.length === 0 &&
    planningAnswers.length === 0;

  if (
    !hasExplicitCoverage &&
    !hasOpenDecisionCoverage &&
    !hasDecisionTopicInferenceCoverage
  ) {
    return [] as string[];
  }

  const inlineClauseIndexes =
    collectSemanticallyValidFrontendInlineTopicClauseIndexes(
      normalizedSourceResponse,
    );
  if (inlineClauseIndexes.size === 0) {
    return [] as string[];
  }

  const remainingChunks = groupRemainingNonFrontendInlineTopicClauseChunks(
    normalizedSourceResponse,
    inlineClauseIndexes,
  );
  if (remainingChunks.length === 0) {
    return [] as string[];
  }

  const standaloneQuestionAuthorities = dedupeNonEmptyFrontendStrings(
    remainingChunks.flatMap((chunk) =>
      extractFrontendStandaloneQuestionAuthoritiesFromText(chunk),
    ),
  );
  if (standaloneQuestionAuthorities.length > 0) {
    return [
      `sourceResponseFormat inline_topics rejected sourceResponse because it still included standalone question authority ${formatFrontendQuotedValueList(
        standaloneQuestionAuthorities,
      )} outside inline topic clauses.`,
    ];
  }

  const standaloneTopicAuthorities = dedupeNonEmptyFrontendStrings(
    remainingChunks.flatMap((chunk) =>
      extractFrontendStandaloneTopicAuthoritiesFromText(chunk),
    ),
  );
  if (standaloneTopicAuthorities.length > 0) {
    return [
      `sourceResponseFormat inline_topics rejected sourceResponse because it still included standalone topic authority for ${formatFrontendQuotedValueList(
        standaloneTopicAuthorities,
      )} outside inline topic clauses.`,
    ];
  }

  return [] as string[];
}

function groupRemainingNonFrontendLabeledSectionLineChunks(sourceResponse: string) {
  const chunks: string[] = [];
  let currentChunkLines: string[] = [];

  const flushChunk = () => {
    if (currentChunkLines.length === 0) {
      return;
    }

    chunks.push(currentChunkLines.join(' '));
    currentChunkLines = [];
  };

  for (const line of sourceResponse.split(/\r?\n/)) {
    const trimmed = line.trim();
    if (!trimmed) {
      flushChunk();
      continue;
    }

    if (parseFrontendLabeledSectionLine(line)) {
      flushChunk();
      continue;
    }

    currentChunkLines.push(trimmed);
  }

  flushChunk();
  return chunks;
}

function listLabeledSectionStandaloneAuthorityIssues({
  format,
  sourceResponse,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
}) {
  if (format !== 'labeled_sections' && format !== 'auto') {
    return [] as string[];
  }

  const normalizedSourceResponse = normalizeOptionalString(sourceResponse) ?? '';
  if (!normalizedSourceResponse) {
    return [] as string[];
  }

  const { sections, issues } = analyzeFrontendLabeledSections(
    normalizedSourceResponse,
  );
  if (issues.length > 0 || sections.length === 0) {
    return [];
  }

  const remainingChunks = groupRemainingNonFrontendLabeledSectionLineChunks(
    normalizedSourceResponse,
  );
  if (remainingChunks.length === 0) {
    return [];
  }

  const standaloneQuestionAuthorities = dedupeNonEmptyFrontendStrings(
    remainingChunks.flatMap((chunk) =>
      extractFrontendStandaloneQuestionAuthoritiesFromText(chunk),
    ),
  );
  if (standaloneQuestionAuthorities.length > 0) {
    return [
      format === 'auto'
        ? `sourceResponseFormat auto rejected labeled_sections because sourceResponse still included standalone question authority ${formatFrontendQuotedValueList(
            standaloneQuestionAuthorities,
          )} outside labeled sections.`
        : `sourceResponseFormat labeled_sections rejected sourceResponse because it still included standalone question authority ${formatFrontendQuotedValueList(
            standaloneQuestionAuthorities,
          )} outside labeled sections.`,
    ];
  }

  const standaloneTopicAuthorities = dedupeNonEmptyFrontendStrings(
    remainingChunks.flatMap((chunk) =>
      extractFrontendStandaloneTopicAuthoritiesFromText(chunk, {
        includeInlineTopicLabels: true,
      }),
    ),
  );
  if (standaloneTopicAuthorities.length > 0) {
    return [
      format === 'auto'
        ? `sourceResponseFormat auto rejected labeled_sections because sourceResponse still included standalone topic authority for ${formatFrontendQuotedValueList(
            standaloneTopicAuthorities,
          )} outside labeled sections.`
        : `sourceResponseFormat labeled_sections rejected sourceResponse because it still included standalone topic authority for ${formatFrontendQuotedValueList(
            standaloneTopicAuthorities,
          )} outside labeled sections.`,
    ];
  }

  return [] as string[];
}

function listAutoInlineTopicMixedAuthorityIssues({
  format,
  sourceResponse,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
}) {
  if (format !== 'auto') {
    return [] as string[];
  }

  const normalizedSourceResponse = normalizeOptionalString(sourceResponse) ?? '';
  if (!normalizedSourceResponse) {
    return [] as string[];
  }

  let hasSeparatorStyleClause = false;
  const verbalAuthorities: string[] = [];

  for (const clause of splitFrontendInlineTopicClauses(normalizedSourceResponse)) {
    const parsed = parseFrontendInlineTopicClause(clause);
    if (!parsed) {
      continue;
    }

    const trimmedClause = stripFrontendPresentationListMarkers(
      clause.trim().replace(/^(?:and|but)\s+/i, ''),
    );
    if (!trimmedClause) {
      continue;
    }

    if (frontendInlineTopicClauseUsesExplicitLabelValueSeparator(trimmedClause)) {
      hasSeparatorStyleClause = true;
      continue;
    }

    verbalAuthorities.push(parsed.label);
  }

  const normalizedAuthorities = dedupeNonEmptyFrontendStrings(verbalAuthorities);
  if (!hasSeparatorStyleClause || normalizedAuthorities.length === 0) {
    return [] as string[];
  }

  return [
    `sourceResponseFormat inline_topics rejected sourceResponse because it mixed separator-style inline topic authority with additional verbal inline topic authority for ${formatFrontendQuotedValueList(
      normalizedAuthorities,
    )}.`,
  ];
}

function inferExactRemainingDecisionTopicSummary(entry: GoalAnswerSourceInput) {
  if (entry.summary?.trim()) {
    return entry.summary.trim();
  }

  const decisionKeySummary = humanizeRemainingDecisionDescriptorKey(entry.decisionKey);
  if (decisionKeySummary) {
    return decisionKeySummary;
  }

  const summaryKeySummary = humanizeRemainingDecisionDescriptorKey(entry.summaryKey);
  if (summaryKeySummary) {
    return summaryKeySummary;
  }

  return humanizeRemainingAnswerSourceKey(entry.answerSourceKey);
}

function buildKnownDecisionSummaryCountMap(decisions: GoalDecision[]) {
  const counts = new Map<string, number>();

  for (const decision of decisions) {
    const candidateSummaries = [
      decision.summary,
      humanizeRemainingDecisionDescriptorKey(decision.summaryKey),
    ];
    const seenSummaries = new Set<string>();

    for (const candidateSummary of candidateSummaries) {
      const normalizedSummary = normalizeRemainingAnswerSourceLabel(candidateSummary ?? '');
      if (!normalizedSummary || seenSummaries.has(normalizedSummary)) {
        continue;
      }

      seenSummaries.add(normalizedSummary);
      counts.set(normalizedSummary, (counts.get(normalizedSummary) ?? 0) + 1);
    }
  }

  return counts;
}

function buildKnownDecisionSummaryLookup(decisions: GoalDecision[]) {
  const summaries = new Set<string>();

  for (const decision of decisions) {
    const candidateSummaries = [
      decision.summary,
      humanizeRemainingDecisionDescriptorKey(decision.summaryKey),
    ];

    for (const candidateSummary of candidateSummaries) {
      const normalizedSummary = normalizeRemainingAnswerSourceLabel(candidateSummary ?? '');
      if (!normalizedSummary) {
        continue;
      }
      summaries.add(normalizedSummary);
    }
  }

  return summaries;
}

function listLabeledSectionDecisionTopicIssues({
  format,
  sourceResponse,
  decisions,
  inferDecisionTopics,
  inferOpenDecisions,
  inferRemainingAnswers,
  explicitDecisionAnswerCount,
  explicitPlanningAnswerCount,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  decisions: GoalDecision[];
  inferDecisionTopics: boolean;
  inferOpenDecisions: boolean;
  inferRemainingAnswers: boolean;
  explicitDecisionAnswerCount: number;
  explicitPlanningAnswerCount?: number;
}) {
  if (!inferDecisionTopics || format !== 'labeled_sections') {
    return [] as string[];
  }

  const sections = parseFrontendLabeledSections(
    normalizeOptionalString(sourceResponse) ?? '',
  );
  if (sections.length === 0) {
    return [
      'sourceResponseFormat labeled_sections requires at least one labeled section when inferDecisionTopics is enabled.',
    ];
  }

  if (
    inferOpenDecisions ||
    inferRemainingAnswers ||
    explicitDecisionAnswerCount > 0 ||
    (explicitPlanningAnswerCount ?? 0) > 0
  ) {
    return [];
  }

  const summaryCounts = buildKnownDecisionSummaryCountMap(decisions);
  const issues: string[] = [];
  const seenSummaries = new Set<string>();

  for (const section of sections) {
    const normalizedSummary = normalizeRemainingAnswerSourceLabel(section.label);
    if (!normalizedSummary || seenSummaries.has(normalizedSummary)) {
      continue;
    }

    if ((summaryCounts.get(normalizedSummary) ?? 0) > 1) {
      issues.push(`Multiple existing decisions match inferred label "${section.label}".`);
      seenSummaries.add(normalizedSummary);
    }
  }

  return issues;
}

function listLabeledSectionOpenDecisionIssues({
  format,
  sourceResponse,
  decisions,
  inferOpenDecisions,
  explicitDecisionAnswerCount,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  decisions: GoalDecision[];
  inferOpenDecisions: boolean;
  explicitDecisionAnswerCount: number;
}) {
  if (!inferOpenDecisions || format !== 'labeled_sections' || explicitDecisionAnswerCount > 0) {
    return [] as string[];
  }

  const sections = parseFrontendLabeledSections(
    normalizeOptionalString(sourceResponse) ?? '',
  );
  if (sections.length === 0) {
    return [
      'sourceResponseFormat labeled_sections requires at least one labeled section when inferOpenDecisions is enabled.',
    ];
  }

  const openDecisionSummaries = buildKnownDecisionSummaryLookup(decisions);
  if (openDecisionSummaries.size === 0) {
    return [];
  }

  const hasMatchingOpenDecision = sections.some((section) =>
    openDecisionSummaries.has(normalizeRemainingAnswerSourceLabel(section.label)),
  );
  if (hasMatchingOpenDecision) {
    return [];
  }

  return [
    'sourceResponseFormat labeled_sections requires at least one labeled section to match an open decision when inferOpenDecisions is enabled.',
  ];
}

function listDecisionTopicRemainingKnownDecisionAmbiguityIssues({
  format,
  sourceResponse,
  answerSources,
  decisions,
  inferDecisionTopics,
  inferOpenDecisions,
  inferRemainingAnswers,
  explicitDecisionAnswerCount,
  explicitPlanningAnswerCount,
}: {
  format: GoalSourceResponseFormat;
  sourceResponse: string;
  answerSources?: GoalAnswerSourceInput[];
  decisions: GoalDecision[];
  inferDecisionTopics: boolean;
  inferOpenDecisions: boolean;
  inferRemainingAnswers: boolean;
  explicitDecisionAnswerCount: number;
  explicitPlanningAnswerCount?: number;
}) {
  if (
    !inferDecisionTopics ||
    inferOpenDecisions ||
    explicitDecisionAnswerCount > 0 ||
    !formatWillUseAnswerSourceOnlyInterpretation(
      format,
      normalizeOptionalString(sourceResponse),
      answerSources,
    )
  ) {
    return [] as string[];
  }

  if (
    inferRemainingAnswers &&
    ((explicitPlanningAnswerCount ?? 0) > 0 ||
      listMixedDecisionTopicAndRemainingAnswerIssues(
        format,
        answerSources,
        inferDecisionTopics,
        inferRemainingAnswers,
      ).length > 0)
  ) {
    return [];
  }

  const candidateEntries = inferRemainingAnswers
    ? (answerSources ?? []).filter(
        (entry) => resolveMixedRemainingAnswerSourceRoute(entry) === 'decision',
      )
    : (answerSources ?? []);
  const knownDecisionKeys = new Set(
    decisions
      .map((decision) => decision.decisionKey.trim())
      .filter((decisionKey) => decisionKey.length > 0),
  );
  const summaryCounts = buildKnownDecisionSummaryCountMap(decisions);
  const issues: string[] = [];
  const seenSummaries = new Set<string>();

  for (const entry of candidateEntries) {
    const decisionKey = entry.decisionKey?.trim();
    if (decisionKey && knownDecisionKeys.has(decisionKey)) {
      continue;
    }

    const inferredSummary = inferExactRemainingDecisionTopicSummary(entry);
    if (!inferredSummary) {
      continue;
    }

    const normalizedSummary = normalizeRemainingAnswerSourceLabel(inferredSummary);
    if (!normalizedSummary || seenSummaries.has(normalizedSummary)) {
      continue;
    }

    if ((summaryCounts.get(normalizedSummary) ?? 0) > 1) {
      issues.push(
        `Multiple existing decisions match inferred answerSource summary "${inferredSummary}".`,
      );
      seenSummaries.add(normalizedSummary);
    }
  }

  return issues;
}

function hasDirectAnswerSourceReferenceAuthority(
  answerSourceKey: string | undefined,
  answerSourceGroupKey: string | undefined,
) {
  return (
    (answerSourceKey?.trim().length ?? 0) > 0 ||
    (answerSourceGroupKey?.trim().length ?? 0) > 0
  );
}

function listDirectAnswerSourceReferenceIssues(
  answerSourceKey: string | undefined,
  answerSourceGroupKey: string | undefined,
) {
  const normalizedAnswerSourceKey = answerSourceKey?.trim() ?? '';
  const normalizedAnswerSourceGroupKey = answerSourceGroupKey?.trim() ?? '';
  if (
    normalizedAnswerSourceKey.length > 0 &&
    normalizedAnswerSourceGroupKey.length > 0
  ) {
    return ['Provide only answerSourceKey or answerSourceGroupKey for this explicit answer.'];
  }

  return [] as string[];
}

function buildKnownAnswerSourceReferenceSets(answerSources?: GoalAnswerSourceInput[]) {
  const answerSourceKeys = new Set<string>();
  const answerSourceGroupKeys = new Set<string>();

  for (const answerSource of answerSources ?? []) {
    const answerSourceKey = answerSource.answerSourceKey.trim();
    if (answerSourceKey) {
      answerSourceKeys.add(answerSourceKey);
    }

    const answerSourceGroupKey = answerSource.sourceGroupKey?.trim() ?? '';
    if (answerSourceGroupKey) {
      answerSourceGroupKeys.add(answerSourceGroupKey);
    }
  }

  return { answerSourceKeys, answerSourceGroupKeys };
}

function listExplicitAnswerSourceReferenceExistenceIssues(
  groups: ExplicitAnswerSourceReferenceGroup[],
  answerSources?: GoalAnswerSourceInput[],
) {
  const issues: string[] = [];
  const { answerSourceKeys, answerSourceGroupKeys } =
    buildKnownAnswerSourceReferenceSets(answerSources);

  for (const group of groups) {
    group.entries.forEach((entry, index) => {
      const answer = entry.answer?.trim() ?? '';
      const sourceExcerpt = entry.sourceExcerpt?.trim() ?? '';
      const answerSourceKey = entry.answerSourceKey?.trim() ?? '';
      const answerSourceGroupKey = entry.answerSourceGroupKey?.trim() ?? '';

      if (
        answer ||
        sourceExcerpt ||
        (!answerSourceKey && !answerSourceGroupKey) ||
        (answerSourceKey && answerSourceGroupKey)
      ) {
        return;
      }

      const label =
        group.entries.length === 1 ? group.label : `${group.label} entry ${index + 1}`;
      if (answerSourceKey && !answerSourceKeys.has(answerSourceKey)) {
        issues.push(`${label} references unknown answerSourceKey "${answerSourceKey}".`);
      }
      if (answerSourceGroupKey && !answerSourceGroupKeys.has(answerSourceGroupKey)) {
        issues.push(
          `${label} references unknown answerSourceGroupKey "${answerSourceGroupKey}".`,
        );
      }
    });
  }

  return issues;
}

function listInferOpenDecisionExplicitAnswerIssues(
  answers: Array<{
    decisionKey?: string;
    summary: string;
  }>,
  inferOpenDecisions: boolean,
) {
  if (!inferOpenDecisions) {
    return [] as string[];
  }

  const missingDecisionKeys = answers
    .filter((answer) => !answer.decisionKey?.trim())
    .map((answer) => answer.summary.trim())
    .filter((summary) => summary.length > 0);

  if (missingDecisionKeys.length === 0) {
    return [] as string[];
  }

  return [
    `Infer open decisions requires every explicit answer entry to include decisionKey. Missing decisionKey for: ${missingDecisionKeys.join(', ')}.`,
  ];
}

function listSourceResponseFormatCompatibilityIssues({
  format,
  sourceResponse,
  answerSourcesJson,
  answerSourcesLabel,
  inferOpenDecisions = false,
  inferDecisionTopics = false,
  inferRemainingAnswers = false,
  mixedRemainingAnswerInference = false,
}: {
  format: GoalSourceResponseFormat
  sourceResponse: string
  answerSourcesJson: string
  answerSourcesLabel: string
  inferOpenDecisions?: boolean
  inferDecisionTopics?: boolean
  inferRemainingAnswers?: boolean
  mixedRemainingAnswerInference?: boolean
}) {
  const sourceResponseValue = normalizeOptionalString(sourceResponse)
  const answerSources = parseAnswerSourcesJsonIfValid(answerSourcesJson, answerSourcesLabel)
  const usesSharedInterpretation =
    Boolean(sourceResponseValue) ||
    Boolean(answerSources && answerSources.length > 0) ||
    inferOpenDecisions ||
    inferDecisionTopics ||
    inferRemainingAnswers

  if (!usesSharedInterpretation) {
    return []
  }

  const issues: string[] = []

  if (!hasInterpretationInputForSelectedFormat(format, sourceResponseValue, answerSources)) {
    issues.push(
      `Current selection needs ${describeSourceResponseInputAuthority(format)} before shared interpretation can run.`,
    )
  }

  if (inferOpenDecisions && !formatSupportsInferOpenDecisions(format)) {
    issues.push('Infer open decisions is not supported by the current source-response format.')
  }

  if (inferDecisionTopics && !formatSupportsInferDecisionTopics(format)) {
    issues.push('Infer decision topics is not supported by the current source-response format.')
  }

  if (inferRemainingAnswers && !formatSupportsInferRemainingAnswers(format)) {
    issues.push(
      'Infer remaining planner answers is not supported by the current source-response format.',
    )
  }

  issues.push(
    ...listMixedDecisionTopicAndRemainingAnswerIssues(
      format,
      answerSources,
      inferDecisionTopics,
      mixedRemainingAnswerInference,
    ),
  );

  issues.push(
    ...listAutoInlineTopicMixedAuthorityIssues({
      format,
      sourceResponse,
    }),
  );

  return issues
}

