export function BoardView() {
  const { goalKey } = useParams<{ goalKey: string }>();
  const [isAssistantOpen, setIsAssistantOpen] = useState(false);
  const [lastReconcileSummary, setLastReconcileSummary] = useState<string | null>(null);
  const [selectedTaskRef, setSelectedTaskRef] = useState<string | null>(null);
  const [selectedTaskRunId, setSelectedTaskRunId] = useState<string | null>(null);
  const [selectedTaskRunStepId, setSelectedTaskRunStepId] = useState<string | null>(null);
  const [taskWriteTraceRoleFilter, setTaskWriteTraceRoleFilter] = useState<AgentRole | 'all'>('all');
  const [taskWriteTraceLimit, setTaskWriteTraceLimit] = useState<number | 'all'>('all');
  const [decisionDraft, setDecisionDraft] = useState({
    decisionKey: '',
    summary: '',
    summaryKey: '',
    prompt: '',
    matchHints: '',
    taskRef: '',
  });
  const [decisionResolutionDrafts, setDecisionResolutionDrafts] = useState<
    Record<string, DecisionResolutionDraft>
  >({});
  const [decisionFollowThroughDrafts, setDecisionFollowThroughDrafts] = useState<
    Record<string, DecisionFollowThroughDraft>
  >({});
  const [answerBundleDraft, setAnswerBundleDraft] = useState<AnswerBundleDraft>({
    ...DEFAULT_ANSWER_BUNDLE_DRAFT,
  });
  const [answerBundleFollowThroughDraft, setAnswerBundleFollowThroughDraft] =
    useState<DecisionFollowThroughDraft>({
      ...DEFAULT_DECISION_FOLLOW_THROUGH_DRAFT,
    });
  const [planningDraft, setPlanningDraft] = useState({
    requestKey: '',
    groupKey: '',
    groupTaskKey: '',
    title: '',
    description: '',
    acceptanceCriteria: '',
    decisionRefs: '',
    answersJson: '',
    answerSourcesJson: '',
    sourceResponse: '',
    sourceResponseFormat: 'auto' as GoalSourceResponseFormat,
    inferRemainingAnswers: false,
    requestedUpdates: '',
    blockedByJson: '',
  });
  const [workflowDraft, setWorkflowDraft] = useState({
    workflowKey: '',
    reuseTaskRef: '',
    reuseGroupKey: '',
    sharedDecisionRefs: '',
    sharedAnswersJson: '',
    answerSourcesJson: '',
    sourceResponse: '',
    sourceResponseFormat: 'auto' as GoalSourceResponseFormat,
    inferRemainingAnswers: false,
    childKind: 'planning' as 'planning' | 'planning_batch',
    requestKey: '',
    workflowTaskKey: '',
    groupKey: '',
    blockedByWorkflowKeys: '',
    childBlockedByJson: '',
    title: '',
    description: '',
    acceptanceCriteria: '',
    requestedUpdates: '',
    childDecisionRefs: '',
    childAnswersJson: '',
    batchRequestsJson: '',
    childrenJson: '',
  });
  const [selectedWorkflowKey, setSelectedWorkflowKey] = useState<string | null>(null);
  const [pendingWorkflowSelectionKey, setPendingWorkflowSelectionKey] = useState<string | null>(
    null,
  );
  const [taskCreateDraft, setTaskCreateDraft] = useState<TaskCreateDraft>({
    ...DEFAULT_TASK_CREATE_DRAFT,
  });
  const [taskMoveDraft, setTaskMoveDraft] = useState<TaskMoveDraft>({
    ...DEFAULT_TASK_MOVE_DRAFT,
  });
  const [preferenceEditor, setPreferenceEditor] = useState('');
  const [preferenceEditorDirty, setPreferenceEditorDirty] = useState(false);
  const [preferenceDraft, setPreferenceDraft] = useState({
    preferenceKey: '',
    summary: '',
    rationale: '',
    supersedes: '',
  });
  const [retireDraft, setRetireDraft] = useState({
    preferenceKey: '',
    reason: '',
    supersededBy: '',
  });
  const queryClient = useQueryClient();

  const queueWorkflowSelection = (workflowKey?: string | null) => {
    const nextWorkflowKey = workflowKey?.trim() ?? '';
    if (!nextWorkflowKey) {
      return;
    }

    setPendingWorkflowSelectionKey(nextWorkflowKey);
  };

  const handleSelectWorkflow = (workflowKey: string | null) => {
    setPendingWorkflowSelectionKey(null);
    setSelectedWorkflowKey(workflowKey);
  };

  const { data: board, isLoading, error, refetch } = useQuery<TodoBoard>({
    queryKey: ['board', goalKey],
    queryFn: async () => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      return readGoalBoard(goalKey);
    },
    enabled: Boolean(goalKey),
  });

  const { data: docs } = useQuery<GoalDocsSnapshot>({
    queryKey: ['goal-docs', goalKey],
    queryFn: async () => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      return readGoalDocs(goalKey);
    },
    enabled: Boolean(goalKey),
  });

  const { data: decisions } = useQuery<GoalDecisionSet>({
    queryKey: ['goal-decisions', goalKey],
    queryFn: async () => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      return readGoalDecisions(goalKey);
    },
    enabled: Boolean(goalKey),
  });

  const { data: planningRequests } = useQuery<GoalPlanningRequestSet>({
    queryKey: ['planning-requests', goalKey],
    queryFn: async () => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      return readGoalPlanningRequests(goalKey);
    },
    enabled: Boolean(goalKey),
  });

  const { data: workflows } = useQuery<{ goalKey: string; workflows: GoalPlanningWorkflowState[] }>({
    queryKey: ['planning-workflows', goalKey],
    queryFn: async () => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      return readGoalPlanningWorkflows(goalKey);
    },
    enabled: Boolean(goalKey),
  });

  const currentPlanningMutationAuthoritySnapshot =
    buildExistingPlanningMutationAuthoritySnapshot(board, planningRequests, workflows);

  const { data: selectedWorkflowDetail, isLoading: isSelectedWorkflowLoading, error: selectedWorkflowError } =
    useQuery<GoalPlanningWorkflowState>({
      queryKey: ['planning-workflow-detail', goalKey, selectedWorkflowKey],
      queryFn: async () => {
        if (!goalKey || !selectedWorkflowKey) {
          throw new Error('Missing workflow selection');
        }

        return readGoalPlanningWorkflow(goalKey, selectedWorkflowKey);
      },
      enabled: Boolean(goalKey && selectedWorkflowKey),
    });

  const { data: preferences } = useQuery<PreferenceDocument>({
    queryKey: ['preferences'],
    queryFn: readPreferences,
  });

  const taskRunsQuery = useQuery<{ goalKey: string; runs: GoalRunSummary[] }>({
    queryKey: ['goal-runs', goalKey],
    queryFn: async () => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      return readGoalRuns(goalKey);
    },
    enabled: Boolean(goalKey && selectedTaskRef),
  });

  const taskRunDetailQuery = useQuery<GoalRunDetail>({
    queryKey: ['goal-run-detail', goalKey, selectedTaskRunId],
    queryFn: async () => {
      if (!goalKey || !selectedTaskRunId) {
        throw new Error('Missing task run selection');
      }

      return readGoalRun(goalKey, selectedTaskRunId);
    },
    enabled: Boolean(goalKey && selectedTaskRunId),
  });

  const taskWriteTraceQuery = useQuery<{ goalKey: string; entries: GoalWriteTraceEntry[] }>({
    queryKey: [
      'task-write-traces',
      goalKey,
      selectedTaskRef,
      taskWriteTraceRoleFilter,
      taskWriteTraceLimit,
    ],
    queryFn: async () => {
      if (!goalKey || !selectedTaskRef) {
        throw new Error('Missing task selection');
      }

      return readGoalWriteTraces(goalKey, {
        taskRef: selectedTaskRef,
        role: taskWriteTraceRoleFilter === 'all' ? undefined : taskWriteTraceRoleFilter,
        limit: taskWriteTraceLimit === 'all' ? undefined : taskWriteTraceLimit,
      });
    },
    enabled: Boolean(goalKey && selectedTaskRef),
  });

  const selectedTaskRunWriteTraceQuery = useQuery<{ goalKey: string; entries: GoalWriteTraceEntry[] }>({
    queryKey: [
      'task-run-write-traces',
      goalKey,
      selectedTaskRef,
      selectedTaskRunId,
      selectedTaskRunStepId,
      taskWriteTraceRoleFilter,
      taskWriteTraceLimit,
    ],
    queryFn: async () => {
      if (!goalKey || !selectedTaskRef || !selectedTaskRunId) {
        throw new Error('Missing task run selection');
      }

      return readGoalWriteTraces(goalKey, {
        taskRef: selectedTaskRef,
        runId: selectedTaskRunId,
        stepId: selectedTaskRunStepId ?? undefined,
        role: taskWriteTraceRoleFilter === 'all' ? undefined : taskWriteTraceRoleFilter,
        limit: taskWriteTraceLimit === 'all' ? undefined : taskWriteTraceLimit,
      });
    },
    enabled: Boolean(goalKey && selectedTaskRef && selectedTaskRunId),
  });

  const reconcileMutation = useMutation({
    mutationFn: async () => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      return reconcileGoal(goalKey);
    },
    onSuccess: async (result: ReconcileResult) => {
      setLastReconcileSummary(summarizeReconcileResult(result));
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ['board', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-docs', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflows', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflow-detail', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-runs', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-run-detail', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['task-write-traces', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['task-run-write-traces', goalKey] }),
      ]);
    },
  });

  const createDecisionMutation = useMutation({
    mutationFn: async (input: {
      decisionKey?: string;
      summary: string;
      summaryKey?: string;
      prompt?: string;
      matchHints?: string[];
      taskRef?: string;
    }) => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      return createGoalDecision(goalKey, input);
    },
    onSuccess: async () => {
      setDecisionDraft({
        decisionKey: '',
        summary: '',
        summaryKey: '',
        prompt: '',
        matchHints: '',
        taskRef: '',
      });
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ['goal-decisions', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-docs', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflows', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflow-detail', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['board', goalKey] }),
      ]);
    },
  });

  const resolveDecisionMutation = useMutation({
    mutationFn: async (input: {
      decision: GoalDecision;
      resolutionDraft: DecisionResolutionDraft;
      followThroughDraft?: DecisionFollowThroughDraft;
      existingState: ExistingPlanningMutationAuthoritySnapshot;
    }): Promise<GoalDecisionResolveMutationResult> => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      const followThrough = input.followThroughDraft
        ? materializeDecisionFollowThroughInput(input.followThroughDraft)
        : undefined;

      const result = await resolveGoalDecision(
        goalKey,
        input.decision.decisionKey,
        materializeDecisionResolutionInput(input.decision, input.resolutionDraft, followThrough),
      );

      return result.followThrough
        ? {
            ...result,
            followThrough: enrichDecisionFollowThroughResultWithReuse(
              result.followThrough,
              input.existingState,
            ),
          }
        : {
            ...result,
            followThrough: undefined,
          };
    },
    onSuccess: async (result, variables) => {
      queueWorkflowSelection(extractWorkflowKeyFromDecisionMutationResult(result));
      setDecisionResolutionDrafts((current) => ({
        ...current,
        [variables.decision.decisionKey]: { ...DEFAULT_DECISION_RESOLUTION_DRAFT },
      }));
      setDecisionFollowThroughDrafts((current) => ({
        ...current,
        [variables.decision.decisionKey]: { ...DEFAULT_DECISION_FOLLOW_THROUGH_DRAFT },
      }));
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ['goal-decisions', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-docs', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-requests', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflows', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflow-detail', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['board', goalKey] }),
      ]);
    },
  });

  const answerBundleMutation = useMutation({
    mutationFn: async (input: {
      draft: AnswerBundleDraft;
      followThroughDraft: DecisionFollowThroughDraft;
      existingState: ExistingPlanningMutationAuthoritySnapshot;
    }): Promise<GoalDecisionAnswerResultWithReuse | GoalDecisionAnswerBatchResultWithReuse> => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      const followThrough = materializeDecisionFollowThroughInput(input.followThroughDraft);
      if (input.draft.mode === 'single') {
        const result = await answerGoalDecision(
          goalKey,
          materializeSingleDecisionAnswerInput(input.draft, followThrough),
        );
        return result.followThrough
          ? {
              ...result,
              followThrough: enrichDecisionFollowThroughResultWithReuse(
                result.followThrough,
                input.existingState,
              ),
            }
          : {
              ...result,
              followThrough: undefined,
            };
      }

      const result = await answerGoalDecisions(
        goalKey,
        materializeDecisionAnswerBatchInput(
          input.draft,
          followThrough,
          decisions?.decisions ?? [],
        ),
      );
      return result.followThrough
        ? {
            ...result,
            followThrough: enrichDecisionFollowThroughResultWithReuse(
              result.followThrough,
              input.existingState,
            ),
          }
        : {
            ...result,
            followThrough: undefined,
          };
    },
    onSuccess: async (result) => {
      queueWorkflowSelection(extractWorkflowKeyFromDecisionMutationResult(result));
      setAnswerBundleDraft({ ...DEFAULT_ANSWER_BUNDLE_DRAFT });
      setAnswerBundleFollowThroughDraft({ ...DEFAULT_DECISION_FOLLOW_THROUGH_DRAFT });
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ['goal-decisions', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-docs', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-requests', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflows', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflow-detail', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['board', goalKey] }),
      ]);
    },
  });

  const createPlanningRequestMutation = useMutation({
    mutationFn: async (input: {
      requestKey?: string;
      groupKey?: string;
      groupTaskKey?: string;
      title: string;
      description: string;
      acceptanceCriteria: string[];
      decisionRefs?: string[];
      answers?: InterpretablePlanningAnswerInput[];
      answerSources?: GoalAnswerSourceInput[];
      sourceResponse?: string;
      sourceResponseFormat?: GoalSourceResponseFormat;
      inferRemainingAnswers?: boolean;
      requestedUpdates?: string[];
      blockedBy?: BlockerRef[];
      existingTaskRefs: string[];
    }) => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      const { existingTaskRefs, ...requestInput } = input;
      const result = await createGoalPlanningRequest(goalKey, requestInput);
      return {
        ...result,
        taskCreated: !existingTaskRefs.includes(result.taskRef),
      };
    },
    onSuccess: async () => {
      setPlanningDraft({
        requestKey: '',
        groupKey: '',
        groupTaskKey: '',
        title: '',
        description: '',
        acceptanceCriteria: '',
        decisionRefs: '',
        answersJson: '',
        answerSourcesJson: '',
        sourceResponse: '',
        sourceResponseFormat: 'auto',
        inferRemainingAnswers: false,
        requestedUpdates: '',
        blockedByJson: '',
      });
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ['planning-requests', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-docs', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflows', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflow-detail', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['board', goalKey] }),
      ]);
    },
  });

  const createWorkflowMutation = useMutation({
    mutationFn: async (input: {
      workflow: GoalPlanningWorkflowCreateInput;
      existingState: ExistingPlanningMutationAuthoritySnapshot;
    }): Promise<GoalPlanningWorkflowCreateResultWithReuse> => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      const result = await createGoalPlanningWorkflow(goalKey, input.workflow);
      return enrichWorkflowCreateResultWithReuse(result, input.existingState);
    },
    onSuccess: async (result) => {
      const nextWorkflowKey = result.workflowKey ?? null;
      setWorkflowDraft({
        workflowKey: '',
        reuseTaskRef: '',
        reuseGroupKey: '',
        sharedDecisionRefs: '',
        sharedAnswersJson: '',
        answerSourcesJson: '',
        sourceResponse: '',
        sourceResponseFormat: 'auto',
        inferRemainingAnswers: false,
        childKind: 'planning',
        requestKey: '',
        workflowTaskKey: '',
        groupKey: '',
        blockedByWorkflowKeys: '',
        childBlockedByJson: '',
        title: '',
        description: '',
        acceptanceCriteria: '',
        requestedUpdates: '',
        childDecisionRefs: '',
        childAnswersJson: '',
        batchRequestsJson: '',
        childrenJson: '',
      });
      queueWorkflowSelection(nextWorkflowKey);
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ['planning-requests', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-docs', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflows', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflow-detail', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['board', goalKey] }),
      ]);
    },
  });

  const createTaskMutation = useMutation({
    mutationFn: async (input: TaskCreateDraft) => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      return createGoalTask(goalKey, {
        ref: input.ref.trim(),
        kind: input.kind,
        title: input.title.trim(),
        description: input.description.trim(),
        acceptanceCriteria: parseListInput(input.acceptanceCriteria),
        blockedBy: input.blockedByJson.trim()
          ? parseBlockerRefsJson(input.blockedByJson, 'Task blockers')
          : undefined,
      });
    },
    onSuccess: async (result, variables) => {
      setTaskCreateDraft({ ...DEFAULT_TASK_CREATE_DRAFT });
      const createdTask = result.items.find((item) => item.ref === variables.ref.trim());
      setTaskMoveDraft({
        taskRef: createdTask?.ref ?? variables.ref.trim(),
        status: createdTask?.status ?? 'planned',
        reason: 'manual transition',
      });
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ['board', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-docs', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflows', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflow-detail', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-runs', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-run-detail', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['task-write-traces', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['task-run-write-traces', goalKey] }),
      ]);
    },
  });

  const moveTaskMutation = useMutation({
    mutationFn: async (input: TaskMoveDraft) => {
      if (!goalKey) {
        throw new Error('Missing goal key');
      }

      return moveGoalTask(goalKey, input.taskRef, {
        status: input.status,
        reason: input.reason.trim() || 'manual transition',
      });
    },
    onSuccess: async (result, variables) => {
      const movedTask = result.items.find((item) => item.ref === variables.taskRef);
      setTaskMoveDraft((current) => ({
        taskRef: movedTask?.ref ?? current.taskRef,
        status: movedTask?.status ?? current.status,
        reason: 'manual transition',
      }));
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ['board', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-docs', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflows', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['planning-workflow-detail', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-runs', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['goal-run-detail', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['task-write-traces', goalKey] }),
        queryClient.invalidateQueries({ queryKey: ['task-run-write-traces', goalKey] }),
      ]);
    },
  });

  const savePreferencesMutation = useMutation({
    mutationFn: async (content: string) => updatePreferences(content),
    onSuccess: async (document) => {
      setPreferenceEditor(document.content);
      setPreferenceEditorDirty(false);
      await queryClient.invalidateQueries({ queryKey: ['preferences'] });
    },
  });

  const recordPreferenceMutation = useMutation({
    mutationFn: async (input: {
      preferenceKey?: string;
      summary: string;
      rationale?: string;
      supersedes?: string[];
    }) => recordPreference(input),
    onSuccess: async () => {
      setPreferenceDraft({
        preferenceKey: '',
        summary: '',
        rationale: '',
        supersedes: '',
      });
      await queryClient.invalidateQueries({ queryKey: ['preferences'] });
    },
  });

  const retirePreferenceMutation = useMutation({
    mutationFn: async (input: {
      preferenceKey: string;
      reason: string;
      supersededBy?: string;
    }) => retirePreference(input),
    onSuccess: async () => {
      setRetireDraft((current) => ({
        preferenceKey: current.preferenceKey,
        reason: '',
        supersededBy: '',
      }));
      await queryClient.invalidateQueries({ queryKey: ['preferences'] });
    },
  });

  useEffect(() => {
    if (!preferenceEditorDirty && preferences?.content !== undefined) {
      setPreferenceEditor(preferences.content);
    }
  }, [preferenceEditorDirty, preferences?.content]);

  useEffect(() => {
    const activeEntries = preferences?.entries.filter((entry) => entry.status === 'active') ?? [];
    const activeKeys = activeEntries.map((entry) => entry.preferenceKey);
    setRetireDraft((current) => {
      if (current.preferenceKey && activeKeys.includes(current.preferenceKey)) {
        return current;
      }
      return {
        ...current,
        preferenceKey: activeKeys[0] ?? '',
      };
    });
  }, [preferences?.entries]);

  useEffect(() => {
    const workflowItems = workflows?.workflows ?? [];
    if (workflowItems.length === 0) {
      if (selectedWorkflowKey !== null) {
        setSelectedWorkflowKey(null);
      }
      return;
    }

    if (pendingWorkflowSelectionKey) {
      if (workflowItems.some((workflow) => workflow.workflowKey === pendingWorkflowSelectionKey)) {
        if (selectedWorkflowKey !== pendingWorkflowSelectionKey) {
          setSelectedWorkflowKey(pendingWorkflowSelectionKey);
        }
        setPendingWorkflowSelectionKey(null);
      }
      return;
    }

    if (!selectedWorkflowKey) {
      setSelectedWorkflowKey(workflowItems[0]?.workflowKey ?? null);
      return;
    }

    if (!workflowItems.some((workflow) => workflow.workflowKey === selectedWorkflowKey)) {
      setSelectedWorkflowKey(workflowItems[0]?.workflowKey ?? null);
    }
  }, [pendingWorkflowSelectionKey, selectedWorkflowKey, workflows?.workflows]);

  useEffect(() => {
    const boardItems = board?.items ?? [];
    if (boardItems.length === 0) {
      if (selectedTaskRef !== null) {
        setSelectedTaskRef(null);
      }
      if (taskMoveDraft.taskRef || taskMoveDraft.status !== 'planned') {
        setTaskMoveDraft({ ...DEFAULT_TASK_MOVE_DRAFT });
      }
      return;
    }

    if (!selectedTaskRef) {
      setSelectedTaskRef(boardItems[0]?.ref ?? null);
    } else if (!boardItems.some((item) => item.ref === selectedTaskRef)) {
      setSelectedTaskRef(boardItems[0]?.ref ?? null);
    }

    if (!taskMoveDraft.taskRef) {
      setTaskMoveDraft({
        taskRef: boardItems[0].ref,
        status: boardItems[0].status,
        reason: 'manual transition',
      });
      return;
    }

    if (!boardItems.some((item) => item.ref === taskMoveDraft.taskRef)) {
      setTaskMoveDraft({
        taskRef: boardItems[0].ref,
        status: boardItems[0].status,
        reason: 'manual transition',
      });
    }
  }, [board?.items, selectedTaskRef, taskMoveDraft.taskRef, taskMoveDraft.status]);

  useEffect(() => {
    if (!selectedTaskRef) {
      if (selectedTaskRunId !== null) {
        setSelectedTaskRunId(null);
      }
      return;
    }

    const runsForTask = [...(taskRunsQuery.data?.runs ?? [])]
      .filter((run) => run.taskRef === selectedTaskRef)
      .sort((left, right) => Date.parse(right.startedAt) - Date.parse(left.startedAt));

    if (runsForTask.length === 0) {
      if (selectedTaskRunId !== null) {
        setSelectedTaskRunId(null);
      }
      return;
    }

    if (!selectedTaskRunId) {
      setSelectedTaskRunId(runsForTask[0]?.runId ?? null);
      return;
    }

    if (!runsForTask.some((run) => run.runId === selectedTaskRunId)) {
      setSelectedTaskRunId(runsForTask[0]?.runId ?? null);
    }
  }, [selectedTaskRef, selectedTaskRunId, taskRunsQuery.data?.runs]);

  useEffect(() => {
    if (selectedTaskRunStepId !== null) {
      setSelectedTaskRunStepId(null);
    }
  }, [selectedTaskRunId]);

  useEffect(() => {
    if (!goalKey) {
      return undefined;
    }

    const evtSource = openGoalEventStream();
    evtSource.onmessage = (event) => {
      const data = JSON.parse(event.data) as GoalEvent;
      if (data.type === 'board_changed' && data.goalKey === goalKey) {
        refetch();
        void queryClient.invalidateQueries({ queryKey: ['goal-runs', goalKey] });
        void queryClient.invalidateQueries({ queryKey: ['goal-run-detail', goalKey] });
        void queryClient.invalidateQueries({ queryKey: ['goal-docs', goalKey] });
        void queryClient.invalidateQueries({ queryKey: ['planning-workflows', goalKey] });
        void queryClient.invalidateQueries({ queryKey: ['planning-workflow-detail', goalKey] });
        void queryClient.invalidateQueries({ queryKey: ['task-write-traces', goalKey] });
        void queryClient.invalidateQueries({ queryKey: ['task-run-write-traces', goalKey] });
      }
      if (data.type === 'decisions_changed' && data.goalKey === goalKey) {
        void Promise.all([
          queryClient.invalidateQueries({ queryKey: ['goal-decisions', goalKey] }),
          queryClient.invalidateQueries({ queryKey: ['goal-docs', goalKey] }),
        ]);
      }
      if (data.type === 'planning_requests_changed' && data.goalKey === goalKey) {
        void Promise.all([
          queryClient.invalidateQueries({ queryKey: ['planning-requests', goalKey] }),
          queryClient.invalidateQueries({ queryKey: ['planning-workflows', goalKey] }),
          queryClient.invalidateQueries({ queryKey: ['planning-workflow-detail', goalKey] }),
          queryClient.invalidateQueries({ queryKey: ['goal-docs', goalKey] }),
        ]);
      }
      if (data.type === 'preferences_changed') {
        void queryClient.invalidateQueries({ queryKey: ['preferences'] });
      }
    };
    return () => evtSource.close();
  }, [goalKey, queryClient, refetch]);

  if (isLoading) {
    return (
      <div className="flex-1 flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-purple-500" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center text-red-400 gap-4">
        <AlertCircle className="w-12 h-12" />
        <p className="text-lg">Failed to load board: {(error as Error).message}</p>
      </div>
    );
  }

  const itemsByStatus: Record<TaskStatus, TodoTaskItem[]> = {
    planned: [],
    in_progress: [],
    in_review: [],
    merging: [],
    done: [],
  };

  for (const item of board?.items ?? []) {
    itemsByStatus[item.status].push(item);
  }

  const createdTaskResult =
    createTaskMutation.data && createTaskMutation.variables
      ? createTaskMutation.data.items.find(
          (item) => item.ref === createTaskMutation.variables.ref.trim(),
        ) ?? null
      : null;

  const movedTaskResult =
    moveTaskMutation.data && moveTaskMutation.variables
      ? moveTaskMutation.data.items.find(
          (item) => item.ref === moveTaskMutation.variables.taskRef,
        ) ?? null
      : null;
  const selectedTask =
    selectedTaskRef
      ? (board?.items ?? []).find((item) => item.ref === selectedTaskRef) ?? null
      : null;
  const selectedTaskDecisions = selectedTask
    ? (decisions?.decisions ?? []).filter((decision) => decision.taskRef === selectedTask.ref)
    : [];
  const selectedTaskPlanningRequests = selectedTask
    ? (planningRequests?.requests ?? []).filter((request) => request.taskRef === selectedTask.ref)
    : [];
  const selectedTaskWorkflows = selectedTask
    ? (workflows?.workflows ?? []).filter(
        (workflow) =>
          workflow.taskRefs.includes(selectedTask.ref) ||
          workflow.blockerTaskRefs.includes(selectedTask.ref),
      )
    : [];
  const selectedTaskDependents = selectedTask
    ? (board?.items ?? []).filter(
        (item) =>
          item.ref !== selectedTask.ref &&
          item.blockedBy.some(
            (blocker) => blocker.kind === 'task' && blocker.ref === selectedTask.ref,
          ),
      )
    : [];
  const selectedTaskRuns = selectedTask
    ? [...((taskRunsQuery.data?.runs ?? []).filter((run) => run.taskRef === selectedTask.ref))].sort(
        (left, right) => Date.parse(right.startedAt) - Date.parse(left.startedAt),
      )
    : [];
  const selectedTaskRunDetail =
    selectedTaskRunId && taskRunDetailQuery.data?.runId === selectedTaskRunId
      ? taskRunDetailQuery.data
      : null;
  const reusableAnswerSourceSuggestions = buildReusableAnswerSourceSuggestions(
    decisions?.decisions ?? [],
    planningRequests?.requests ?? [],
  );
  const reusablePlanningAnswerSuggestions = buildReusablePlanningAnswerSuggestions(
    decisions?.decisions ?? [],
    planningRequests?.requests ?? [],
  );
  const reusableDecisionAnswerSuggestions = buildReusableDecisionAnswerSuggestions(
    decisions?.decisions ?? [],
  );
  const reusableDecisionRefSuggestions = buildReusableDecisionRefSuggestions(
    decisions?.decisions ?? [],
  );
  const reusablePlanningRequestSuggestions = buildReusablePlanningRequestSuggestions(
    planningRequests?.requests ?? [],
    board?.items ?? [],
  );
  const reusableTaskRefSuggestions = buildReusableTaskRefSuggestions(board?.items ?? []);
  const reusablePlanningRequestKeySuggestions = buildReusablePlanningRequestKeySuggestions(
    planningRequests?.requests ?? [],
    board?.items ?? [],
  );
  const reusablePlanningGroupKeySuggestions = buildReusablePlanningGroupKeySuggestions(
    planningRequests?.requests ?? [],
    board?.items ?? [],
  );
  const reusablePlanningGroupTaskKeySuggestions =
    buildReusablePlanningGroupTaskKeySuggestions(
      planningRequests?.requests ?? [],
      board?.items ?? [],
    );
  const reusableBatchRequestSuggestions = buildReusableBatchRequestSuggestions(
    planningRequests?.requests ?? [],
    board?.items ?? [],
  );
  const reusableBatchRequestGroupSuggestions =
    buildReusableBatchRequestGroupSuggestions(
      planningRequests?.requests ?? [],
      board?.items ?? [],
    );
  const reusableBlockerSuggestions = buildReusableBlockerSuggestions(
    board?.items ?? [],
    decisions?.decisions ?? [],
  );
  const reusableWorkflowKeySuggestions = buildReusableWorkflowKeySuggestions(
    workflows?.workflows ?? [],
  );
  const reusableWorkflowContextSuggestions = buildReusableWorkflowContextSuggestions(
    workflows?.workflows ?? [],
  );
  const reusableWorkflowGraphSuggestions = buildReusableWorkflowGraphSuggestions(
    workflows?.workflows ?? [],
    board?.items ?? [],
  );
  const reusableWorkflowChildSuggestions = buildReusableWorkflowChildSuggestions(
    workflows?.workflows ?? [],
    board?.items ?? [],
  );
  const reusableDecisionWorkflowChildSuggestions =
    buildReusableDecisionWorkflowChildSuggestions(
      workflows?.workflows ?? [],
      board?.items ?? [],
    );
  const reusableWorkflowTaskRefSuggestions = buildReusableWorkflowTaskRefSuggestions(
    planningRequests?.requests ?? [],
    board?.items ?? [],
    workflows?.workflows ?? [],
  );
  const reusableWorkflowGroupKeySuggestions = buildReusableWorkflowGroupKeySuggestions(
    planningRequests?.requests ?? [],
    board?.items ?? [],
    workflows?.workflows ?? [],
  );
  const reusablePreferenceKeySuggestions = buildReusablePreferenceKeySuggestions(
    preferences?.entries ?? [],
  );

  return (
    <div className="flex-1 flex flex-col h-full overflow-hidden bg-[#1A1A1A] relative">
      <header className="px-6 py-4 border-b border-[#333] shrink-0 flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-white">{board?.goal.title}</h2>
          <p className="text-sm text-gray-400 mt-1">Goal Key: <code className="bg-[#2A2A2A] px-1.5 py-0.5 rounded text-purple-400">{board?.goal.goalKey}</code></p>
        </div>
        <div className="flex items-center gap-3">
          <button
            onClick={() => reconcileMutation.mutate()}
            disabled={reconcileMutation.isPending}
            className="flex items-center gap-2 px-4 py-2 bg-[#252525] hover:bg-[#2f2f2f] text-gray-200 rounded-lg transition-colors font-medium disabled:opacity-60"
          >
            {reconcileMutation.isPending ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              <RefreshCw className="w-4 h-4" />
            )}
            Reconcile Once
          </button>
          <button
            onClick={() => setIsAssistantOpen(true)}
            className="flex items-center gap-2 px-4 py-2 bg-purple-600 hover:bg-purple-500 text-white rounded-lg transition-colors font-medium shadow-lg shadow-purple-900/20"
          >
            <MessageSquare className="w-4 h-4" />
            Goal Assistant
          </button>
        </div>
      </header>

      <div className="flex-1 overflow-x-auto overflow-y-hidden p-6">
        <div className="flex gap-6 h-full min-w-max pb-4">
          {STATUS_COLUMNS.map((col) => (
            <div key={col.id} className="w-80 flex flex-col shrink-0">
              <div className="flex items-center justify-between mb-4">
                <h3 className={cn("text-sm font-semibold px-3 py-1 border rounded-full uppercase tracking-wider", col.color)}>
                  {col.label}
                </h3>
                <span className="text-xs text-gray-500 font-mono bg-[#2A2A2A] px-2 py-0.5 rounded-full">
                  {itemsByStatus[col.id]?.length || 0}
                </span>
              </div>

              <div className="flex-1 flex flex-col gap-3 overflow-y-auto pr-2 pb-2">
                {itemsByStatus[col.id]?.map((task) => (
                  <TaskCard
                    key={task.ref}
                    task={task}
                    selected={task.ref === selectedTaskRef}
                    onClick={() => setSelectedTaskRef(task.ref)}
                  />
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="border-t border-[#333] bg-[#151515] px-6 py-5 space-y-4 shrink-0">
        {lastReconcileSummary && (
          <div className="rounded-xl border border-emerald-500/15 bg-emerald-500/10 px-4 py-3 text-sm text-emerald-200">
            {lastReconcileSummary}
          </div>
        )}

        <div className="grid gap-4 lg:grid-cols-2">
          <DocCard
            title="goal.md"
            subtitle={docs?.goal.path ?? 'Goal snapshot'}
            status={docs?.goal.status}
            content={docs?.goal.content}
          />
          <DocCard
            title="design.md"
            subtitle={docs?.design.path ?? 'Design snapshot'}
            status={docs?.design.status}
            content={docs?.design.content}
          />
        </div>

        <div className="grid gap-4 xl:grid-cols-2">
          <DecisionPanel
            decisions={decisions?.decisions ?? []}
            decisionDraft={decisionDraft}
            onDecisionDraftChange={(field, value) =>
              setDecisionDraft((current) => ({ ...current, [field]: value }))
            }
            onCreateDecision={() =>
              createDecisionMutation.mutate({
                decisionKey: decisionDraft.decisionKey || undefined,
                summary: decisionDraft.summary.trim(),
                summaryKey: decisionDraft.summaryKey.trim() || undefined,
                prompt: decisionDraft.prompt.trim() || undefined,
                matchHints: parseListInput(decisionDraft.matchHints),
                taskRef: decisionDraft.taskRef.trim() || undefined,
              })
            }
            createPending={createDecisionMutation.isPending}
            createError={createDecisionMutation.error}
            decisionResolutionDrafts={decisionResolutionDrafts}
            decisionFollowThroughDrafts={decisionFollowThroughDrafts}
            onDecisionResolutionDraftChange={(decisionKey, field, value) =>
              setDecisionResolutionDrafts((current) => ({
                ...current,
                [decisionKey]: {
                  ...(current[decisionKey] ?? DEFAULT_DECISION_RESOLUTION_DRAFT),
                  [field]: value,
                },
              }))
            }
            onDecisionFollowThroughChange={(decisionKey, field, value) =>
              setDecisionFollowThroughDrafts((current) => ({
                ...current,
                [decisionKey]: {
                  ...(current[decisionKey] ?? DEFAULT_DECISION_FOLLOW_THROUGH_DRAFT),
                  [field]: value,
                },
              }))
            }
            onResolveDecision={(decision) =>
              resolveDecisionMutation.mutate({
                decision,
                resolutionDraft:
                  decisionResolutionDrafts[decision.decisionKey] ??
                  DEFAULT_DECISION_RESOLUTION_DRAFT,
                followThroughDraft:
                  decisionFollowThroughDrafts[decision.decisionKey] ??
                  DEFAULT_DECISION_FOLLOW_THROUGH_DRAFT,
                existingState: currentPlanningMutationAuthoritySnapshot,
              })
            }
            resolvePendingDecisionKey={
              resolveDecisionMutation.isPending
                ? resolveDecisionMutation.variables?.decision.decisionKey ?? null
                : null
            }
            resolveError={resolveDecisionMutation.error}
            createResult={createDecisionMutation.data}
            resolveResultDecisionKey={resolveDecisionMutation.variables?.decision.decisionKey ?? null}
            resolveResult={resolveDecisionMutation.data}
            reusableAnswerSourceSuggestions={reusableAnswerSourceSuggestions}
            reusablePlanningAnswerSuggestions={reusablePlanningAnswerSuggestions}
            reusablePlanningRequestSuggestions={reusablePlanningRequestSuggestions}
            reusableTaskRefSuggestions={reusableTaskRefSuggestions}
            reusableBlockerSuggestions={reusableBlockerSuggestions}
            reusablePlanningRequestKeySuggestions={reusablePlanningRequestKeySuggestions}
            reusablePlanningGroupKeySuggestions={reusablePlanningGroupKeySuggestions}
            reusablePlanningGroupTaskKeySuggestions={reusablePlanningGroupTaskKeySuggestions}
            reusableBatchRequestSuggestions={reusableBatchRequestSuggestions}
            reusableBatchRequestGroupSuggestions={
              reusableBatchRequestGroupSuggestions
            }
            reusableWorkflowKeySuggestions={reusableWorkflowKeySuggestions}
            reusableWorkflowContextSuggestions={reusableWorkflowContextSuggestions}
            reusableWorkflowGraphSuggestions={reusableWorkflowGraphSuggestions}
            reusableDecisionWorkflowChildSuggestions={
              reusableDecisionWorkflowChildSuggestions
            }
            reusableWorkflowTaskRefSuggestions={reusableWorkflowTaskRefSuggestions}
            reusableWorkflowGroupKeySuggestions={reusableWorkflowGroupKeySuggestions}
          />
          <PlanningRequestPanel
            requests={planningRequests?.requests ?? []}
            tasks={board?.items ?? []}
            planningDraft={planningDraft}
            onPlanningDraftChange={(field, value) =>
              setPlanningDraft((current) => ({ ...current, [field]: value }))
            }
            onPlanningDraftPrefill={(patch) =>
              setPlanningDraft((current) => ({ ...current, ...patch }))
            }
            onCreatePlanningRequest={() =>
              createPlanningRequestMutation.mutate({
                ...materializePlanningRequestInput(planningDraft),
                existingTaskRefs: (board?.items ?? []).map((task) => task.ref),
              })
            }
            createPending={createPlanningRequestMutation.isPending}
            createError={createPlanningRequestMutation.error}
            createResult={createPlanningRequestMutation.data}
            reusableAnswerSourceSuggestions={reusableAnswerSourceSuggestions}
            reusablePlanningAnswerSuggestions={reusablePlanningAnswerSuggestions}
            reusablePlanningRequestSuggestions={reusablePlanningRequestSuggestions}
            reusableDecisionRefSuggestions={reusableDecisionRefSuggestions}
            reusableBlockerSuggestions={reusableBlockerSuggestions}
            reusablePlanningRequestKeySuggestions={reusablePlanningRequestKeySuggestions}
            reusablePlanningGroupKeySuggestions={reusablePlanningGroupKeySuggestions}
            reusablePlanningGroupTaskKeySuggestions={reusablePlanningGroupTaskKeySuggestions}
          />
        </div>

        <div className="grid gap-4">
          <AnswerBundlePanel
            draft={answerBundleDraft}
            decisions={decisions?.decisions ?? []}
            onDraftChange={(patch) =>
              setAnswerBundleDraft((current) => ({
                ...current,
                ...patch,
              }))
            }
            followThroughDraft={answerBundleFollowThroughDraft}
            onFollowThroughChange={(field, value) =>
              setAnswerBundleFollowThroughDraft((current) => ({
                ...current,
                [field]: value,
              }))
            }
            onSubmit={() =>
              answerBundleMutation.mutate({
                draft: answerBundleDraft,
                followThroughDraft: answerBundleFollowThroughDraft,
                existingState: currentPlanningMutationAuthoritySnapshot,
              })
            }
            submitPending={answerBundleMutation.isPending}
            submitError={answerBundleMutation.error}
            submitResult={answerBundleMutation.data}
            reusableAnswerSourceSuggestions={reusableAnswerSourceSuggestions}
            reusablePlanningAnswerSuggestions={reusablePlanningAnswerSuggestions}
            reusablePlanningRequestSuggestions={reusablePlanningRequestSuggestions}
            reusableDecisionAnswerSuggestions={reusableDecisionAnswerSuggestions}
            reusableTaskRefSuggestions={reusableTaskRefSuggestions}
            reusableBlockerSuggestions={reusableBlockerSuggestions}
            reusablePlanningRequestKeySuggestions={reusablePlanningRequestKeySuggestions}
            reusablePlanningGroupKeySuggestions={reusablePlanningGroupKeySuggestions}
            reusablePlanningGroupTaskKeySuggestions={reusablePlanningGroupTaskKeySuggestions}
            reusableBatchRequestSuggestions={reusableBatchRequestSuggestions}
            reusableBatchRequestGroupSuggestions={
              reusableBatchRequestGroupSuggestions
            }
            reusableWorkflowKeySuggestions={reusableWorkflowKeySuggestions}
            reusableWorkflowContextSuggestions={reusableWorkflowContextSuggestions}
            reusableWorkflowGraphSuggestions={reusableWorkflowGraphSuggestions}
            reusableDecisionWorkflowChildSuggestions={
              reusableDecisionWorkflowChildSuggestions
            }
            reusableWorkflowTaskRefSuggestions={reusableWorkflowTaskRefSuggestions}
            reusableWorkflowGroupKeySuggestions={reusableWorkflowGroupKeySuggestions}
          />
        </div>

        <div className="grid gap-4 xl:grid-cols-2">
          <WorkflowPanel
            workflows={workflows?.workflows ?? []}
            tasks={board?.items ?? []}
            selectedWorkflowKey={selectedWorkflowKey}
            selectedWorkflow={selectedWorkflowDetail ?? null}
            workflowDetailLoading={isSelectedWorkflowLoading}
            workflowDetailError={selectedWorkflowError as Error | null}
            workflowDraft={workflowDraft}
            onWorkflowDraftChange={(field, value) =>
              setWorkflowDraft((current) => ({ ...current, [field]: value }))
            }
            onCreateWorkflow={() =>
              createWorkflowMutation.mutate({
                workflow: materializeWorkflowMutationInput(workflowDraft),
                existingState: currentPlanningMutationAuthoritySnapshot,
              })
            }
            createPending={createWorkflowMutation.isPending}
            createError={createWorkflowMutation.error}
            createResult={createWorkflowMutation.data}
            reusableAnswerSourceSuggestions={reusableAnswerSourceSuggestions}
            reusablePlanningAnswerSuggestions={reusablePlanningAnswerSuggestions}
            reusablePlanningRequestSuggestions={reusablePlanningRequestSuggestions}
            reusableDecisionRefSuggestions={reusableDecisionRefSuggestions}
            reusableBlockerSuggestions={reusableBlockerSuggestions}
            reusablePlanningRequestKeySuggestions={reusablePlanningRequestKeySuggestions}
            reusablePlanningGroupTaskKeySuggestions={
              reusablePlanningGroupTaskKeySuggestions
            }
            reusableBatchRequestSuggestions={reusableBatchRequestSuggestions}
            reusableBatchRequestGroupSuggestions={
              reusableBatchRequestGroupSuggestions
            }
            reusableWorkflowKeySuggestions={reusableWorkflowKeySuggestions}
            reusableWorkflowContextSuggestions={reusableWorkflowContextSuggestions}
            reusableWorkflowGraphSuggestions={reusableWorkflowGraphSuggestions}
            reusableWorkflowChildSuggestions={reusableWorkflowChildSuggestions}
            reusableWorkflowTaskRefSuggestions={reusableWorkflowTaskRefSuggestions}
            reusableWorkflowGroupKeySuggestions={reusableWorkflowGroupKeySuggestions}
            onPrefillWorkflowKey={(workflowKey) =>
              setWorkflowDraft((current) => ({ ...current, workflowKey }))
            }
            onSelectWorkflow={handleSelectWorkflow}
            onPrefillReuseTaskRef={(taskRef, workflowKey) =>
              setWorkflowDraft((current) => ({
                ...current,
                workflowKey,
                reuseTaskRef: taskRef,
                reuseGroupKey: '',
              }))
            }
            onPrefillReuseGroupKey={(groupKey, workflowKey) =>
              setWorkflowDraft((current) => ({
                ...current,
                workflowKey,
                reuseTaskRef: '',
                reuseGroupKey: groupKey,
                childKind: 'planning_batch',
                groupKey,
              }))
            }
          />
          <PreferencePanel
            document={preferences}
            reusablePreferenceKeySuggestions={reusablePreferenceKeySuggestions}
            preferenceEditor={preferenceEditor}
            preferenceEditorDirty={preferenceEditorDirty}
            onPreferenceEditorChange={(value) => {
              setPreferenceEditor(value);
              setPreferenceEditorDirty(true);
            }}
            onSavePreferences={() => savePreferencesMutation.mutate(preferenceEditor)}
            savePending={savePreferencesMutation.isPending}
            saveError={savePreferencesMutation.error}
            preferenceDraft={preferenceDraft}
            onPreferenceDraftChange={(field, value) =>
              setPreferenceDraft((current) => ({ ...current, [field]: value }))
            }
            onRecordPreference={() =>
              recordPreferenceMutation.mutate({
                preferenceKey: preferenceDraft.preferenceKey.trim() || undefined,
                summary: preferenceDraft.summary.trim(),
                rationale: preferenceDraft.rationale.trim() || undefined,
                supersedes: parseListInput(preferenceDraft.supersedes),
              })
            }
            recordPending={recordPreferenceMutation.isPending}
            recordError={recordPreferenceMutation.error}
            saveResult={savePreferencesMutation.data}
            recordResult={recordPreferenceMutation.data}
            recordResultPreferenceKey={
              recordPreferenceMutation.variables?.preferenceKey?.trim() || null
            }
            recordResultSummary={recordPreferenceMutation.variables?.summary?.trim() || null}
            retireDraft={retireDraft}
            onRetireDraftChange={(field, value) =>
              setRetireDraft((current) => ({ ...current, [field]: value }))
            }
            onRetirePreference={() =>
              retirePreferenceMutation.mutate({
                preferenceKey: retireDraft.preferenceKey,
                reason: retireDraft.reason.trim(),
                supersededBy: retireDraft.supersededBy.trim() || undefined,
              })
            }
            retirePending={retirePreferenceMutation.isPending}
            retireError={retirePreferenceMutation.error}
            retireResult={retirePreferenceMutation.data}
            retireResultPreferenceKey={retirePreferenceMutation.variables?.preferenceKey ?? null}
          />
        </div>

        <div className="grid gap-4">
          <TaskActionsPanel
            tasks={board?.items ?? []}
            createDraft={taskCreateDraft}
            onCreateDraftChange={(field, value) =>
              setTaskCreateDraft((current) => ({ ...current, [field]: value }))
            }
            onCreateTask={() => createTaskMutation.mutate(taskCreateDraft)}
            createPending={createTaskMutation.isPending}
            createError={createTaskMutation.error}
            createResult={createdTaskResult}
            moveDraft={taskMoveDraft}
            onMoveDraftChange={(field, value) =>
              setTaskMoveDraft((current) => ({ ...current, [field]: value }))
            }
            onSelectMoveTask={(taskRef) => {
              const selectedTask = (board?.items ?? []).find((item) => item.ref === taskRef);
              setTaskMoveDraft((current) => ({
                ...current,
                taskRef,
                status: selectedTask?.status ?? current.status,
              }));
            }}
            onMoveTask={() => moveTaskMutation.mutate(taskMoveDraft)}
            movePending={moveTaskMutation.isPending}
            moveError={moveTaskMutation.error}
            moveResult={movedTaskResult}
            reusableBlockerSuggestions={reusableBlockerSuggestions}
          />
          <TaskAuthorityPanel
            task={selectedTask}
            linkedDecisions={selectedTaskDecisions}
            linkedPlanningRequests={selectedTaskPlanningRequests}
            linkedWorkflows={selectedTaskWorkflows}
            dependentTasks={selectedTaskDependents}
            writeTraceRoleFilter={taskWriteTraceRoleFilter}
            onWriteTraceRoleFilterChange={setTaskWriteTraceRoleFilter}
            writeTraceLimit={taskWriteTraceLimit}
            onWriteTraceLimitChange={setTaskWriteTraceLimit}
            taskRuns={selectedTaskRuns}
            selectedTaskRunId={selectedTaskRunId}
            onSelectTaskRun={(runId) => setSelectedTaskRunId(runId)}
            selectedTaskRunStepId={selectedTaskRunStepId}
            onSelectTaskRunStep={(stepId) => setSelectedTaskRunStepId(stepId)}
            taskRunsLoading={taskRunsQuery.isLoading}
            taskRunsError={taskRunsQuery.error as Error | null}
            taskRunDetail={selectedTaskRunDetail}
            taskRunDetailLoading={taskRunDetailQuery.isLoading}
            taskRunDetailError={taskRunDetailQuery.error as Error | null}
            selectedTaskRunWriteTraces={selectedTaskRunWriteTraceQuery.data?.entries ?? []}
            selectedTaskRunWriteTraceLoading={selectedTaskRunWriteTraceQuery.isLoading}
            selectedTaskRunWriteTraceError={
              selectedTaskRunWriteTraceQuery.error as Error | null
            }
            writeTraces={taskWriteTraceQuery.data?.entries ?? []}
            writeTraceLoading={taskWriteTraceQuery.isLoading}
            writeTraceError={taskWriteTraceQuery.error as Error | null}
          />
        </div>
      </div>

      <AssistantPanel
        goalKey={board?.goal.goalKey || ''}
        isOpen={isAssistantOpen}
        onClose={() => setIsAssistantOpen(false)}
      />
    </div>
  );
}

function TaskCard({
  task,
  selected,
  onClick,
}: {
  task: TodoTaskItem;
  selected: boolean;
  onClick: () => void;
}) {
  const isBlocked = task.blockedBy.length > 0;

  return (
    <button
      type="button"
      onClick={onClick}
      className={cn(
        "w-full p-4 rounded-xl border transition-all cursor-pointer group shadow-sm text-left",
        isBlocked
          ? "bg-[#2a1616] border-red-900/50 hover:border-red-500/50"
          : "bg-[#222] border-[#333] hover:border-purple-500/50 hover:bg-[#252525]",
        selected && "ring-1 ring-purple-500/40 border-purple-500/50 bg-[#252525]",
      )}
    >
      <div className="flex justify-between items-start mb-2 gap-2">
        <span className="text-xs font-mono text-gray-500 bg-[#1A1A1A] px-1.5 py-0.5 rounded">
          {task.ref}
        </span>
        <span className="text-[10px] font-bold text-gray-400 bg-[#1A1A1A] px-2 py-0.5 rounded-full uppercase shrink-0">
          {task.kind}
        </span>
        {isBlocked && (
          <span className="text-[10px] font-bold text-red-400 bg-red-400/10 px-2 py-0.5 rounded-full uppercase shrink-0 flex items-center gap-1 animate-pulse">
            <AlertCircle className="w-3 h-3" />
            Intervention Needed
          </span>
        )}
      </div>

      <h4 className="text-sm font-medium text-gray-200 mb-3 leading-snug group-hover:text-purple-300 transition-colors">
        {task.title}
      </h4>

      {task.description && (
        <p className="text-xs text-gray-400 leading-relaxed mb-3 line-clamp-3">{task.description}</p>
      )}

      {task.blockedBy.length > 0 && (
        <div className="flex flex-wrap gap-1 mt-auto">
          {task.blockedBy.map((blocker) => (
            <span key={`${blocker.kind}:${blocker.ref}`} className="text-[10px] font-mono text-blue-400 bg-blue-400/10 px-1.5 py-0.5 rounded border border-blue-400/20">
              {blocker.kind}: {blocker.ref}
            </span>
          ))}
        </div>
      )}
    </button>
  );
}

function TaskActionsPanel({
  tasks,
  createDraft,
  onCreateDraftChange,
  onCreateTask,
  createPending,
  createError,
  createResult,
  moveDraft,
  onMoveDraftChange,
  onSelectMoveTask,
  onMoveTask,
  movePending,
  moveError,
  moveResult,
  reusableBlockerSuggestions,
}: {
  tasks: TodoTaskItem[];
  createDraft: TaskCreateDraft;
  onCreateDraftChange: (
    field: keyof TaskCreateDraft,
    value: string,
  ) => void;
  onCreateTask: () => void;
  createPending: boolean;
  createError: Error | null;
  createResult?: TodoTaskItem | null;
  moveDraft: TaskMoveDraft;
  onMoveDraftChange: (field: keyof TaskMoveDraft, value: string) => void;
  onSelectMoveTask: (taskRef: string) => void;
  onMoveTask: () => void;
  movePending: boolean;
  moveError: Error | null;
  moveResult?: TodoTaskItem | null;
  reusableBlockerSuggestions: ReusableBlockerSuggestion[];
}) {
  const selectedTask = tasks.find((task) => task.ref === moveDraft.taskRef) ?? null;

  return (
    <SurfaceCard
      icon={<FolderKanban className="w-4 h-4 text-purple-400" />}
      title="Task Actions"
      subtitle={`${tasks.length} visible tasks · direct board mutations`}
    >
      <div className="grid gap-4 xl:grid-cols-2">
        <div className="rounded-xl border border-[#303030] bg-[#191919] p-4">
          <div className="mb-3 text-sm font-medium text-white">Create Task</div>
          <div className="grid gap-3 md:grid-cols-2">
            <label className="space-y-1">
              <span className="text-[11px] uppercase tracking-wide text-gray-500">Task Ref</span>
              <input
                value={createDraft.ref}
                onChange={(event) => onCreateDraftChange('ref', event.target.value)}
                className="w-full rounded-lg border border-[#343434] bg-[#111] px-3 py-2 text-sm text-gray-100 outline-none transition focus:border-purple-500/50"
                placeholder="T-42"
              />
            </label>
            <label className="space-y-1">
              <span className="text-[11px] uppercase tracking-wide text-gray-500">Kind</span>
              <select
                value={createDraft.kind}
                onChange={(event) => onCreateDraftChange('kind', event.target.value)}
                className="w-full rounded-lg border border-[#343434] bg-[#111] px-3 py-2 text-sm text-gray-100 outline-none transition focus:border-purple-500/50"
              >
                <option value="planning">planning</option>
                <option value="engineering">engineering</option>
              </select>
            </label>
            <label className="space-y-1 md:col-span-2">
              <span className="text-[11px] uppercase tracking-wide text-gray-500">Title</span>
              <input
                value={createDraft.title}
                onChange={(event) => onCreateDraftChange('title', event.target.value)}
                className="w-full rounded-lg border border-[#343434] bg-[#111] px-3 py-2 text-sm text-gray-100 outline-none transition focus:border-purple-500/50"
                placeholder="Implement atomic writes"
              />
            </label>
            <label className="space-y-1 md:col-span-2">
              <span className="text-[11px] uppercase tracking-wide text-gray-500">
                Description
              </span>
              <textarea
                value={createDraft.description}
                onChange={(event) => onCreateDraftChange('description', event.target.value)}
                rows={3}
                className="w-full rounded-lg border border-[#343434] bg-[#111] px-3 py-2 text-sm text-gray-100 outline-none transition focus:border-purple-500/50"
                placeholder="Make writes safe."
              />
            </label>
            <label className="space-y-1 md:col-span-2">
              <span className="text-[11px] uppercase tracking-wide text-gray-500">
                Acceptance Criteria
              </span>
              <textarea
                value={createDraft.acceptanceCriteria}
                onChange={(event) =>
                  onCreateDraftChange('acceptanceCriteria', event.target.value)
                }
                rows={3}
                className="w-full rounded-lg border border-[#343434] bg-[#111] px-3 py-2 text-sm text-gray-100 outline-none transition focus:border-purple-500/50"
                placeholder={'One item per line\nConcurrent writes are safe.'}
              />
              <StructuredStringListEditor
                label="Structured acceptance criteria"
                value={createDraft.acceptanceCriteria}
                onChange={(value) => onCreateDraftChange('acceptanceCriteria', value)}
                itemLabel="Criterion"
                addLabel="Add criterion"
                placeholder="Concurrent writes are safe."
                emptyLabel="No structured acceptance criteria yet."
              />
            </label>
            <div className="space-y-1 md:col-span-2">
              <StructuredBlockersEditor
                label="Structured task blockers"
                value={createDraft.blockedByJson}
                onChange={(value) => onCreateDraftChange('blockedByJson', value)}
                suggestions={reusableBlockerSuggestions}
              />
            </div>
          </div>
          <div className="mt-3 flex items-center justify-between gap-3">
            <MutationFeedback error={createError} />
            <button
              onClick={onCreateTask}
              disabled={
                createPending ||
                createDraft.ref.trim().length === 0 ||
                createDraft.title.trim().length === 0 ||
                !hasValidBlockersJsonOrEmpty(createDraft.blockedByJson, 'Task blockers')
              }
              className="rounded-lg bg-purple-600 px-3 py-2 text-sm font-medium text-white transition hover:bg-purple-500 disabled:cursor-not-allowed disabled:opacity-60"
            >
              {createPending ? 'Creating...' : 'Create Task'}
            </button>
          </div>
          {createResult && (
            <div className="mt-3 rounded-lg border border-violet-500/20 bg-violet-500/10 px-3 py-2 text-xs text-violet-200">
              <div>{summarizeTaskMutationResult(createResult)}</div>
              {createResult.blockedBy.length > 0 && (
                <div className="mt-1">
                  <TaskBlockerSummary blockers={createResult.blockedBy} />
                </div>
              )}
            </div>
          )}
        </div>

        <div className="rounded-xl border border-[#303030] bg-[#191919] p-4">
          <div className="mb-3 text-sm font-medium text-white">Manual Move</div>
          <div className="grid gap-3 md:grid-cols-2">
            <label className="space-y-1 md:col-span-2">
              <span className="text-[11px] uppercase tracking-wide text-gray-500">Task</span>
              <select
                value={moveDraft.taskRef}
                onChange={(event) => onSelectMoveTask(event.target.value)}
                className="w-full rounded-lg border border-[#343434] bg-[#111] px-3 py-2 text-sm text-gray-100 outline-none transition focus:border-purple-500/50"
              >
                {tasks.length === 0 ? (
                  <option value="">No tasks available</option>
                ) : (
                  tasks.map((task) => (
                    <option key={task.ref} value={task.ref}>
                      {task.ref} · {task.title}
                    </option>
                  ))
                )}
              </select>
            </label>
            <label className="space-y-1">
              <span className="text-[11px] uppercase tracking-wide text-gray-500">
                Target Status
              </span>
              <select
                value={moveDraft.status}
                onChange={(event) => onMoveDraftChange('status', event.target.value)}
                className="w-full rounded-lg border border-[#343434] bg-[#111] px-3 py-2 text-sm text-gray-100 outline-none transition focus:border-purple-500/50"
              >
                {STATUS_COLUMNS.map((statusColumn) => (
                  <option key={statusColumn.id} value={statusColumn.id}>
                    {statusColumn.label}
                  </option>
                ))}
              </select>
            </label>
            <label className="space-y-1">
              <span className="text-[11px] uppercase tracking-wide text-gray-500">Reason</span>
              <input
                value={moveDraft.reason}
                onChange={(event) => onMoveDraftChange('reason', event.target.value)}
                className="w-full rounded-lg border border-[#343434] bg-[#111] px-3 py-2 text-sm text-gray-100 outline-none transition focus:border-purple-500/50"
                placeholder="manual transition"
              />
            </label>
          </div>

          {selectedTask ? (
            <div className="mt-3 rounded-lg border border-[#2c2c2c] bg-[#161616] px-3 py-3 text-sm text-gray-300">
              <div className="flex flex-wrap items-center gap-2">
                <span className="rounded bg-[#111] px-2 py-1 font-mono text-xs text-gray-400">
                  {selectedTask.ref}
                </span>
                <span className="text-white">{selectedTask.title}</span>
              </div>
              <div className="mt-2 text-xs text-gray-500">
                Current status: <span className="text-gray-300">{selectedTask.status}</span>
                {' '}→ target: <span className="text-gray-300">{moveDraft.status}</span>
              </div>
              {selectedTask.blockedBy.length > 0 && (
                <div className="mt-2 flex flex-wrap gap-2">
                  {selectedTask.blockedBy.map((blocker) => (
                    <span
                      key={`${blocker.kind}:${blocker.ref}`}
                      className="rounded-full border border-blue-400/20 bg-blue-400/10 px-2 py-1 text-[10px] font-mono text-blue-300"
                    >
                      {blocker.kind}: {blocker.ref}
                    </span>
                  ))}
                </div>
              )}
            </div>
          ) : (
            <div className="mt-3 rounded-lg border border-dashed border-[#313131] bg-[#161616] px-3 py-4 text-sm text-gray-500">
              No task selected for manual move.
            </div>
          )}

          <div className="mt-3 flex items-center justify-between gap-3">
            <MutationFeedback error={moveError} />
            <button
              onClick={onMoveTask}
              disabled={
                movePending ||
                !selectedTask ||
                moveDraft.taskRef.trim().length === 0 ||
                selectedTask.status === moveDraft.status
              }
              className="rounded-lg bg-amber-600 px-3 py-2 text-sm font-medium text-white transition hover:bg-amber-500 disabled:cursor-not-allowed disabled:opacity-60"
            >
              {movePending ? 'Moving...' : 'Move Task'}
            </button>
          </div>
          {moveResult && (
            <div className="mt-3 rounded-lg border border-violet-500/20 bg-violet-500/10 px-3 py-2 text-xs text-violet-200">
              <div>{summarizeTaskMutationResult(moveResult)}</div>
              {moveResult.blockedBy.length > 0 && (
                <div className="mt-1">
                  <TaskBlockerSummary blockers={moveResult.blockedBy} />
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </SurfaceCard>
  );
}

function TaskAuthorityPanel({
  task,
  linkedDecisions,
  linkedPlanningRequests,
  linkedWorkflows,
  dependentTasks,
  writeTraceRoleFilter,
  onWriteTraceRoleFilterChange,
  writeTraceLimit,
  onWriteTraceLimitChange,
  taskRuns,
  selectedTaskRunId,
  onSelectTaskRun,
  selectedTaskRunStepId,
  onSelectTaskRunStep,
  taskRunsLoading,
  taskRunsError,
  taskRunDetail,
  taskRunDetailLoading,
  taskRunDetailError,
  selectedTaskRunWriteTraces,
  selectedTaskRunWriteTraceLoading,
  selectedTaskRunWriteTraceError,
  writeTraces,
  writeTraceLoading,
  writeTraceError,
}: {
  task: TodoTaskItem | null;
  linkedDecisions: GoalDecision[];
  linkedPlanningRequests: GoalPlanningRequest[];
  linkedWorkflows: GoalPlanningWorkflowState[];
  dependentTasks: TodoTaskItem[];
  writeTraceRoleFilter: AgentRole | 'all';
  onWriteTraceRoleFilterChange: (value: AgentRole | 'all') => void;
  writeTraceLimit: number | 'all';
  onWriteTraceLimitChange: (value: number | 'all') => void;
  taskRuns: GoalRunSummary[];
  selectedTaskRunId: string | null;
  onSelectTaskRun: (runId: string) => void;
  selectedTaskRunStepId: string | null;
  onSelectTaskRunStep: (stepId: string | null) => void;
  taskRunsLoading: boolean;
  taskRunsError: Error | null;
  taskRunDetail: GoalRunDetail | null;
  taskRunDetailLoading: boolean;
  taskRunDetailError: Error | null;
  selectedTaskRunWriteTraces: GoalWriteTraceEntry[];
  selectedTaskRunWriteTraceLoading: boolean;
  selectedTaskRunWriteTraceError: Error | null;
  writeTraces: GoalWriteTraceEntry[];
  writeTraceLoading: boolean;
  writeTraceError: Error | null;
}) {
  return (
    <SurfaceCard
      icon={<FolderKanban className="w-4 h-4 text-purple-400" />}
      title="Task Authority"
      subtitle={
        task
          ? `${task.status.replace('_', ' ')} · ${task.kind} · ${linkedPlanningRequests.length} planning refs`
          : 'Select a task from the board to inspect its durable authority'
      }
    >
      {!task ? (
        <SurfaceEmptyState label="Select a task card from the board to inspect full task authority." />
      ) : (
        <div className="space-y-4">
          <div className="rounded-xl border border-[#303030] bg-[#191919] p-4">
            <div className="flex items-start justify-between gap-3">
              <div>
                <div className="text-sm font-medium text-white">{task.title}</div>
                <div className="mt-1 text-xs text-gray-500 font-mono">{task.ref}</div>
              </div>
              <div className="flex flex-wrap items-center justify-end gap-2">
                <span className="rounded-full border border-[#3a3a3a] bg-[#111] px-2 py-0.5 text-[10px] font-bold uppercase text-gray-300">
                  {task.kind}
                </span>
                <span className="rounded-full border border-purple-500/20 bg-purple-500/10 px-2 py-0.5 text-[10px] font-bold uppercase text-purple-200">
                  {task.status}
                </span>
              </div>
            </div>

            <p className="mt-3 whitespace-pre-wrap text-xs leading-6 text-gray-300">
              {task.description}
            </p>

            <div className="mt-3 grid gap-3 lg:grid-cols-2">
              <div className="rounded-lg border border-[#2c2c2c] bg-[#111] px-3 py-3">
                <div className="text-[11px] font-medium uppercase tracking-wide text-gray-500">
                  Acceptance Criteria
                </div>
                {task.acceptanceCriteria.length === 0 ? (
                  <div className="mt-2 text-xs text-gray-500">No durable acceptance criteria.</div>
                ) : (
                  <div className="mt-2 space-y-1">
                    {task.acceptanceCriteria.map((criterion, index) => (
                      <div key={`${task.ref}:criterion:${index}`} className="text-xs leading-5 text-gray-300">
                        {index + 1}. {criterion}
                      </div>
                    ))}
                  </div>
                )}
              </div>

              <div className="rounded-lg border border-[#2c2c2c] bg-[#111] px-3 py-3">
                <div className="text-[11px] font-medium uppercase tracking-wide text-gray-500">
                  Blocking Authority
                </div>
                {task.blockedBy.length === 0 ? (
                  <div className="mt-2 text-xs text-gray-500">No durable blockers.</div>
                ) : (
                  <div className="mt-2">
                    <TaskBlockerSummary blockers={task.blockedBy} />
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="grid gap-4 xl:grid-cols-2">
            <div className="rounded-xl border border-[#303030] bg-[#191919] p-4">
              <div className="mb-3 text-sm font-medium text-white">Linked Decisions</div>
              {linkedDecisions.length === 0 ? (
                <div className="text-xs text-gray-500">No durable decisions currently point at this task.</div>
              ) : (
                <div className="space-y-3">
                  {linkedDecisions.map((decision) => (
                    <div key={decision.decisionKey} className="rounded-lg border border-[#2c2c2c] bg-[#111] px-3 py-3">
                      <div className="flex items-start justify-between gap-3">
                        <div>
                          <div className="text-sm text-white">{decision.summary}</div>
                          <div className="mt-1 text-xs font-mono text-gray-500">{decision.decisionKey}</div>
                        </div>
                        <span
                          className={cn(
                            'rounded-full border px-2 py-0.5 text-[10px] font-bold uppercase',
                            decision.status === 'resolved'
                              ? 'border-emerald-500/20 bg-emerald-500/10 text-emerald-300'
                            : 'border-amber-500/20 bg-amber-500/10 text-amber-300',
                          )}
                        >
                          {decision.status}
                        </span>
                      </div>
                      <DecisionAuthorityDetails decision={decision} tone="gray" />
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="rounded-xl border border-[#303030] bg-[#191919] p-4">
              <div className="mb-3 text-sm font-medium text-white">Linked Planning Requests</div>
              {linkedPlanningRequests.length === 0 ? (
                <div className="text-xs text-gray-500">No durable planning requests currently point at this task.</div>
              ) : (
                <div className="space-y-3">
                  {linkedPlanningRequests.map((request) => (
                    <div key={request.requestKey} className="rounded-lg border border-[#2c2c2c] bg-[#111] px-3 py-3">
                      <div className="flex items-start justify-between gap-3">
                        <div>
                          <div className="text-sm text-white">{request.title}</div>
                          <div className="mt-1 text-xs font-mono text-gray-500">{request.requestKey}</div>
                        </div>
                        <span
                          className={cn(
                            'rounded-full border px-2 py-0.5 text-[10px] font-bold uppercase',
                            request.status === 'resolved'
                              ? 'border-emerald-500/20 bg-emerald-500/10 text-emerald-300'
                            : 'border-sky-500/20 bg-sky-500/10 text-sky-300',
                          )}
                        >
                          {request.status}
                        </span>
                      </div>
                      <PlanningRequestAuthorityDetails request={request} tone="gray" />
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="grid gap-4 xl:grid-cols-2">
            <div className="rounded-xl border border-[#303030] bg-[#191919] p-4">
              <div className="mb-3 text-sm font-medium text-white">Workflow Membership</div>
              {linkedWorkflows.length === 0 ? (
                <div className="text-xs text-gray-500">No visible workflow graph currently references this task.</div>
              ) : (
                <div className="space-y-3">
                  {linkedWorkflows.map((workflow) => {
                    const relationship = [
                      workflow.taskRefs.includes(task.ref) ? 'member task' : null,
                      workflow.blockerTaskRefs.includes(task.ref) ? 'workflow blocker' : null,
                    ].filter(Boolean);
                    const matchingPlanningChildren = workflow.workflows.flatMap((child) =>
                      child.kind === 'planning' && child.request.taskRef === task.ref
                        ? [
                            {
                              workflowTaskKey: child.workflowTaskKey,
                              blockedByWorkflowKeys: child.blockedByWorkflowKeys,
                              blockerTaskRefs: child.blockerTaskRefs,
                              request: child.request,
                            },
                          ]
                        : [],
                    );
                    const matchingGroupedRequests = workflow.workflows.flatMap((child) =>
                      child.kind === 'planning_batch'
                        ? child.requests
                            .filter((request) => request.taskRef === task.ref)
                            .map((request) => ({
                              groupKey: child.groupKey,
                              blockedByWorkflowKeys: child.blockedByWorkflowKeys,
                              blockerTaskRefs: child.blockerTaskRefs,
                              request,
                            }))
                        : [],
                    );

                    return (
                      <div key={workflow.workflowKey} className="rounded-lg border border-[#2c2c2c] bg-[#111] px-3 py-3">
                        <div className="text-sm text-white">{workflow.workflowKey}</div>
                        <div className="mt-1 text-xs text-gray-500">
                          {relationship.join(' · ') || 'referenced'}
                        </div>
                        <div className="mt-2 space-y-1 text-xs text-gray-400">
                          <div>{workflow.workflows.length} child node(s)</div>
                          {workflow.requestKeys.length > 0 && (
                            <div>Request keys: {workflow.requestKeys.join(', ')}</div>
                          )}
                          {workflow.groupKeys.length > 0 && (
                            <div>Group keys: {workflow.groupKeys.join(', ')}</div>
                          )}
                          {workflow.blockerTaskRefs.length > 0 && (
                            <div>Blocker task refs: {workflow.blockerTaskRefs.join(', ')}</div>
                          )}
                          {workflow.workflowSharedDecisionRefs.length > 0 && (
                            <div>
                              Workflow-shared decisions:{' '}
                              {workflow.workflowSharedDecisionRefs.join(', ')}
                            </div>
                          )}
                          {workflow.workflowSharedAnswers.length > 0 && (
                            <div>
                              Workflow-shared answers:{' '}
                              {workflow.workflowSharedAnswers
                                .map(summarizeCapturedAnswer)
                                .join(' | ')}
                            </div>
                          )}
                        </div>
                        {(matchingPlanningChildren.length > 0 ||
                          matchingGroupedRequests.length > 0) && (
                          <div className="mt-3 space-y-3">
                            {matchingPlanningChildren.map((child) => (
                              <div
                                key={`${workflow.workflowKey}:${child.request.requestKey}`}
                                className="rounded-lg border border-[#252525] bg-[#161616] px-3 py-3"
                              >
                                <div className="text-sm text-gray-200">{child.request.title}</div>
                                <PlanningRequestAuthorityDetails
                                  request={child.request}
                                  tone="gray"
                                  includeRequestKeyInMeta
                                  prefixLines={
                                    <>
                                      <div>Status: {child.request.status}</div>
                                      <div>Task status: {task.status}</div>
                                      {child.blockerTaskRefs.length > 0 && (
                                        <div>
                                          Blocker task refs: {child.blockerTaskRefs.join(', ')}
                                        </div>
                                      )}
                                    </>
                                  }
                                  suffixLines={
                                    task.blockedBy.length > 0 ? (
                                      <TaskBlockerSummary blockers={task.blockedBy} />
                                    ) : undefined
                                  }
                                />
                              </div>
                            ))}
                            {matchingGroupedRequests.map(({ groupKey, blockedByWorkflowKeys, blockerTaskRefs, request }) => (
                              <div
                                key={`${workflow.workflowKey}:${groupKey}:${request.requestKey}`}
                                className="rounded-lg border border-[#252525] bg-[#161616] px-3 py-3"
                              >
                                <div className="text-sm text-gray-200">{request.title}</div>
                                <PlanningRequestAuthorityDetails
                                  request={request}
                                  tone="gray"
                                  includeRequestKeyInMeta
                                  prefixLines={
                                    <>
                                      <div>Status: {request.status}</div>
                                      <div>Task status: {task.status}</div>
                                      <div>Grouped child: {groupKey}</div>
                                      {blockedByWorkflowKeys.length > 0 && (
                                        <div>
                                          Workflow dependencies: {blockedByWorkflowKeys.join(', ')}
                                        </div>
                                      )}
                                      {blockerTaskRefs.length > 0 && (
                                        <div>
                                          Blocker task refs: {blockerTaskRefs.join(', ')}
                                        </div>
                                      )}
                                    </>
                                  }
                                  suffixLines={
                                    task.blockedBy.length > 0 ? (
                                      <TaskBlockerSummary blockers={task.blockedBy} />
                                    ) : undefined
                                  }
                                />
                              </div>
                            ))}
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              )}
            </div>

            <div className="rounded-xl border border-[#303030] bg-[#191919] p-4">
              <div className="mb-3 text-sm font-medium text-white">Dependent Tasks</div>
              {dependentTasks.length === 0 ? (
                <div className="text-xs text-gray-500">No visible tasks are currently blocked by this task ref.</div>
              ) : (
                <div className="space-y-3">
                  {dependentTasks.map((dependentTask) => (
                    <div key={dependentTask.ref} className="rounded-lg border border-[#2c2c2c] bg-[#111] px-3 py-3">
                      <div className="flex items-start justify-between gap-3">
                        <div>
                          <div className="text-sm text-white">{dependentTask.title}</div>
                          <div className="mt-1 text-xs font-mono text-gray-500">{dependentTask.ref}</div>
                        </div>
                        <span className="rounded-full border border-[#3a3a3a] bg-[#191919] px-2 py-0.5 text-[10px] font-bold uppercase text-gray-300">
                          {dependentTask.status}
                        </span>
                      </div>
                      <div className="mt-2 text-xs text-gray-400">
                        {dependentTask.kind} task · {dependentTask.acceptanceCriteria.length} acceptance item(s)
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="rounded-xl border border-[#303030] bg-[#191919] p-4">
            <div className="mb-3 text-sm font-medium text-white">Task Run History</div>
            {taskRunsError ? (
              <div className="rounded-lg border border-red-500/20 bg-red-500/10 px-3 py-3 text-xs text-red-200">
                {taskRunsError.message}
              </div>
            ) : taskRunsLoading ? (
              <div className="flex items-center gap-2 text-xs text-gray-500">
                <Loader2 className="h-4 w-4 animate-spin" />
                Loading task-scoped workflow runs...
              </div>
            ) : taskRuns.length === 0 ? (
              <div className="text-xs text-gray-500">
                No durable workflow runs currently target this task.
              </div>
            ) : (
              <div className="space-y-3">
                {taskRuns.map((run) => (
                  <button
                    type="button"
                    key={run.runId}
                    onClick={() => onSelectTaskRun(run.runId)}
                    className={cn(
                      'w-full rounded-lg border bg-[#111] px-3 py-3 text-left transition-colors',
                      run.runId === selectedTaskRunId
                        ? 'border-purple-500/40 bg-purple-500/10'
                        : 'border-[#2c2c2c] hover:border-purple-500/30',
                    )}
                  >
                    <div className="flex flex-wrap items-start justify-between gap-2">
                      <div>
                        <div className="text-sm text-white">{run.runId}</div>
                        <div className="mt-1 text-xs font-mono text-gray-500">
                          {run.taskKind} · {formatTimestamp(run.startedAt)}
                        </div>
                      </div>
                      <div className="flex flex-wrap items-center gap-2">
                        <span
                          className={cn(
                            'rounded-full border px-2 py-0.5 text-[10px] font-bold uppercase',
                            summarizeRunStatusClasses(run.status),
                          )}
                        >
                          {run.status}
                        </span>
                        {run.finalTaskStatus && (
                          <span className="rounded-full border border-[#3a3a3a] bg-[#191919] px-2 py-0.5 text-[10px] font-bold uppercase text-gray-300">
                            task {run.finalTaskStatus}
                          </span>
                        )}
                      </div>
                    </div>
                    <div className="mt-2 space-y-1 text-xs text-gray-400">
                      <div>{run.stepCount} step(s)</div>
                      {run.terminalOutcome && <div>Terminal outcome: {run.terminalOutcome}</div>}
                      {run.endedAt && <div>Ended: {formatTimestamp(run.endedAt)}</div>}
                    </div>
                  </button>
                ))}
              </div>
            )}

            {taskRunDetailError ? (
              <div className="mt-3 rounded-lg border border-red-500/20 bg-red-500/10 px-3 py-3 text-xs text-red-200">
                {taskRunDetailError.message}
              </div>
            ) : taskRunDetailLoading ? (
              <div className="mt-3 flex items-center gap-2 text-xs text-gray-500">
                <Loader2 className="h-4 w-4 animate-spin" />
                Loading selected run detail...
              </div>
            ) : taskRunDetail ? (
              <div className="mt-3 rounded-lg border border-[#2c2c2c] bg-[#111] px-3 py-3">
                <div className="flex flex-wrap items-start justify-between gap-2">
                  <div>
                    <div className="text-sm text-white">Selected Run Detail</div>
                    <div className="mt-1 text-xs font-mono text-gray-500">
                      {taskRunDetail.runId} · {taskRunDetail.taskKind}
                    </div>
                  </div>
                  <div className="flex flex-wrap items-center gap-2">
                    <span
                      className={cn(
                        'rounded-full border px-2 py-0.5 text-[10px] font-bold uppercase',
                        summarizeRunStatusClasses(taskRunDetail.status),
                      )}
                    >
                      {taskRunDetail.status}
                    </span>
                    {taskRunDetail.finalTaskStatus && (
                      <span className="rounded-full border border-[#3a3a3a] bg-[#191919] px-2 py-0.5 text-[10px] font-bold uppercase text-gray-300">
                        task {taskRunDetail.finalTaskStatus}
                      </span>
                    )}
                  </div>
                </div>
                <div className="mt-2 space-y-1 text-xs text-gray-400">
                  <div>Started: {formatTimestamp(taskRunDetail.startedAt)}</div>
                  {taskRunDetail.endedAt && <div>Ended: {formatTimestamp(taskRunDetail.endedAt)}</div>}
                  {taskRunDetail.terminalOutcome && (
                    <div>Terminal outcome: {taskRunDetail.terminalOutcome}</div>
                  )}
                </div>
                <div className="mt-3 space-y-3">
                  {taskRunDetail.steps.map((step) => (
                    <div
                      key={step.stepId}
                      className={cn(
                        'rounded-lg border bg-[#161616] px-3 py-3',
                        step.stepId === selectedTaskRunStepId
                          ? 'border-purple-500/40'
                          : 'border-[#252525]',
                      )}
                    >
                      <div className="flex flex-wrap items-start justify-between gap-2">
                        <div>
                          <div className="text-sm text-white">{step.stepId}</div>
                          <div className="mt-1 text-xs font-mono text-gray-500">
                            {step.role} · {formatTimestamp(step.startedAt)}
                          </div>
                        </div>
                        <span
                          className={cn(
                            'rounded-full border px-2 py-0.5 text-[10px] font-bold uppercase',
                            summarizeStepOutcomeClasses(step.outcome),
                          )}
                        >
                          {step.outcome}
                        </span>
                      </div>
                      <div className="mt-2 space-y-1 text-xs text-gray-400">
                        <div>
                          Status: {step.statusBefore}
                          {step.statusAfter ? ` → ${step.statusAfter}` : ''}
                        </div>
                        <div>
                          Messages: {step.messages.length} · Transcript: {step.transcript.length}
                          {' '}· Artifacts: {step.execution?.artifacts.length ?? 0}
                        </div>
                        {step.execution?.worktree?.path && (
                          <div>Worktree: {step.execution.worktree.path}</div>
                        )}
                        {step.endedAt && <div>Ended: {formatTimestamp(step.endedAt)}</div>}
                      </div>
                      <div className="mt-3">
                        <button
                          type="button"
                          onClick={() =>
                            onSelectTaskRunStep(
                              step.stepId === selectedTaskRunStepId ? null : step.stepId,
                            )
                          }
                          className={cn(
                            'rounded-lg border px-3 py-1.5 text-[11px] font-medium transition',
                            step.stepId === selectedTaskRunStepId
                              ? 'border-purple-500/40 bg-purple-500/10 text-purple-200'
                              : 'border-[#343434] bg-[#111] text-gray-200 hover:border-purple-500/40 hover:text-white',
                          )}
                        >
                          {step.stepId === selectedTaskRunStepId
                            ? 'Showing step-scoped writes'
                            : 'Filter write traces to this step'}
                        </button>
                      </div>
                      {step.stepId === selectedTaskRunStepId && (
                        <div className="mt-3 space-y-3 rounded-lg border border-[#2c2c2c] bg-[#111] px-3 py-3">
                          {(step.execution?.worktree?.path ||
                            step.execution?.worktree?.branch ||
                            step.execution?.worktree?.baseBranch) && (
                            <div className="space-y-1">
                              <div className="text-[11px] font-medium uppercase tracking-wide text-gray-500">
                                Worktree Authority
                              </div>
                              <div className="space-y-1 text-xs text-gray-400">
                                {step.execution?.worktree?.path && (
                                  <div>Path: {step.execution.worktree.path}</div>
                                )}
                                {step.execution?.worktree?.branch && (
                                  <div>Branch: {step.execution.worktree.branch}</div>
                                )}
                                {step.execution?.worktree?.baseBranch && (
                                  <div>Base branch: {step.execution.worktree.baseBranch}</div>
                                )}
                              </div>
                            </div>
                          )}
                          {step.transcript.length > 0 && (
                            <div className="space-y-2">
                              <div className="text-[11px] font-medium uppercase tracking-wide text-gray-500">
                                Transcript Entries
                              </div>
                              <div className="space-y-2">
                                {step.transcript.map((entry) => (
                                  <div
                                    key={`${step.stepId}:transcript:${entry.entryId}`}
                                    className="rounded-lg border border-[#252525] bg-[#161616] px-3 py-2"
                                  >
                                    <div className="flex flex-wrap items-start justify-between gap-2">
                                      <div className="text-xs text-gray-200">
                                        {entry.transport}:{entry.kind}
                                      </div>
                                      <div className="text-[10px] font-mono text-gray-500">
                                        {formatTimestamp(entry.createdAt)}
                                      </div>
                                    </div>
                                    <div className="mt-1 text-xs text-gray-400">
                                      {entry.summary}
                                    </div>
                                    {(entry.toolName ||
                                      entry.toolInvocationKey ||
                                      entry.vendorEventType) && (
                                      <div className="mt-1 flex flex-wrap gap-2 text-[10px] text-gray-500">
                                        {entry.toolName && <span>tool={entry.toolName}</span>}
                                        {entry.toolInvocationKey && (
                                          <span>invocation={entry.toolInvocationKey}</span>
                                        )}
                                        {entry.vendorEventType && (
                                          <span>vendor={entry.vendorEventType}</span>
                                        )}
                                      </div>
                                    )}
                                  </div>
                                ))}
                              </div>
                            </div>
                          )}
                          {step.messages.length > 0 && (
                            <div className="space-y-2">
                              <div className="text-[11px] font-medium uppercase tracking-wide text-gray-500">
                                Step Messages
                              </div>
                              <div className="space-y-2">
                                {step.messages.map((message) => (
                                  <div
                                    key={`${step.stepId}:message:${message.messageId}`}
                                    className="rounded-lg border border-[#252525] bg-[#161616] px-3 py-2"
                                  >
                                    <div className="flex flex-wrap items-start justify-between gap-2">
                                      <div className="text-xs text-gray-200">
                                        {message.kind}:{message.role}
                                      </div>
                                      <div className="text-[10px] font-mono text-gray-500">
                                        {formatTimestamp(message.createdAt)}
                                      </div>
                                    </div>
                                    <div className="mt-1 whitespace-pre-wrap text-xs text-gray-400">
                                      {message.content}
                                    </div>
                                  </div>
                                ))}
                              </div>
                            </div>
                          )}
                          {(step.execution?.artifacts.length ?? 0) > 0 && (
                            <div className="space-y-2">
                              <div className="text-[11px] font-medium uppercase tracking-wide text-gray-500">
                                Artifacts
                              </div>
                              <div className="space-y-2">
                                {step.execution?.artifacts.map((artifact) => (
                                  <div
                                    key={`${step.stepId}:artifact:${artifact.ref}`}
                                    className="rounded-lg border border-[#252525] bg-[#161616] px-3 py-2"
                                  >
                                    <div className="text-xs text-gray-200">{artifact.label}</div>
                                    <div className="mt-1 text-[10px] font-mono text-gray-500">
                                      {artifact.ref}
                                    </div>
                                  </div>
                                ))}
                              </div>
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                  ))}
                </div>
                <div className="mt-4 rounded-lg border border-[#252525] bg-[#161616] px-3 py-3">
                  <div className="flex flex-wrap items-start justify-between gap-3">
                    <div>
                      <div className="text-sm text-white">Selected Run Write Traces</div>
                      <div className="mt-1 text-xs text-gray-500">
                        {selectedTaskRunStepId
                          ? `Scoped to ${selectedTaskRunStepId} inside ${taskRunDetail.runId}.`
                          : `Scoped to ${taskRunDetail.runId}.`}
                      </div>
                    </div>
                    <div className="flex flex-wrap items-center gap-2">
                      <label className="flex items-center gap-2 text-[11px] uppercase tracking-wide text-gray-500">
                        <span>Role</span>
                        <select
                          value={writeTraceRoleFilter}
                          onChange={(event) =>
                            onWriteTraceRoleFilterChange(
                              event.target.value as AgentRole | 'all',
                            )
                          }
                          className="rounded-lg border border-[#343434] bg-[#111] px-2 py-1 text-[11px] normal-case text-gray-200 outline-none transition focus:border-purple-500/50"
                        >
                          {WRITE_TRACE_ROLE_FILTERS.map((role) => (
                            <option key={role} value={role}>
                              {role}
                            </option>
                          ))}
                        </select>
                      </label>
                      <label className="flex items-center gap-2 text-[11px] uppercase tracking-wide text-gray-500">
                        <span>Limit</span>
                        <select
                          value={String(writeTraceLimit)}
                          onChange={(event) =>
                            onWriteTraceLimitChange(
                              event.target.value === 'all'
                                ? 'all'
                                : Number.parseInt(event.target.value, 10),
                            )
                          }
                          className="rounded-lg border border-[#343434] bg-[#111] px-2 py-1 text-[11px] normal-case text-gray-200 outline-none transition focus:border-purple-500/50"
                        >
                          {WRITE_TRACE_LIMIT_OPTIONS.map((limit) => (
                            <option key={String(limit)} value={String(limit)}>
                              {limit}
                            </option>
                          ))}
                        </select>
                      </label>
                      <span className="rounded-full border border-[#3a3a3a] bg-[#111] px-2 py-0.5 text-[10px] font-mono text-gray-300">
                        {taskRunDetail.runId}
                      </span>
                      {selectedTaskRunStepId && (
                        <>
                          <span className="rounded-full border border-purple-500/20 bg-purple-500/10 px-2 py-0.5 text-[10px] font-mono text-purple-200">
                            {selectedTaskRunStepId}
                          </span>
                          <button
                            type="button"
                            onClick={() => onSelectTaskRunStep(null)}
                            className="rounded-lg border border-[#343434] bg-[#111] px-2 py-1 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
                          >
                            Show run writes
                          </button>
                        </>
                      )}
                    </div>
                  </div>
                  {selectedTaskRunWriteTraceError ? (
                    <div className="mt-3 rounded-lg border border-red-500/20 bg-red-500/10 px-3 py-3 text-xs text-red-200">
                      {selectedTaskRunWriteTraceError.message}
                    </div>
                  ) : selectedTaskRunWriteTraceLoading ? (
                    <div className="mt-3 flex items-center gap-2 text-xs text-gray-500">
                      <Loader2 className="h-4 w-4 animate-spin" />
                      Loading selected-run write traces...
                    </div>
                  ) : selectedTaskRunWriteTraces.length === 0 ? (
                    <div className="mt-3 text-xs text-gray-500">
                      {selectedTaskRunStepId
                        ? 'No durable write traces currently match this selected run step.'
                        : 'No durable write traces currently match this selected run.'}
                    </div>
                  ) : (
                    <div className="mt-3 space-y-3">
                      {selectedTaskRunWriteTraces.map((entry) => (
                        <div
                          key={`${taskRunDetail.runId}:${entry.id}`}
                          className="rounded-lg border border-[#2c2c2c] bg-[#111] px-3 py-3"
                        >
                          <div className="flex flex-wrap items-start justify-between gap-2">
                            <div>
                              <div className="text-sm text-white">{entry.toolName}</div>
                              <div className="mt-1 text-xs font-mono text-gray-500">
                                {entry.role} · {entry.agent} · {formatTimestamp(entry.timestamp)}
                              </div>
                            </div>
                            <span className="rounded-full border border-[#3a3a3a] bg-[#191919] px-2 py-0.5 text-[10px] font-mono text-gray-300">
                              {entry.stepId}
                            </span>
                          </div>
                          <div className="mt-2 space-y-1 text-xs text-gray-400">
                            <div>Call: {entry.callId}</div>
                            <div className="break-all">Cwd: {entry.cwd}</div>
                            {entry.argumentSummary && <div>Args: {entry.argumentSummary}</div>}
                            {entry.resultSummary && <div>Result: {entry.resultSummary}</div>}
                          </div>
                          {entry.targetPaths.length > 0 && (
                            <div className="mt-2 flex flex-wrap gap-2">
                              {entry.targetPaths.map((path) => (
                                <span
                                  key={`${entry.id}:run-target:${path}`}
                                  className="rounded-full border border-cyan-500/20 bg-cyan-500/10 px-2 py-0.5 text-[10px] font-mono text-cyan-200"
                                >
                                  {path}
                                </span>
                              ))}
                            </div>
                          )}
                          {entry.changes.length > 0 && (
                            <div className="mt-2 space-y-1 text-xs text-gray-400">
                              {entry.changes.map((change, index) => (
                                <div key={`${entry.id}:run-change:${index}`}>
                                  {change.kind}: {change.path}
                                </div>
                              ))}
                            </div>
                          )}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            ) : null}
          </div>

          <div className="rounded-xl border border-[#303030] bg-[#191919] p-4">
            <div className="mb-3 flex flex-wrap items-center justify-between gap-3">
              <div className="text-sm font-medium text-white">Task Write Traces</div>
              <div className="flex flex-wrap items-center gap-3">
                <label className="flex items-center gap-2 text-[11px] uppercase tracking-wide text-gray-500">
                  <span>Role</span>
                  <select
                    value={writeTraceRoleFilter}
                    onChange={(event) =>
                      onWriteTraceRoleFilterChange(event.target.value as AgentRole | 'all')
                    }
                    className="rounded-lg border border-[#343434] bg-[#111] px-2 py-1 text-[11px] normal-case text-gray-200 outline-none transition focus:border-purple-500/50"
                  >
                    {WRITE_TRACE_ROLE_FILTERS.map((role) => (
                      <option key={role} value={role}>
                        {role}
                      </option>
                    ))}
                  </select>
                </label>
                <label className="flex items-center gap-2 text-[11px] uppercase tracking-wide text-gray-500">
                  <span>Limit</span>
                  <select
                    value={String(writeTraceLimit)}
                    onChange={(event) =>
                      onWriteTraceLimitChange(
                        event.target.value === 'all'
                          ? 'all'
                          : Number.parseInt(event.target.value, 10),
                      )
                    }
                    className="rounded-lg border border-[#343434] bg-[#111] px-2 py-1 text-[11px] normal-case text-gray-200 outline-none transition focus:border-purple-500/50"
                  >
                    {WRITE_TRACE_LIMIT_OPTIONS.map((limit) => (
                      <option key={String(limit)} value={String(limit)}>
                        {limit}
                      </option>
                    ))}
                  </select>
                </label>
              </div>
            </div>
            {writeTraceError ? (
              <div className="rounded-lg border border-red-500/20 bg-red-500/10 px-3 py-3 text-xs text-red-200">
                {writeTraceError.message}
              </div>
            ) : writeTraceLoading ? (
              <div className="flex items-center gap-2 text-xs text-gray-500">
                <Loader2 className="h-4 w-4 animate-spin" />
                Loading task-scoped write traces...
              </div>
            ) : writeTraces.length === 0 ? (
              <div className="text-xs text-gray-500">
                No durable write traces currently reference this task.
              </div>
            ) : (
              <div className="space-y-3">
                {writeTraces.map((entry) => (
                  <div
                    key={entry.id}
                    className="rounded-lg border border-[#2c2c2c] bg-[#111] px-3 py-3"
                  >
                    <div className="flex flex-wrap items-start justify-between gap-2">
                      <div>
                        <div className="text-sm text-white">{entry.toolName}</div>
                        <div className="mt-1 text-xs font-mono text-gray-500">
                          {entry.role} · {entry.agent} · {formatTimestamp(entry.timestamp)}
                        </div>
                      </div>
                      <div className="rounded-full border border-[#3a3a3a] bg-[#191919] px-2 py-0.5 text-[10px] font-mono text-gray-300">
                        {entry.runId}
                      </div>
                    </div>
                    <div className="mt-2 space-y-1 text-xs text-gray-400">
                      <div>Step: {entry.stepId}</div>
                      <div>Call: {entry.callId}</div>
                      <div className="break-all">Cwd: {entry.cwd}</div>
                      {entry.argumentSummary && <div>Args: {entry.argumentSummary}</div>}
                      {entry.resultSummary && <div>Result: {entry.resultSummary}</div>}
                    </div>
                    {entry.targetPaths.length > 0 && (
                      <div className="mt-2 flex flex-wrap gap-2">
                        {entry.targetPaths.map((path) => (
                          <span
                            key={`${entry.id}:target:${path}`}
                            className="rounded-full border border-cyan-500/20 bg-cyan-500/10 px-2 py-0.5 text-[10px] font-mono text-cyan-200"
                          >
                            {path}
                          </span>
                        ))}
                      </div>
                    )}
                    {entry.changes.length > 0 && (
                      <div className="mt-2 space-y-1 text-xs text-gray-400">
                        {entry.changes.map((change, index) => (
                          <div key={`${entry.id}:change:${index}`}>
                            {change.kind}: {change.path}
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
    </SurfaceCard>
  );
}

function DocCard({
  title,
  subtitle,
  status,
  content,
}: {
  title: string;
  subtitle: string;
  status?: GoalDocsSnapshot['goal']['status'];
  content?: string;
}) {
  const [expanded, setExpanded] = useState(false);
  const normalizedContent = content?.trim() || 'Loading document snapshot...';
  const hasOverflow =
    normalizedContent !== 'Loading document snapshot...' &&
    (normalizedContent.split('\n').length > 6 || normalizedContent.length > 480);

  return (
    <div className="rounded-2xl border border-[#2f2f2f] bg-[#1D1D1D] p-4">
      <div className="flex items-start justify-between gap-3 mb-3">
        <div>
          <div className="flex items-center gap-2 text-white font-medium">
            <FileText className="w-4 h-4 text-purple-400" />
            {title}
          </div>
          <p className="mt-1 text-xs text-gray-500 break-all">{subtitle}</p>
        </div>
        {status && (
          <span
            className={cn(
              'rounded-full border px-2 py-0.5 text-[10px] font-bold uppercase',
              status === 'curated'
                ? 'border-emerald-500/20 bg-emerald-500/10 text-emerald-300'
                : 'border-yellow-500/20 bg-yellow-500/10 text-yellow-300',
            )}
          >
            {status}
          </span>
        )}
      </div>

      <pre
        className={cn(
          'm-0 whitespace-pre-wrap break-words text-xs leading-6 text-gray-400 font-mono',
          !expanded && 'line-clamp-6',
        )}
      >
        {normalizedContent}
      </pre>
      {hasOverflow && (
        <div className="mt-3 flex justify-end">
          <button
            type="button"
            onClick={() => setExpanded((current) => !current)}
            className="rounded-lg border border-[#343434] bg-[#111] px-3 py-1.5 text-[11px] font-medium text-gray-300 transition hover:border-purple-500/40 hover:text-white"
          >
            {expanded ? 'Collapse doc' : 'Show full doc'}
          </button>
        </div>
      )}
    </div>
  );
}

function SourceResponseFormatGuidance({
  format,
  sourceResponse,
  onApplyTemplate,
  onApplyFormatTemplate,
  onApplyFormatContextSetup,
  onApplyFormatAnswerContextSetup,
  onApplyCurrentContextSetup,
  onApplyCurrentAnswerContextSetup,
  onApplyCurrentAnswerSetup,
  onApplyCurrentAnswerSourceSetup,
  onApplyCurrentConsumerRouting,
  consumers = [],
}: {
  format: GoalSourceResponseFormat;
  sourceResponse?: string;
  onApplyTemplate?: (value: string) => void;
  onApplyFormatTemplate?: (format: GoalSourceResponseFormat, value: string) => void;
  onApplyFormatContextSetup?: (format: GoalSourceResponseFormat, value: string) => void;
  onApplyFormatAnswerContextSetup?: (
    format: GoalSourceResponseFormat,
    value: string,
  ) => void;
  onApplyCurrentContextSetup?: (value: string) => void;
  onApplyCurrentAnswerContextSetup?: (value: string) => void;
  onApplyCurrentAnswerSetup?: () => void;
  onApplyCurrentAnswerSourceSetup?: () => void;
  onApplyCurrentConsumerRouting?: () => void;
  consumers?: SourceResponseTemplateConsumer[];
}) {
  const template = buildSourceResponseFormatTemplate(format);
  const trimmedSourceResponse = sourceResponse?.trim() ?? '';
  const usesAnswerSourceOnly = ANSWER_SOURCE_ONLY_FORMATS.has(format);
  const contextualConsumers = collectSourceResponseTemplateConsumers(consumers);
  const contextualTemplate = buildContextualSourceResponseTemplate(
    format,
    contextualConsumers,
  );
  const recommendedContextualTemplate =
    format === 'auto'
      ? buildRecommendedContextualSourceResponseTemplate(contextualConsumers)
      : null;

  return (
    <div className="mt-2 rounded-lg border border-[#2c2c2c] bg-[#161616] px-3 py-3">
      <div className="text-[11px] font-medium uppercase tracking-wide text-gray-500">
        {formatSourceResponseFormatLabel(format)}
      </div>
      <div className="mt-1 text-xs leading-5 text-gray-400">
        {describeSourceResponseFormat(format)}
      </div>
      <div className="mt-2 text-[11px] text-gray-500">
        Input authority: {describeSourceResponseInputAuthority(format)}
      </div>
      <div className="mt-1 text-[11px] text-gray-500">
        Inference support: open decisions{' '}
        {INFER_OPEN_DECISION_FORMATS.has(format) ? 'yes' : 'no'} · decision topics{' '}
        {INFER_DECISION_TOPIC_FORMATS.has(format) ? 'yes' : 'no'} · remaining answers{' '}
        {INFER_REMAINING_PLANNING_ANSWER_FORMATS.has(format) ? 'yes' : 'no'}
      </div>
      {format === 'auto' ? (
        <div className="mt-2 text-[11px] text-gray-500">
          Pick a concrete deterministic format to reveal a starter template, or keep auto when you
          already have a well-structured shared reply.
        </div>
      ) : usesAnswerSourceOnly ? (
        <div className="mt-2 text-[11px] text-gray-500">
          This format consumes structured answer sources instead of a shared source-response
          textarea.
        </div>
      ) : template ? (
        <details className="mt-3 rounded-lg border border-[#252525] bg-[#111] px-3 py-3">
          <summary className="cursor-pointer text-[11px] font-medium uppercase tracking-wide text-gray-500">
            Starter template
          </summary>
          <div className="mt-3 text-[11px] text-gray-500">
            Insert a deterministic skeleton for this format, then replace the placeholder content
            with the current reply text.
          </div>
          <pre className="mt-3 overflow-x-auto rounded-lg border border-[#252525] bg-[#161616] px-3 py-3 text-xs leading-5 text-gray-300 whitespace-pre-wrap">
            {template}
          </pre>
          {onApplyTemplate && (
            <button
              type="button"
              onClick={() => onApplyTemplate(template)}
              className="mt-3 inline-flex items-center gap-2 rounded-lg border border-[#343434] bg-[#161616] px-3 py-2 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
            >
              {trimmedSourceResponse.length > 0 ? 'Replace source response' : 'Insert template'}
            </button>
          )}
        </details>
      ) : null}
      {contextualConsumers.length > 0 ? (
        <details className="mt-3 rounded-lg border border-[#252525] bg-[#111] px-3 py-3">
          <summary className="cursor-pointer text-[11px] font-medium uppercase tracking-wide text-gray-500">
            Current consumer prefill
          </summary>
          <div className="mt-3 text-[11px] text-gray-500">
            Preserve this current consumer order or label authority when rewriting the shared reply
            into a deterministic format.
          </div>
          <div className="mt-3 space-y-2">
            {contextualConsumers.map((consumer, index) => (
              <div
                key={`${consumer.summary}:${consumer.prompt ?? index}`}
                className="rounded-lg border border-[#252525] bg-[#161616] px-3 py-2"
              >
                <div className="text-[11px] font-medium text-gray-300">
                  {index + 1}. {consumer.summary || consumer.prompt}
                </div>
                {consumer.prompt && consumer.prompt !== consumer.summary ? (
                  <div className="mt-1 text-[11px] text-gray-500">{consumer.prompt}</div>
                ) : null}
              </div>
            ))}
          </div>
          {contextualTemplate && !usesAnswerSourceOnly ? (
            <>
              <div className="mt-3 text-[11px] text-gray-500">
                Insert a deterministic skeleton seeded from the current consumer authority instead
                of rebuilding the labels or order by hand.
              </div>
              <pre className="mt-3 overflow-x-auto rounded-lg border border-[#252525] bg-[#161616] px-3 py-3 text-xs leading-5 text-gray-300 whitespace-pre-wrap">
                {contextualTemplate}
              </pre>
              {onApplyTemplate && (
                <button
                  type="button"
                  onClick={() => onApplyTemplate(contextualTemplate)}
                  className="mt-3 inline-flex items-center gap-2 rounded-lg border border-[#343434] bg-[#161616] px-3 py-2 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
                >
                  {trimmedSourceResponse.length > 0
                    ? 'Replace with current-context template'
                    : 'Insert current-context template'}
                </button>
              )}
              {onApplyCurrentContextSetup && (
                <button
                  type="button"
                  onClick={() => onApplyCurrentContextSetup(contextualTemplate)}
                  className="mt-3 ml-3 inline-flex items-center gap-2 rounded-lg border border-[#343434] bg-[#161616] px-3 py-2 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
                >
                  Set up current-context reply
                </button>
              )}
              {onApplyCurrentAnswerContextSetup && (
                <button
                  type="button"
                  onClick={() => onApplyCurrentAnswerContextSetup(contextualTemplate)}
                  className="mt-3 ml-3 inline-flex items-center gap-2 rounded-lg border border-[#343434] bg-[#161616] px-3 py-2 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
                >
                  Set up current answer context
                </button>
              )}
            </>
          ) : format === 'auto' ? (
            <>
              <div className="mt-3 text-[11px] text-gray-500">
                Auto will still reuse the current consumer order and authority. Pick a concrete
                deterministic format if you want a seeded reply template, or route the current
                consumers directly into structured answer sources here.
              </div>
              {recommendedContextualTemplate ? (
                <>
                  <div className="mt-3 text-[11px] text-gray-500">
                    Recommended deterministic surface:{' '}
                    {formatSourceResponseFormatLabel(recommendedContextualTemplate.format)}.
                  </div>
                  <pre className="mt-3 overflow-x-auto rounded-lg border border-[#252525] bg-[#161616] px-3 py-3 text-xs leading-5 text-gray-300 whitespace-pre-wrap">
                    {recommendedContextualTemplate.template}
                  </pre>
                  {onApplyFormatTemplate ? (
                    <button
                      type="button"
                      onClick={() =>
                        onApplyFormatTemplate(
                          recommendedContextualTemplate.format,
                          recommendedContextualTemplate.template,
                        )
                      }
                      className="mt-3 inline-flex items-center gap-2 rounded-lg border border-[#343434] bg-[#161616] px-3 py-2 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
                    >
                      Use {formatSourceResponseFormatLabel(recommendedContextualTemplate.format)}
                    </button>
                  ) : null}
                  {onApplyFormatContextSetup ? (
                    <button
                      type="button"
                      onClick={() =>
                        onApplyFormatContextSetup(
                          recommendedContextualTemplate.format,
                          recommendedContextualTemplate.template,
                        )
                      }
                      className="mt-3 ml-3 inline-flex items-center gap-2 rounded-lg border border-[#343434] bg-[#161616] px-3 py-2 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
                    >
                      Set up {formatSourceResponseFormatLabel(recommendedContextualTemplate.format)}
                    </button>
                  ) : null}
                  {onApplyFormatAnswerContextSetup ? (
                    <button
                      type="button"
                      onClick={() =>
                        onApplyFormatAnswerContextSetup(
                          recommendedContextualTemplate.format,
                          recommendedContextualTemplate.template,
                        )
                      }
                      className="mt-3 ml-3 inline-flex items-center gap-2 rounded-lg border border-[#343434] bg-[#161616] px-3 py-2 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
                    >
                      Set up current answer context
                    </button>
                  ) : null}
                </>
              ) : null}
              {onApplyCurrentAnswerSetup ? (
                <button
                  type="button"
                  onClick={() => onApplyCurrentAnswerSetup()}
                  className="mt-3 mr-3 inline-flex items-center gap-2 rounded-lg border border-[#343434] bg-[#161616] px-3 py-2 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
                >
                  Set up current answers
                </button>
              ) : null}
              {onApplyCurrentAnswerSourceSetup ? (
                <button
                  type="button"
                  onClick={() => onApplyCurrentAnswerSourceSetup()}
                  className="mt-3 mr-3 inline-flex items-center gap-2 rounded-lg border border-[#343434] bg-[#161616] px-3 py-2 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
                >
                  Set up current answer sources
                </button>
              ) : null}
              {onApplyCurrentConsumerRouting && (
                <button
                  type="button"
                  onClick={() => onApplyCurrentConsumerRouting()}
                  className="mt-3 inline-flex items-center gap-2 rounded-lg border border-[#343434] bg-[#161616] px-3 py-2 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
                >
                  Route current consumers
                </button>
              )}
            </>
          ) : usesAnswerSourceOnly ? (
            <>
              <div className="mt-3 text-[11px] text-gray-500">
                This format routes structured answer sources without a shared source-response
                textarea. Use the current consumer order above to seed those routing entries
                directly.
              </div>
              {onApplyCurrentAnswerSourceSetup && (
                <button
                  type="button"
                  onClick={() => onApplyCurrentAnswerSourceSetup()}
                  className="mt-3 mr-3 inline-flex items-center gap-2 rounded-lg border border-[#343434] bg-[#161616] px-3 py-2 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
                >
                  Set up current answer sources
                </button>
              )}
              {onApplyCurrentAnswerSetup ? (
                <button
                  type="button"
                  onClick={() => onApplyCurrentAnswerSetup()}
                  className="mt-3 mr-3 inline-flex items-center gap-2 rounded-lg border border-[#343434] bg-[#161616] px-3 py-2 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
                >
                  Set up current answers
                </button>
              ) : null}
              {onApplyCurrentConsumerRouting && (
                <button
                  type="button"
                  onClick={() => onApplyCurrentConsumerRouting()}
                  className="mt-3 inline-flex items-center gap-2 rounded-lg border border-[#343434] bg-[#161616] px-3 py-2 text-[11px] font-medium text-gray-200 transition hover:border-purple-500/40 hover:text-white"
                >
                  Route current consumers
                </button>
              )}
            </>
          ) : (
            <div className="mt-3 text-[11px] text-gray-500">
              Use the consumer order above together with the generic starter template for this
              format.
            </div>
          )}
        </details>
      ) : null}
    </div>
  );
}

