function summarizeCapturedAnswer(answer: CapturedAnswer) {
  const metadata = [
    answer.prompt ? `prompt=${answer.prompt}` : null,
    answer.summaryKey ? `summaryKey=${answer.summaryKey}` : null,
    answer.answerKey ? `answerKey=${answer.answerKey}` : null,
    answer.matchHints && answer.matchHints.length > 0
      ? `matchHints=${answer.matchHints.join('|')}`
      : null,
    answer.captureFormat ? `captureFormat=${answer.captureFormat}` : null,
  ]
    .filter(Boolean)
    .join(' · ');

  return metadata.length > 0
    ? `${answer.summary} [${metadata}]: ${answer.answer}`
    : `${answer.summary}: ${answer.answer}`;
}

function summarizeWorkflowLeafCardTitle(workflowChild: GoalPlanningWorkflowLeafState) {
  if (workflowChild.kind === 'planning') {
    return `Planning child ${workflowChild.workflowTaskKey ?? workflowChild.request.requestKey} -> ${workflowChild.request.title}`;
  }

  return `Grouped child ${workflowChild.groupKey}`;
}

function summarizeWorkflowLeafRequestStatus(workflowChild: GoalPlanningWorkflowLeafState) {
  if (workflowChild.kind === 'planning') {
    return `Request status: ${workflowChild.request.status}`;
  }

  const openCount = workflowChild.requests.filter((request) => request.status === 'open').length;
  const resolvedCount = workflowChild.requests.filter((request) => request.status === 'resolved').length;
  const parts = [
    openCount > 0 ? `${openCount} open` : '',
    resolvedCount > 0 ? `${resolvedCount} resolved` : '',
  ].filter((part) => part.length > 0);

  if (parts.length === 0) {
    return null;
  }

  return `Grouped request status: ${parts.join(' · ')}`;
}

function summarizeWorkflowLeafCardTail(workflowChild: GoalPlanningWorkflowLeafState) {
  return workflowChild.blockerTaskRefs.length > 0
    ? workflowChild.blockerTaskRefs.join(', ')
    : 'none';
}

function summarizeWorkflowLeafDecisionRefs(workflowChild: GoalPlanningWorkflowLeafState) {
  const decisionRefs =
    workflowChild.kind === 'planning'
      ? workflowChild.request.decisionRefs
      : collectUniquePlanningRequestDecisionRefs(workflowChild.requests);

  if (decisionRefs.length === 0) {
    return null;
  }

  return summarizePreviewText(decisionRefs.join(', '), 180);
}

function summarizeWorkflowLeafCapturedAnswers(workflowChild: GoalPlanningWorkflowLeafState) {
  const answers =
    workflowChild.kind === 'planning'
      ? workflowChild.request.answers
      : collectUniqueCapturedAnswersFromPlanningRequests(workflowChild.requests);

  if (answers.length === 0) {
    return null;
  }

  return summarizePreviewText(answers.map(summarizeCapturedAnswer).join(' | '), 220);
}

function summarizeWorkflowLeafGroupedRequests(workflowChild: GoalPlanningWorkflowLeafState) {
  if (workflowChild.kind !== 'planning_batch' || workflowChild.requests.length === 0) {
    return null;
  }

  return workflowChild.requests
    .map((request) => `${request.groupTaskKey ?? request.requestKey} [${request.status}]: ${request.title}`)
    .join(' | ');
}

function buildReusableAnswerSourceSuggestions(
  decisions: GoalDecision[],
  requests: GoalPlanningRequest[],
): ReusableAnswerSourceSuggestion[] {
  const suggestions: ReusableAnswerSourceSuggestion[] = [];
  const seenSuggestionKeys = new Set<string>();

  const pushSuggestion = (suggestion: ReusableAnswerSourceSuggestion | null) => {
    if (!suggestion || seenSuggestionKeys.has(suggestion.suggestionKey)) {
      return;
    }
    seenSuggestionKeys.add(suggestion.suggestionKey);
    suggestions.push(suggestion);
  };

  for (const decision of decisions) {
    pushSuggestion(createDecisionAnswerSourceSuggestion(decision));
  }

  for (const request of requests) {
    for (const answer of request.answers) {
      pushSuggestion(createPlanningAnswerSourceSuggestion(request, answer, 'request'));
    }
    for (const answer of request.workflowSharedAnswers) {
      pushSuggestion(createPlanningAnswerSourceSuggestion(request, answer, 'workflow_shared'));
    }
  }

  return suggestions;
}

function buildReusableAnswerSourceRoutingSuggestions({
  decisions = [],
  decisionAnswerItems = [],
  planningAnswerItems = [],
}: {
  decisions?: GoalDecision[];
  decisionAnswerItems?: DecisionAnswerEntryEditorItem[];
  planningAnswerItems?: PlanningAnswerEditorItem[];
}) {
  const suggestions: ReusableAnswerSourceRoutingSuggestion[] = [];
  const seenSuggestionKeys = new Set<string>();

  const pushSuggestion = (
    suggestion: ReusableAnswerSourceRoutingSuggestion | null,
  ) => {
    if (!suggestion || seenSuggestionKeys.has(suggestion.suggestionKey)) {
      return;
    }
    seenSuggestionKeys.add(suggestion.suggestionKey);
    suggestions.push(suggestion);
  };

  for (const decision of decisions) {
    pushSuggestion(createDecisionAnswerSourceRoutingSuggestionFromDecision(decision));
  }

  decisionAnswerItems.forEach((item, index) => {
    pushSuggestion(
      createDecisionAnswerSourceRoutingSuggestionFromDecisionAnswerItem(item, index),
    );
  });

  planningAnswerItems.forEach((item, index) => {
    pushSuggestion(
      createPlanningAnswerSourceRoutingSuggestionFromPlanningAnswerItem(item, index),
    );
  });

  return suggestions;
}

function mergeReusableAnswerSourceRoutingSuggestions(
  ...groups: Array<ReusableAnswerSourceRoutingSuggestion[]>
) {
  const merged: ReusableAnswerSourceRoutingSuggestion[] = [];
  const seenSuggestionKeys = new Set<string>();

  for (const group of groups) {
    for (const suggestion of group) {
      if (seenSuggestionKeys.has(suggestion.suggestionKey)) {
        continue;
      }
      seenSuggestionKeys.add(suggestion.suggestionKey);
      merged.push(suggestion);
    }
  }

  return merged;
}

function buildReusablePlanningAnswerSuggestions(
  decisions: GoalDecision[],
  requests: GoalPlanningRequest[],
): ReusablePlanningAnswerSuggestion[] {
  const suggestions: ReusablePlanningAnswerSuggestion[] = [];
  const seenSuggestionKeys = new Set<string>();

  const pushSuggestion = (suggestion: ReusablePlanningAnswerSuggestion | null) => {
    if (!suggestion || seenSuggestionKeys.has(suggestion.suggestionKey)) {
      return;
    }
    seenSuggestionKeys.add(suggestion.suggestionKey);
    suggestions.push(suggestion);
  };

  for (const decision of decisions) {
    pushSuggestion(createDecisionPlanningAnswerSuggestion(decision));
  }

  for (const request of requests) {
    for (const answer of request.answers) {
      pushSuggestion(createCapturedPlanningAnswerSuggestion(request, answer, 'request'));
    }
    for (const answer of request.workflowSharedAnswers) {
      pushSuggestion(
        createCapturedPlanningAnswerSuggestion(request, answer, 'workflow_shared'),
      );
    }
  }

  return suggestions;
}

