function buildReusableWorkflowTaskRefSuggestions(
  requests: GoalPlanningRequest[],
  tasks: TodoTaskItem[],
  workflows: GoalPlanningWorkflowState[],
): ReusableStringSuggestion[] {
  const suggestions: ReusableStringSuggestion[] = [];
  const seenValues = new Set<string>();

  const pushSuggestion = (suggestion: ReusableStringSuggestion | null) => {
    const value = suggestion?.value.trim() ?? '';
    if (!suggestion || value.length === 0 || seenValues.has(value)) {
      return;
    }
    seenValues.add(value);
    suggestions.push(suggestion);
  };

  const openPlanningTaskRefSet = new Set(
    tasks
      .filter((task) => task.kind === 'planning' && task.status !== 'done')
      .map((task) => task.ref),
  );
  const openRequestByTaskRef = new Map<string, GoalPlanningRequest>();
  for (const request of requests) {
    if (request.status !== 'open' || !openPlanningTaskRefSet.has(request.taskRef)) {
      continue;
    }
    if (!openRequestByTaskRef.has(request.taskRef)) {
      openRequestByTaskRef.set(request.taskRef, request);
    }
  }

  for (const task of tasks) {
    if (task.kind !== 'planning' || task.status === 'done') {
      continue;
    }
    pushSuggestion(
      createWorkflowRootTaskRefSuggestion(task, openRequestByTaskRef.get(task.ref)),
    );
  }

  for (const workflow of workflows) {
    for (const taskRef of workflow.taskRefs) {
      pushSuggestion(createWorkflowTaskRefSuggestion(taskRef, workflow));
    }
  }

  return suggestions;
}

function buildReusableWorkflowTaskKeySuggestions(
  workflowGraphs: ReusableWorkflowGraphSuggestion[],
  workflowKey: string,
): ReusableStringSuggestion[] {
  const normalizedWorkflowKey = workflowKey.trim();
  if (normalizedWorkflowKey.length === 0) {
    return [];
  }

  const suggestions: ReusableStringSuggestion[] = [];
  const seenSuggestionKeys = new Set<string>();
  const workflowGraph = workflowGraphs.find(
    (suggestion) => suggestion.item.workflowKey === normalizedWorkflowKey,
  );
  if (!workflowGraph) {
    return suggestions;
  }

  const { items } = parseWorkflowChildEditorItems(workflowGraph.item.childrenJson);
  for (const item of items) {
    if (item.kind !== 'planning' || !item.workflowTaskKey.trim()) {
      continue;
    }
    const suggestion = createWorkflowTaskKeySuggestion(
      item.workflowTaskKey,
      workflowGraph.item.workflowKey,
    );
    if (!suggestion || seenSuggestionKeys.has(suggestion.suggestionKey)) {
      continue;
    }
    seenSuggestionKeys.add(suggestion.suggestionKey);
    suggestions.push(suggestion);
  }

  return suggestions;
}

function buildReusableWorkflowGroupKeySuggestions(
  requests: GoalPlanningRequest[],
  tasks: TodoTaskItem[],
  workflows: GoalPlanningWorkflowState[],
): ReusableStringSuggestion[] {
  const suggestions: ReusableStringSuggestion[] = [];
  const seenValues = new Set<string>();

  const pushSuggestion = (suggestion: ReusableStringSuggestion | null) => {
    const value = suggestion?.value.trim() ?? '';
    if (!suggestion || value.length === 0 || seenValues.has(value)) {
      return;
    }
    seenValues.add(value);
    suggestions.push(suggestion);
  };

  const openTaskRefSet = new Set(
    tasks.filter((task) => task.status !== 'done').map((task) => task.ref),
  );
  const openRequestsByGroupKey = new Map<string, GoalPlanningRequest[]>();
  for (const request of requests) {
    const groupKey = request.groupKey?.trim();
    if (!groupKey || request.status !== 'open' || !openTaskRefSet.has(request.taskRef)) {
      continue;
    }
    const current = openRequestsByGroupKey.get(groupKey) ?? [];
    current.push(request);
    openRequestsByGroupKey.set(groupKey, current);
  }

  for (const [groupKey, groupedRequests] of openRequestsByGroupKey) {
    pushSuggestion(createWorkflowRootGroupKeySuggestion(groupKey, groupedRequests));
  }

  for (const workflow of workflows) {
    for (const groupKey of workflow.groupKeys) {
      pushSuggestion(createWorkflowGroupKeySuggestion(groupKey, workflow));
    }
  }

  return suggestions;
}

function buildReusableWorkflowDependencyKeySuggestions(
  workflowGraphs: ReusableWorkflowGraphSuggestion[],
  workflowKey: string,
): ReusableStringSuggestion[] {
  const normalizedWorkflowKey = workflowKey.trim();
  if (normalizedWorkflowKey.length === 0) {
    return [];
  }

  const suggestions: ReusableStringSuggestion[] = [];
  const seenValues = new Set<string>();
  const workflowGraph = workflowGraphs.find(
    (suggestion) => suggestion.item.workflowKey === normalizedWorkflowKey,
  );
  if (!workflowGraph) {
    return suggestions;
  }

  const pushSuggestion = (suggestion: ReusableStringSuggestion | null) => {
    const value = suggestion?.value.trim() ?? '';
    if (!suggestion || value.length === 0 || seenValues.has(value)) {
      return;
    }
    seenValues.add(value);
    suggestions.push(suggestion);
  };

  const { items } = parseWorkflowChildEditorItems(workflowGraph.item.childrenJson);
  for (const item of items) {
    pushSuggestion(
      createWorkflowDependencyKeySuggestion(item, workflowGraph.item.workflowKey),
    );
  }

  return suggestions;
}

function buildReusableBlockerSuggestions(
  tasks: TodoTaskItem[],
  decisions: GoalDecision[],
): ReusableBlockerSuggestion[] {
  const suggestions: ReusableBlockerSuggestion[] = [];
  const seenSuggestionKeys = new Set<string>();

  const pushSuggestion = (suggestion: ReusableBlockerSuggestion | null) => {
    if (!suggestion || seenSuggestionKeys.has(suggestion.suggestionKey)) {
      return;
    }
    seenSuggestionKeys.add(suggestion.suggestionKey);
    suggestions.push(suggestion);
  };

  for (const task of tasks) {
    pushSuggestion(createTaskBlockerSuggestion(task));
  }

  for (const decision of decisions) {
    pushSuggestion(createDecisionBlockerSuggestion(decision));
  }

  return suggestions;
}

function createDecisionAnswerSourceSuggestion(
  decision: GoalDecision,
): ReusableAnswerSourceSuggestion | null {
  if (!decision.answer?.trim()) {
    return null;
  }

  return {
    suggestionKey: `decision:${decision.decisionKey}`,
    title: decision.summary,
    subtitle: `decision · ${decision.decisionKey}`,
    preview: summarizePreviewText(decision.answer),
    item: {
      answerSourceKey: decision.decisionKey,
      route: 'decision',
      summary: decision.summary,
      answer: decision.answer,
      sourceExcerpt: '',
      sourceOccurrence: '',
      sourceGroupKey: '',
      decisionKey: decision.decisionKey,
      prompt: decision.prompt ?? '',
      summaryKey: decision.summaryKey ?? '',
      answerKey: '',
      matchHints: (decision.matchHints ?? []).join('\n'),
    },
  };
}

function createDecisionAnswerSourceRoutingSuggestionFromDecision(
  decision: GoalDecision,
): ReusableAnswerSourceRoutingSuggestion | null {
  return createDecisionAnswerSourceRoutingSuggestion({
    decisionKey: decision.decisionKey,
    summary: decision.summary,
    summaryKey: decision.summaryKey ?? '',
    prompt: decision.prompt ?? '',
    matchHints: (decision.matchHints ?? []).join('\n'),
    title: decision.summary,
    subtitle: `decision route · ${decision.decisionKey}`,
  });
}

function createDecisionAnswerSourceRoutingSuggestionFromResolutionDraft(
  decision: GoalDecision,
  draft: DecisionResolutionDraft,
): ReusableAnswerSourceRoutingSuggestion | null {
  const fallbackMatchHints = (decision.matchHints ?? []).join('\n');
  const summaryKey = draft.summaryKey.trim() || (decision.summaryKey ?? '');
  const prompt = draft.prompt.trim() || (decision.prompt ?? '');

  return createDecisionAnswerSourceRoutingSuggestion({
    decisionKey: decision.decisionKey,
    summary: decision.summary,
    summaryKey,
    prompt,
    matchHints: draft.matchHints.trim() || fallbackMatchHints,
    title: decision.summary,
    subtitle: `decision route · ${decision.decisionKey}`,
  });
}

function createDecisionAnswerSourceRoutingSuggestionFromSingleAnswerBundleDraft(
  draft: AnswerBundleDraft,
): ReusableAnswerSourceRoutingSuggestion | null {
  return createDecisionAnswerSourceRoutingSuggestion({
    decisionKey: draft.decisionKey.trim(),
    summary: draft.summary.trim(),
    summaryKey: draft.summaryKey.trim(),
    prompt: draft.prompt.trim(),
    matchHints: draft.matchHints.trim(),
    title:
      draft.summary.trim() ||
      draft.prompt.trim() ||
      draft.decisionKey.trim() ||
      'Current single decision',
    subtitle:
      draft.decisionKey.trim().length > 0
        ? `single decision route · ${draft.decisionKey.trim()}`
        : 'single decision route · current draft',
  });
}

function createDecisionAnswerSourceRoutingSuggestionFromDecisionAnswerItem(
  item: DecisionAnswerEntryEditorItem,
  index: number,
): ReusableAnswerSourceRoutingSuggestion | null {
  const decisionKey = item.decisionKey.trim();
  const summary = item.summary.trim();
  const prompt = item.prompt.trim();
  const summaryKey = item.summaryKey.trim();
  const matchHints = item.matchHints.trim();
  if (
    decisionKey.length === 0 &&
    summary.length === 0 &&
    prompt.length === 0 &&
    summaryKey.length === 0 &&
    matchHints.length === 0
  ) {
    return null;
  }

  return createDecisionAnswerSourceRoutingSuggestion({
    decisionKey,
    summary,
    summaryKey,
    prompt,
    matchHints,
    title: summary || prompt || decisionKey || `Decision consumer ${index + 1}`,
    subtitle:
      decisionKey.length > 0
        ? `decision route · ${decisionKey}`
        : `decision route · current consumer ${index + 1}`,
  });
}

function createDecisionAnswerSourceRoutingSuggestion({
  decisionKey,
  summary,
  summaryKey,
  prompt,
  matchHints,
  title,
  subtitle,
}: {
  decisionKey: string;
  summary: string;
  summaryKey: string;
  prompt: string;
  matchHints: string;
  title: string;
  subtitle: string;
}): ReusableAnswerSourceRoutingSuggestion | null {
  const stableIdentity =
    decisionKey.trim() ||
    summaryKey.trim() ||
    summary.trim() ||
    prompt.trim();
  if (stableIdentity.length === 0) {
    return null;
  }

  const normalizedDecisionKey = decisionKey.trim();
  const normalizedSummary = summary.trim();
  const normalizedSummaryKey = summaryKey.trim();
  const normalizedPrompt = prompt.trim();
  const normalizedMatchHints = matchHints.trim();
  const previewParts = [
    'route=decision',
    normalizedDecisionKey.length > 0 ? `decisionKey=${normalizedDecisionKey}` : '',
    normalizedSummary.length > 0 ? normalizedSummary : normalizedPrompt,
    normalizedMatchHints.length > 0
      ? `matchHints=${parseListInput(normalizedMatchHints).join(', ')}`
      : '',
  ].filter((part) => part && part.length > 0);

  return {
    suggestionKey: `answer-source-route:decision:${slugifySourceKeyPart(stableIdentity)}`,
    title,
    subtitle,
    preview: summarizePreviewText(previewParts.join(' • ')),
    item: {
      answerSourceKey: `decision-${slugifySourceKeyPart(stableIdentity)}-source`,
      route: 'decision',
      summary: normalizedSummary,
      answer: '',
      sourceExcerpt: '',
      sourceOccurrence: '',
      sourceGroupKey: '',
      decisionKey: normalizedDecisionKey,
      prompt: normalizedPrompt,
      summaryKey: normalizedSummaryKey,
      answerKey: '',
      matchHints: normalizedMatchHints,
    },
  };
}

