function buildDecisionAnswerEntrySuggestionIdentity(
  item: Pick<
    DecisionAnswerEntryEditorItem,
    | 'decisionKey'
    | 'summaryKey'
    | 'summary'
    | 'prompt'
    | 'matchHints'
    | 'taskRef'
    | 'answer'
    | 'sourceExcerpt'
    | 'sourceOccurrence'
    | 'answerSourceKey'
    | 'answerSourceGroupKey'
  >,
) {
  const decisionKey = item.decisionKey.trim();
  if (decisionKey.length > 0) {
    return `decision:${decisionKey}`;
  }

  const summaryKey = item.summaryKey.trim();
  if (summaryKey.length > 0) {
    return `summaryKey:${summaryKey}`;
  }

  const summary = normalizeEditorIdentityPart(item.summary);
  const prompt = normalizeEditorIdentityPart(item.prompt);
  const matchHints = normalizeEditorIdentityList(item.matchHints);
  const taskRef = normalizeEditorIdentityPart(item.taskRef);
  const answer = normalizeEditorIdentityPart(item.answer);
  const sourceExcerpt = normalizeEditorIdentityPart(item.sourceExcerpt);
  const sourceOccurrence = normalizeEditorIdentityPart(item.sourceOccurrence);
  const answerSourceKey = normalizeEditorIdentityPart(item.answerSourceKey);
  const answerSourceGroupKey = normalizeEditorIdentityPart(item.answerSourceGroupKey);
  const compositeParts = [
    summary.length > 0 ? `summary=${summary}` : '',
    prompt.length > 0 ? `prompt=${prompt}` : '',
    matchHints.length > 0 ? `matchHints=${matchHints.join(',')}` : '',
    taskRef.length > 0 ? `task=${taskRef}` : '',
    answer.length > 0 ? `answer=${answer}` : '',
    sourceExcerpt.length > 0 ? `excerpt=${sourceExcerpt}` : '',
    sourceOccurrence.length > 0 ? `occurrence=${sourceOccurrence}` : '',
    answerSourceKey.length > 0 ? `answerSourceKey=${answerSourceKey}` : '',
    answerSourceGroupKey.length > 0
      ? `answerSourceGroupKey=${answerSourceGroupKey}`
      : '',
  ].filter((part) => part.length > 0);

  if (compositeParts.length > 0) {
    return `composite:${compositeParts.join('|')}`;
  }

  return null;
}

function buildPlanningAnswerEditorSuggestionIdentity(
  item: Pick<
    PlanningAnswerEditorItem,
    | 'answerKey'
    | 'summaryKey'
    | 'summary'
    | 'prompt'
    | 'matchHints'
    | 'answer'
    | 'sourceExcerpt'
    | 'sourceOccurrence'
    | 'answerSourceKey'
    | 'answerSourceGroupKey'
  >,
) {
  const answerKey = item.answerKey.trim();
  if (answerKey.length > 0) {
    return `answer:${answerKey}`;
  }

  const summaryKey = item.summaryKey.trim();
  if (summaryKey.length > 0) {
    return `summaryKey:${summaryKey}`;
  }

  const summary = normalizeEditorIdentityPart(item.summary);
  const prompt = normalizeEditorIdentityPart(item.prompt);
  const matchHints = normalizeEditorIdentityList(item.matchHints);
  const answer = normalizeEditorIdentityPart(item.answer);
  const sourceExcerpt = normalizeEditorIdentityPart(item.sourceExcerpt);
  const sourceOccurrence = normalizeEditorIdentityPart(item.sourceOccurrence);
  const answerSourceKey = normalizeEditorIdentityPart(item.answerSourceKey);
  const answerSourceGroupKey = normalizeEditorIdentityPart(item.answerSourceGroupKey);
  const compositeParts = [
    summary.length > 0 ? `summary=${summary}` : '',
    prompt.length > 0 ? `prompt=${prompt}` : '',
    matchHints.length > 0 ? `matchHints=${matchHints.join(',')}` : '',
    answer.length > 0 ? `answer=${answer}` : '',
    sourceExcerpt.length > 0 ? `excerpt=${sourceExcerpt}` : '',
    sourceOccurrence.length > 0 ? `occurrence=${sourceOccurrence}` : '',
    answerSourceKey.length > 0 ? `answerSourceKey=${answerSourceKey}` : '',
    answerSourceGroupKey.length > 0
      ? `answerSourceGroupKey=${answerSourceGroupKey}`
      : '',
  ].filter((part) => part.length > 0);

  if (compositeParts.length > 0) {
    return `composite:${compositeParts.join('|')}`;
  }

  return null;
}

function normalizeEditorIdentityPart(value: string) {
  return value.trim().replace(/\s+/g, ' ').toLowerCase();
}

function normalizeEditorIdentityList(value: string) {
  return parseListInput(value).map((entry) => normalizeEditorIdentityPart(entry));
}

function buildEditorAnswerSourceIdentity(
  item: {
    answerSourceKey: string;
    answerSourceGroupKey?: string;
    sourceGroupKey?: string;
    route?: string;
    decisionKey?: string;
    summary: string;
    answer: string;
    sourceExcerpt: string;
    sourceOccurrence: string;
    prompt: string;
    summaryKey: string;
    answerKey?: string;
    matchHints: string;
  },
) {
  const answerSourceKey = item.answerSourceKey.trim();
  const answerSourceGroupKey = (item.sourceGroupKey ?? item.answerSourceGroupKey ?? '').trim();

  if (answerSourceKey.length > 0 || answerSourceGroupKey.length > 0) {
    return [answerSourceKey, answerSourceGroupKey]
      .filter((entry) => entry.length > 0)
      .join('::');
  }

  const compositeParts = [
    normalizeEditorIdentityPart(item.route ?? ''),
    normalizeEditorIdentityPart(item.decisionKey ?? ''),
    normalizeEditorIdentityPart(item.answerKey ?? ''),
    normalizeEditorIdentityPart(item.summaryKey),
    normalizeEditorIdentityPart(item.summary),
    normalizeEditorIdentityPart(item.prompt),
    normalizeEditorIdentityList(item.matchHints).join('|'),
    normalizeEditorIdentityPart(item.answer),
    normalizeEditorIdentityPart(item.sourceExcerpt),
    normalizeEditorIdentityPart(item.sourceOccurrence),
  ].filter((entry) => entry.length > 0);

  if (compositeParts.length > 0) {
    return `composite:${compositeParts.join('|')}`;
  }

  return null;
}

function buildBlockerSuggestionIdentity(
  item: Pick<BlockerEditorItem, 'kind' | 'ref'>,
) {
  const kind = item.kind.trim();
  const ref = item.ref.trim();
  if (kind.length === 0 || ref.length === 0) {
    return null;
  }
  return `${kind}:${ref}`;
}

function appendUniqueBlockerEditorItems(
  items: BlockerEditorItem[],
  nextItems: BlockerEditorItem[],
) {
  const merged = [...items];
  const seenKeys = new Set(
    items
      .map((item) => buildBlockerSuggestionIdentity(item))
      .filter((item): item is string => item !== null),
  );

  for (const item of nextItems) {
    const identity = buildBlockerSuggestionIdentity(item);
    if (!identity || seenKeys.has(identity)) {
      continue;
    }
    seenKeys.add(identity);
    merged.push(item);
  }

  return merged;
}

function createPlanningAnswerSourceSuggestion(
  request: GoalPlanningRequest,
  answer: CapturedAnswer,
  kind: 'request' | 'workflow_shared',
): ReusableAnswerSourceSuggestion | null {
  if (!answer.answer.trim()) {
    return null;
  }

  const requestScope =
    kind === 'workflow_shared'
      ? request.workflowKey ?? request.groupKey ?? request.requestKey
      : request.requestKey;
  const sourceKey =
    answer.answerKey ||
    `${kind === 'workflow_shared' ? 'workflow' : 'request'}-${requestScope}-${slugifySourceKeyPart(
      answer.summaryKey || answer.summary,
    )}`;

  return {
    suggestionKey: `${kind}:${request.requestKey}:${sourceKey}`,
    title: answer.summary,
    subtitle:
      kind === 'workflow_shared'
        ? `workflow-shared · ${request.workflowKey ?? request.requestKey}`
        : `planning request · ${request.requestKey}`,
    preview: summarizePreviewText(answer.answer),
    item: {
      answerSourceKey: sourceKey,
      route: 'planning',
      summary: answer.summary,
      answer: answer.answer,
      sourceExcerpt: '',
      sourceOccurrence: '',
      sourceGroupKey:
        kind === 'workflow_shared'
          ? request.workflowKey ?? request.groupKey ?? request.requestKey
          : request.groupKey ?? request.requestKey,
      decisionKey: '',
      prompt: answer.prompt ?? '',
      summaryKey: answer.summaryKey ?? '',
      answerKey: answer.answerKey ?? '',
      matchHints: (answer.matchHints ?? []).join('\n'),
    },
  };
}

function createPlanningAnswerSourceRoutingSuggestionFromPlanningAnswerItem(
  item: PlanningAnswerEditorItem,
  index: number,
): ReusableAnswerSourceRoutingSuggestion | null {
  const summary = item.summary.trim();
  const prompt = item.prompt.trim();
  const summaryKey = item.summaryKey.trim();
  const answerKey = item.answerKey.trim();
  const answerSourceGroupKey = item.answerSourceGroupKey.trim();
  const matchHints = item.matchHints.trim();
  if (
    summary.length === 0 &&
    prompt.length === 0 &&
    summaryKey.length === 0 &&
    answerKey.length === 0 &&
    answerSourceGroupKey.length === 0 &&
    matchHints.length === 0
  ) {
    return null;
  }

  const stableIdentity =
    answerKey ||
    summaryKey ||
    answerSourceGroupKey ||
    summary ||
    prompt ||
    `planning-consumer-${index + 1}`;
  const previewParts = [
    'route=planning',
    answerKey.length > 0 ? `answerKey=${answerKey}` : '',
    answerSourceGroupKey.length > 0 ? `sourceGroup=${answerSourceGroupKey}` : '',
    summary.length > 0 ? summary : prompt,
    matchHints.length > 0 ? `matchHints=${parseListInput(matchHints).join(', ')}` : '',
  ].filter((part) => part && part.length > 0);

  return {
    suggestionKey: `answer-source-route:planning:${slugifySourceKeyPart(stableIdentity)}`,
    title: summary || prompt || answerKey || `Planning consumer ${index + 1}`,
    subtitle:
      answerKey.length > 0
        ? `planning route · ${answerKey}`
        : `planning route · current consumer ${index + 1}`,
    preview: summarizePreviewText(previewParts.join(' • ')),
    item: {
      answerSourceKey: `planning-${slugifySourceKeyPart(stableIdentity)}-source`,
      route: 'planning',
      summary,
      answer: '',
      sourceExcerpt: '',
      sourceOccurrence: '',
      sourceGroupKey: answerSourceGroupKey,
      decisionKey: '',
      prompt,
      summaryKey,
      answerKey,
      matchHints,
    },
  };
}

function createCapturedPlanningAnswerSuggestion(
  request: GoalPlanningRequest,
  answer: CapturedAnswer,
  kind: 'request' | 'workflow_shared',
): ReusablePlanningAnswerSuggestion | null {
  if (!answer.answer.trim()) {
    return null;
  }

  const requestScope =
    kind === 'workflow_shared'
      ? request.workflowKey ?? request.groupKey ?? request.requestKey
      : request.requestKey;
  const stableAnswerKey =
    answer.answerKey ||
    `${kind === 'workflow_shared' ? 'workflow' : 'request'}-${requestScope}-${slugifySourceKeyPart(
      answer.summaryKey || answer.summary,
    )}`;

  return {
    suggestionKey: `${kind}:${request.requestKey}:${stableAnswerKey}`,
    title: answer.summary,
    subtitle:
      kind === 'workflow_shared'
        ? `workflow-shared · ${request.workflowKey ?? request.requestKey}`
        : `planning request · ${request.requestKey}`,
    preview: summarizePreviewText(answer.answer),
    item: {
      summary: answer.summary,
      answer: answer.answer,
      sourceExcerpt: '',
      sourceOccurrence: '',
      prompt: answer.prompt ?? '',
      summaryKey: answer.summaryKey ?? '',
      answerKey: answer.answerKey ?? stableAnswerKey,
      matchHints: (answer.matchHints ?? []).join('\n'),
      answerSourceKey: '',
      answerSourceGroupKey:
        kind === 'workflow_shared'
          ? request.workflowKey ?? request.groupKey ?? request.requestKey
          : request.groupKey ?? request.requestKey,
    },
  };
}

function serializePlanningAnswersFromPlanningRequests(requests: GoalPlanningRequest[]) {
  const answers = collectUniqueCapturedAnswersFromPlanningRequests(requests);
  if (answers.length === 0) {
    return '';
  }

  return serializePlanningAnswerEditorItems(
    answers.map((answer) => createPlanningAnswerEditorItemFromCapturedAnswer(answer)),
  );
}

function createWorkflowChildEditorItemFromWorkflowLeaf(
  workflowChild: GoalPlanningWorkflowLeafState,
  tasksByRef: Map<string, TodoTaskItem>,
  groupedTaskKeyByTaskRef: Map<string, string>,
): WorkflowChildEditorItem {
  if (workflowChild.kind === 'planning') {
    const linkedTask = tasksByRef.get(workflowChild.request.taskRef);
    return {
      kind: 'planning',
      requestKey: workflowChild.request.requestKey,
      workflowTaskKey: workflowChild.workflowTaskKey ?? '',
      groupKey: workflowChild.request.groupKey ?? workflowChild.groupKey ?? '',
      blockedByWorkflowKeys: workflowChild.blockedByWorkflowKeys.join('\n'),
      blockedByJson:
        linkedTask && linkedTask.blockedBy.length > 0
          ? serializeBlockerEditorItems(
              linkedTask.blockedBy.map((blocker) => ({
                kind: blocker.kind,
                ref: blocker.ref,
              })),
            )
          : '',
      title: workflowChild.request.title,
      description: workflowChild.request.description,
      acceptanceCriteria: workflowChild.request.acceptanceCriteria.join('\n'),
      decisionRefs: workflowChild.request.decisionRefs.join('\n'),
      answersJson: serializePlanningAnswerEditorItems(
        workflowChild.request.answers.map((answer) =>
          createPlanningAnswerEditorItemFromCapturedAnswer(answer),
        ),
      ),
      requestedUpdates: workflowChild.request.requestedUpdates.join('\n'),
      batchRequestsJson: '',
    };
  }

  return {
    kind: 'planning_batch',
    requestKey: '',
    workflowTaskKey: '',
    groupKey: workflowChild.groupKey,
    blockedByWorkflowKeys: workflowChild.blockedByWorkflowKeys.join('\n'),
    blockedByJson: '',
    title: '',
    description: '',
    acceptanceCriteria: '',
    decisionRefs: collectUniquePlanningRequestDecisionRefs(workflowChild.requests).join('\n'),
    answersJson: serializePlanningAnswersFromPlanningRequests(workflowChild.requests),
    requestedUpdates: '',
    batchRequestsJson: serializeBatchRequestEditorItems(
      workflowChild.requests
        .map((request) =>
          buildBatchRequestEditorItemFromPlanningRequest(
            request,
            tasksByRef.get(request.taskRef),
            groupedTaskKeyByTaskRef,
          ),
        )
        .filter((item): item is BatchRequestEditorItem => item !== null),
    ),
  };
}

function createDecisionWorkflowChildEditorItemFromWorkflowLeaf(
  workflowChild: GoalPlanningWorkflowLeafState,
  tasksByRef: Map<string, TodoTaskItem>,
  groupedTaskKeyByTaskRef: Map<string, string>,
): DecisionWorkflowChildEditorItem {
  if (workflowChild.kind === 'planning') {
    return {
      kind: 'planning',
      workflowTaskKey: workflowChild.workflowTaskKey ?? '',
      groupKey: '',
      blockedByWorkflowKeys: workflowChild.blockedByWorkflowKeys.join('\n'),
      title: workflowChild.request.title,
      description: workflowChild.request.description,
      acceptanceCriteria: workflowChild.request.acceptanceCriteria.join('\n'),
      answersJson: serializePlanningAnswerEditorItems(
        workflowChild.request.answers.map((answer) =>
          createPlanningAnswerEditorItemFromCapturedAnswer(answer),
        ),
      ),
      requestedUpdates: workflowChild.request.requestedUpdates.join('\n'),
      batchRequestsJson: '',
    };
  }

  return {
    kind: 'planning_batch',
    workflowTaskKey: '',
    groupKey: workflowChild.groupKey,
    blockedByWorkflowKeys: workflowChild.blockedByWorkflowKeys.join('\n'),
    title: '',
    description: '',
    acceptanceCriteria: '',
    answersJson: serializePlanningAnswersFromPlanningRequests(workflowChild.requests),
    requestedUpdates: '',
    batchRequestsJson: serializeBatchRequestEditorItems(
      workflowChild.requests
        .map((request) =>
          buildBatchRequestEditorItemFromPlanningRequest(
            request,
            tasksByRef.get(request.taskRef),
            groupedTaskKeyByTaskRef,
          ),
        )
        .filter((item): item is BatchRequestEditorItem => item !== null),
    ),
  };
}

function collectUniquePlanningRequestDecisionRefs(requests: GoalPlanningRequest[]) {
  return Array.from(new Set(requests.flatMap((request) => request.decisionRefs)));
}

function collectUniqueWorkflowSharedDecisionRefsFromPlanningRequests(
  requests: GoalPlanningRequest[],
) {
  return Array.from(new Set(requests.flatMap((request) => request.workflowSharedDecisionRefs)));
}

function collectUniqueCapturedAnswersFromPlanningRequests(requests: GoalPlanningRequest[]) {
  const answers: CapturedAnswer[] = [];
  const seenKeys = new Set<string>();

  for (const request of requests) {
    for (const answer of request.answers) {
      const identity =
        answer.answerKey?.trim() ||
        answer.summaryKey?.trim() ||
        `${answer.summary.trim().toLowerCase()}::${answer.answer.trim()}`;
      if (!identity || seenKeys.has(identity)) {
        continue;
      }
      seenKeys.add(identity);
      answers.push(answer);
    }
  }

  return answers;
}

function collectUniqueWorkflowSharedAnswersFromPlanningRequests(requests: GoalPlanningRequest[]) {
  const answers: CapturedAnswer[] = [];
  const seenKeys = new Set<string>();

  for (const request of requests) {
    for (const answer of request.workflowSharedAnswers) {
      const identity =
        answer.answerKey?.trim() ||
        answer.summaryKey?.trim() ||
        `${answer.summary.trim().toLowerCase()}::${answer.answer.trim()}`;
      if (!identity || seenKeys.has(identity)) {
        continue;
      }
      seenKeys.add(identity);
      answers.push(answer);
    }
  }

  return answers;
}

function slugifySourceKeyPart(value: string) {
  const normalized = value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');
  return normalized.length > 0 ? normalized : 'answer';
}

function summarizePreviewText(value: string, maxLength = 120) {
  const normalized = value.replace(/\s+/g, ' ').trim();
  if (normalized.length <= maxLength) {
    return normalized;
  }
  return `${normalized.slice(0, maxLength - 1)}…`;
}

function buildExistingPlanningMutationAuthoritySnapshot(
  board: TodoBoard | undefined,
  planningRequests: GoalPlanningRequestSet | undefined,
  workflows: { goalKey: string; workflows: GoalPlanningWorkflowState[] } | undefined,
): ExistingPlanningMutationAuthoritySnapshot {
  return {
    existingRequestKeys: Array.from(
      new Set((planningRequests?.requests ?? []).map((request) => request.requestKey)),
    ),
    existingTaskRefs: Array.from(new Set((board?.items ?? []).map((task) => task.ref))),
    existingGroupKeys: Array.from(
      new Set(
        (planningRequests?.requests ?? [])
          .map((request) => request.groupKey?.trim())
          .filter((groupKey): groupKey is string => Boolean(groupKey && groupKey.length > 0)),
      ),
    ),
    existingWorkflowKeys: Array.from(
      new Set((workflows?.workflows ?? []).map((workflow) => workflow.workflowKey)),
    ),
  };
}

function partitionMutationAuthorityRefs(
  refs: string[],
  existingRefs: string[],
) {
  const existing = new Set(existingRefs);
  const created: string[] = [];
  const reused: string[] = [];

  for (const ref of refs) {
    if (!ref || created.includes(ref) || reused.includes(ref)) {
      continue;
    }
    if (existing.has(ref)) {
      reused.push(ref);
    } else {
      created.push(ref);
    }
  }

  return {
    created,
    reused,
  };
}

function buildDecisionFollowThroughReuseAuthority(
  followThrough: GoalDecisionFollowThroughResult,
  existingState: ExistingPlanningMutationAuthoritySnapshot,
): GoalDecisionFollowThroughReuseAuthority {
  const requestRefs = partitionMutationAuthorityRefs(
    followThrough.requestKeys,
    existingState.existingRequestKeys,
  );
  const taskRefs = partitionMutationAuthorityRefs(
    followThrough.taskRefs,
    existingState.existingTaskRefs,
  );
  const groupKeys =
    'groupKeys' in followThrough
      ? partitionMutationAuthorityRefs(
          followThrough.groupKeys,
          existingState.existingGroupKeys,
        )
      : 'groupKey' in followThrough
        ? partitionMutationAuthorityRefs(
            [followThrough.groupKey],
            existingState.existingGroupKeys,
          )
        : { created: [], reused: [] };

  return {
    createdRequestKeys: requestRefs.created,
    reusedRequestKeys: requestRefs.reused,
    createdTaskRefs: taskRefs.created,
    reusedTaskRefs: taskRefs.reused,
    createdGroupKeys: groupKeys.created,
    reusedGroupKeys: groupKeys.reused,
    workflowCreated:
      'workflowKey' in followThrough && followThrough.workflowKey
        ? !existingState.existingWorkflowKeys.includes(followThrough.workflowKey)
        : undefined,
  };
}

function enrichDecisionFollowThroughResultWithReuse(
  followThrough: GoalDecisionFollowThroughResult,
  existingState: ExistingPlanningMutationAuthoritySnapshot,
): GoalDecisionFollowThroughResultWithReuse {
  const authority = buildDecisionFollowThroughReuseAuthority(followThrough, existingState);

  if (followThrough.kind === 'workflow_batch') {
    return {
      ...followThrough,
      ...authority,
      workflowSharedDecisionRefs: collectUniqueWorkflowSharedDecisionRefsFromPlanningRequests(
        followThrough.requests,
      ),
      workflowSharedAnswers: collectUniqueWorkflowSharedAnswersFromPlanningRequests(
        followThrough.requests,
      ),
      workflows: followThrough.workflows.map((workflow) =>
        enrichDecisionFollowThroughResultWithReuse(
          workflow,
          existingState,
        ) as GoalDecisionLeafFollowThroughResultWithReuse,
      ),
    };
  }

  return {
    ...followThrough,
    ...authority,
  };
}

function collectWorkflowCreateChildGroupKeys(
  workflow: GoalPlanningWorkflowCreateResult['workflows'][number],
) {
  return Array.from(
    new Set(
      [
        'groupKey' in workflow ? workflow.groupKey?.trim() : undefined,
        ...workflow.requests.map((request) => request.groupKey?.trim()),
      ].filter((groupKey): groupKey is string => Boolean(groupKey && groupKey.length > 0)),
    ),
  );
}

function buildWorkflowCreateChildReuseAuthority(
  workflow: GoalPlanningWorkflowCreateResult['workflows'][number],
  existingState: ExistingPlanningMutationAuthoritySnapshot,
) {
  const groupKeys = partitionMutationAuthorityRefs(
    collectWorkflowCreateChildGroupKeys(workflow),
    existingState.existingGroupKeys,
  );

  return {
    createdGroupKeys: groupKeys.created,
    reusedGroupKeys: groupKeys.reused,
  };
}

function enrichWorkflowCreateResultWithReuse(
  result: GoalPlanningWorkflowCreateResult & {
    created: boolean;
    resolvedSourceResponseFormat?: GoalSourceResponseFormat;
  },
  existingState: ExistingPlanningMutationAuthoritySnapshot,
): GoalPlanningWorkflowCreateResultWithReuse {
  const groupKeys = partitionMutationAuthorityRefs(
    result.groupKeys,
    existingState.existingGroupKeys,
  );

  return {
    ...result,
    workflowCreated: result.workflowKey
      ? !existingState.existingWorkflowKeys.includes(result.workflowKey)
      : result.created,
    createdGroupKeys: groupKeys.created,
    reusedGroupKeys: groupKeys.reused,
    workflows: result.workflows.map((workflow) => ({
      ...workflow,
      ...buildWorkflowCreateChildReuseAuthority(workflow, existingState),
    })),
  };
}

function summarizeDecisionMutationResult(
  decision: GoalDecision & {
    created?: boolean;
  },
) {
  const details = [
    decision.decisionKey,
    decision.summaryKey ? `summaryKey=${decision.summaryKey}` : null,
    decision.taskRef ? `task=${decision.taskRef}` : null,
    decision.matchHints && decision.matchHints.length > 0
      ? `matchHints=${decision.matchHints.join('|')}`
      : null,
  ].filter(Boolean);

  return `${decision.created === false ? 'Reused open decision' : 'Opened decision'} ${details.join(' · ')}.`;
}

function summarizeDecisionFollowThroughResult(followThrough: GoalDecisionFollowThroughResult) {
  const details = [
    `kind=${followThrough.kind}`,
    'workflowKey' in followThrough && followThrough.workflowKey
      ? `workflow=${followThrough.workflowKey}`
      : null,
    'groupKey' in followThrough && followThrough.groupKey
      ? `group=${followThrough.groupKey}`
      : null,
    'groupKeys' in followThrough && followThrough.groupKeys.length > 0
      ? `${followThrough.groupKeys.length} group sink(s)`
      : null,
    'workflows' in followThrough
      ? `${followThrough.workflows.length} workflow child(ren)`
      : null,
    'workflowSharedDecisionRefs' in followThrough &&
    Array.isArray(followThrough.workflowSharedDecisionRefs) &&
    followThrough.workflowSharedDecisionRefs.length > 0
      ? `${followThrough.workflowSharedDecisionRefs.length} shared decision ref(s)`
      : null,
    'workflowSharedAnswers' in followThrough &&
    Array.isArray(followThrough.workflowSharedAnswers) &&
    followThrough.workflowSharedAnswers.length > 0
      ? `${followThrough.workflowSharedAnswers.length} shared answer(s)`
      : null,
    `${followThrough.requestKeys.length} request(s)`,
    `${followThrough.taskRefs.length} task(s)`,
    `${followThrough.blockerTaskRefs.length} blocker task(s)`,
  ].filter(Boolean);

  return details.join(' · ');
}

function summarizeTaskMutationResult(task: TodoTaskItem) {
  const details = [
    task.ref,
    task.kind,
    `status=${task.status}`,
    `${task.acceptanceCriteria.length} acceptance item(s)`,
    task.blockedBy.length > 0 ? `${task.blockedBy.length} blocker(s)` : null,
  ].filter(Boolean);

  return details.join(' · ');
}

function summarizePlanningRequestMutationResult(
  request: GoalPlanningRequest & { resolvedSourceResponseFormat?: GoalSourceResponseFormat },
) {
  const details = [
    request.requestKey,
    `task=${request.taskRef}`,
    request.workflowKey ? `workflow=${request.workflowKey}` : null,
    request.workflowTaskKey ? `child=${request.workflowTaskKey}` : null,
    request.groupKey ? `group=${request.groupKey}` : null,
    request.resolvedSourceResponseFormat
      ? `resolvedFormat=${request.resolvedSourceResponseFormat}`
      : null,
  ].filter(Boolean);

  return details.join(' · ');
}

function summarizePreferenceDocumentMutationResult(document: PreferenceDocument) {
  const activeCount = document.entries.filter((entry) => entry.status === 'active').length;
  const retiredCount = document.entries.filter((entry) => entry.status === 'retired').length;

  return `${document.entries.length} preference(s) total · ${activeCount} active · ${retiredCount} retired`;
}

function summarizeWorkflowCreateMutationResult(
  result: GoalPlanningWorkflowCreateResultWithReuse,
) {
  const reusedRequestKeys = listReusedMutationRefs(
    result.requestKeys,
    result.createdRequestKeys,
  );
  const reusedTaskRefs = listReusedMutationRefs(result.taskRefs, result.createdTaskRefs);
  const details = [
    result.workflowKey ?? 'workflow_batch',
    result.workflowCreated ? 'workflow created' : 'workflow updated',
    result.workflows.length > 0 ? `${result.workflows.length} workflow child(ren)` : null,
    result.groupKeys.length > 0 ? `${result.groupKeys.length} group sink(s)` : null,
    result.createdGroupKeys.length > 0 ? `${result.createdGroupKeys.length} group(s) created` : null,
    result.reusedGroupKeys.length > 0 ? `${result.reusedGroupKeys.length} group(s) reused` : null,
    result.workflowSharedDecisionRefs.length > 0
      ? `${result.workflowSharedDecisionRefs.length} shared decision ref(s)`
      : null,
    result.workflowSharedAnswers.length > 0
      ? `${result.workflowSharedAnswers.length} shared answer(s)`
      : null,
    `${result.createdRequestKeys.length} request(s) created`,
    `${result.createdTaskRefs.length} task(s) created`,
    reusedRequestKeys.length > 0 ? `${reusedRequestKeys.length} request(s) reused` : null,
    reusedTaskRefs.length > 0 ? `${reusedTaskRefs.length} task(s) reused` : null,
    result.blockerTaskRefs.length > 0
      ? `${result.blockerTaskRefs.length} blocker task(s)`
      : null,
    result.resolvedSourceResponseFormat
      ? `resolvedFormat=${result.resolvedSourceResponseFormat}`
      : null,
  ].filter(Boolean);

  return details.join(' · ');
}

function listReusedMutationRefs(allRefs: string[], createdRefs: string[]) {
  if (allRefs.length === 0) {
    return [];
  }

  const created = new Set(createdRefs);
  return allRefs.filter((ref) => !created.has(ref));
}

function formatTimestamp(value: string) {
  return new Date(value).toLocaleString();
}

